function extractManualPdfProviderIdFromPort(port) {
  const name = typeof port?.name === 'string' ? port.name.trim() : '';
  const prefix = 'manual-pdf-provider:';
  if (!name || !name.startsWith(prefix)) return '';
  const providerId = name.slice(prefix.length).trim();
  return providerId || '';
}

async function waitForManualPdfProviderPort(providerId, timeoutMs = 5000) {
  const safeProviderId = typeof providerId === 'string' ? providerId.trim() : '';
  if (!safeProviderId) return false;
  if (manualPdfProviderPorts.has(safeProviderId)) return true;
  const startedAt = Date.now();
  const maxWaitMs = Math.max(500, Math.min(15000, Number.isInteger(timeoutMs) ? timeoutMs : 5000));
  while (Date.now() - startedAt < maxWaitMs) {
    if (manualPdfProviderPorts.has(safeProviderId)) return true;
    await sleep(100);
  }
  return manualPdfProviderPorts.has(safeProviderId);
}

function normalizeComposerThinkingEffort(value) {
  const normalized = typeof value === 'string' ? value.trim().toLowerCase() : '';
  if (!normalized) return '';
  if (normalized === 'light' || normalized === 'standard' || normalized === 'extended' || normalized === 'heavy') {
    return normalized;
  }
  return '';
}

async function getStoredResumeComposerThinkingEffort() {
  try {
    const stored = await chrome.storage.local.get(RESUME_COMPOSER_THINKING_EFFORT_STORAGE_KEY);
    return normalizeComposerThinkingEffort(stored?.[RESUME_COMPOSER_THINKING_EFFORT_STORAGE_KEY]);
  } catch (error) {
    console.warn('[resume-effort] get stored value failed:', error?.message || error);
    return '';
  }
}

async function setStoredResumeComposerThinkingEffort(value) {
  const normalized = normalizeComposerThinkingEffort(value);
  try {
    if (normalized) {
      await chrome.storage.local.set({
        [RESUME_COMPOSER_THINKING_EFFORT_STORAGE_KEY]: normalized
      });
    } else {
      await chrome.storage.local.remove(RESUME_COMPOSER_THINKING_EFFORT_STORAGE_KEY);
    }
  } catch (error) {
    console.warn('[resume-effort] set stored value failed:', error?.message || error);
  }
  return normalized;
}

function normalizeProcessLifecycleStatus(value, fallback = 'running') {
  if (typeof ProcessContractUtils.normalizeLifecycleStatus === 'function') {
    return ProcessContractUtils.normalizeLifecycleStatus(value, fallback);
  }
  if (typeof value !== 'string') return fallback || 'running';
  const normalized = value.trim().toLowerCase();
  return normalized || fallback || 'running';
}

function normalizeProcessPhase(value, fallback = '') {
  if (typeof ProcessContractUtils.normalizePhase === 'function') {
    return ProcessContractUtils.normalizePhase(value, fallback);
  }
  if (typeof value !== 'string') return fallback || '';
  const normalized = value.trim().toLowerCase();
  return normalized || fallback || '';
}

function normalizeProcessActionRequired(value, fallback = 'none') {
  if (typeof ProcessContractUtils.normalizeActionRequired === 'function') {
    return ProcessContractUtils.normalizeActionRequired(value, fallback);
  }
  if (typeof value !== 'string') return fallback || 'none';
  const normalized = value.trim().toLowerCase();
  return normalized || fallback || 'none';
}

function deriveProcessActionRequired(record = {}) {
  if (typeof ProcessContractUtils.deriveActionRequiredFromLegacy === 'function') {
    return ProcessContractUtils.deriveActionRequiredFromLegacy(record);
  }
  return record?.needsAction === true ? 'manual_resume' : 'none';
}

function deriveProcessStatusCode(record = {}) {
  if (typeof ProcessContractUtils.deriveStatusCode === 'function') {
    return ProcessContractUtils.deriveStatusCode(record);
  }
  return typeof record?.statusCode === 'string' ? record.statusCode.trim() : '';
}

function buildOperatorStatusText(record = {}) {
  if (typeof ProcessContractUtils.buildOperatorStatusText === 'function') {
    return ProcessContractUtils.buildOperatorStatusText(record);
  }
  return typeof record?.statusText === 'string' ? record.statusText.trim() : '';
}

function appendProcessRuntimeDebugEvent(rawEvent = {}) {
  const event = rawEvent && typeof rawEvent === 'object' ? { ...rawEvent } : {};
  const runId = typeof event.runId === 'string' && event.runId.trim() ? event.runId.trim() : '';
  if (!runId) return null;
  const current = processRuntimeDebugEventsByRunId.get(runId) || [];
  const next = current.slice(-(PROCESS_DEBUG_EVENT_LIMIT - 1));
  next.push({
    ts: Number.isInteger(event.ts) ? event.ts : Date.now(),
    level: typeof event.level === 'string' ? event.level : 'info',
    area: typeof event.area === 'string' ? event.area : 'runtime',
    event: typeof event.event === 'string' ? event.event : 'unknown',
    phase: typeof event.phase === 'string' ? event.phase : '',
    statusCode: typeof event.statusCode === 'string' ? event.statusCode : '',
    durationMs: Number.isInteger(event.durationMs) ? event.durationMs : null,
    meta: event.meta && typeof event.meta === 'object' ? event.meta : {}
  });
  processRuntimeDebugEventsByRunId.set(runId, next);
  return next[next.length - 1];
}

const logger = {
  event(rawEvent = {}) {
    const event = rawEvent && typeof rawEvent === 'object' ? { ...rawEvent } : {};
    const level = typeof event.level === 'string' ? event.level.trim().toLowerCase() : 'info';
    const area = typeof event.area === 'string' && event.area.trim() ? event.area.trim() : 'runtime';
    const eventName = typeof event.event === 'string' && event.event.trim() ? event.event.trim() : 'unknown';
    const runId = typeof event.runId === 'string' && event.runId.trim() ? event.runId.trim() : '';
    const statusCode = typeof event.statusCode === 'string' && event.statusCode.trim()
      ? event.statusCode.trim()
      : deriveProcessStatusCode(event);
    const phase = normalizeProcessPhase(event.phase || '');
    const durationMs = Number.isInteger(event.durationMs) ? event.durationMs : null;
    const meta = event.meta && typeof event.meta === 'object' ? event.meta : {};

    if (runId) {
      appendProcessRuntimeDebugEvent({
        ts: Date.now(),
        runId,
        level,
        area,
        event: eventName,
        phase,
        statusCode,
        durationMs,
        meta
      });
    }

    const logFn = level === 'error'
      ? console.error
      : level === 'warn'
        ? console.warn
        : level === 'info'
          ? console.info
          : console.log;
    logFn(`[runtime:${area}] ${eventName}`, {
      runId: runId || null,
      jobId: typeof event.jobId === 'string' ? event.jobId : null,
      responseId: typeof event.responseId === 'string' ? event.responseId : null,
      phase: phase || null,
      statusCode: statusCode || null,
      durationMs,
      meta
    });
  }
};

function isClosedProcessStatus(status) {
  const normalized = normalizeProcessLifecycleStatus(status, 'running');
  if (typeof ProcessContractUtils.isClosedLifecycleStatus === 'function') {
    return ProcessContractUtils.isClosedLifecycleStatus(normalized);
  }
  return normalized === 'completed' || normalized === 'failed' || normalized === 'stopped';
}

function isQueuedProcessStatus(status) {
  return normalizeProcessStatus(status) === 'queued';
}

function normalizeProcessStatus(status) {
  return normalizeProcessLifecycleStatus(status, 'running');
}

function normalizePromptCounters(status, currentPrompt, totalPrompts, stageIndex) {
  let total = Number.isInteger(totalPrompts) ? totalPrompts : 0;
  let current = Number.isInteger(currentPrompt) ? currentPrompt : 0;
  const stage = Number.isInteger(stageIndex) ? stageIndex : null;

  if (total < 0) total = 0;
  if (current < 0) current = 0;

  if (total === 0 && Number.isInteger(stage) && stage >= 0) {
    total = stage + 1;
  }
  if (current === 0 && Number.isInteger(stage) && stage >= 0) {
    current = stage + 1;
  }
  if (total === 0 && current > 0) {
    total = current;
  }
  if (total > 0 && current > total) {
    current = total;
  }
  if (isClosedProcessStatus(status) && current === 0 && total > 0) {
    current = total;
  }
  if (status === 'completed' && total > 0) {
    current = total;
  }

  return { currentPrompt: current, totalPrompts: total };
}

function normalizeAutoRecoveryState(rawState) {
  if (!rawState || typeof rawState !== 'object') return null;

  const normalized = {};
  if (Number.isInteger(rawState.attempt) && rawState.attempt >= 0) {
    normalized.attempt = rawState.attempt;
  }
  if (Number.isInteger(rawState.maxAttempts) && rawState.maxAttempts > 0) {
    normalized.maxAttempts = rawState.maxAttempts;
  }
  if (Number.isInteger(rawState.delayMs) && rawState.delayMs >= 0) {
    normalized.delayMs = rawState.delayMs;
  }
  if (typeof rawState.reason === 'string' && rawState.reason.trim()) {
    normalized.reason = rawState.reason.trim();
  }
  if (Number.isInteger(rawState.currentPrompt) && rawState.currentPrompt >= 0) {
    normalized.currentPrompt = rawState.currentPrompt;
  }
  if (Number.isInteger(rawState.stageIndex) && rawState.stageIndex >= 0) {
    normalized.stageIndex = rawState.stageIndex;
  }
  if (Number.isInteger(rawState.updatedAt) && rawState.updatedAt > 0) {
    normalized.updatedAt = rawState.updatedAt;
  }

  if (Object.keys(normalized).length === 0) return null;
  if (!Number.isInteger(normalized.maxAttempts)) normalized.maxAttempts = AUTO_RECOVERY_MAX_ATTEMPTS;
  if (!Number.isInteger(normalized.delayMs)) normalized.delayMs = AUTO_RECOVERY_DELAY_MS;
  if (!Number.isInteger(normalized.attempt)) normalized.attempt = 0;
  return normalized;
}

function isFailedProcessStatus(status) {
  const normalized = normalizeProcessStatus(status);
  return normalized === 'failed' || normalized === 'error';
}

function collectProcessRecordAnomalies(record) {
  if (!record || typeof record !== 'object') return [];
  const anomalies = [];
  const status = normalizeProcessStatus(record.status);
  const currentPrompt = Number.isInteger(record.currentPrompt) ? record.currentPrompt : null;
  const totalPrompts = Number.isInteger(record.totalPrompts) ? record.totalPrompts : null;
  const hasTabOrWindow = Number.isInteger(record.tabId) || Number.isInteger(record.windowId);

  if (Number.isInteger(currentPrompt) && Number.isInteger(totalPrompts) && currentPrompt > totalPrompts) {
    anomalies.push('current_gt_total');
  }
  if (isClosedProcessStatus(status) && record.needsAction) {
    anomalies.push('closed_with_needs_action');
  }
  if (!isClosedProcessStatus(status) && !isQueuedProcessStatus(status) && !hasTabOrWindow) {
    anomalies.push('running_without_tab_or_window');
  }
  if (isFailedProcessStatus(status) && !record.reason && !record.error) {
    anomalies.push('failed_without_reason');
  }
  return anomalies;
}

function collectNormalizationCorrections(next, patch) {
  const corrections = [];
  if (!next || !patch || typeof patch !== 'object') return corrections;

  if (Number.isInteger(patch.currentPrompt) && patch.currentPrompt !== next.currentPrompt) {
    corrections.push(`currentPrompt:${patch.currentPrompt}->${next.currentPrompt}`);
  }
  if (Number.isInteger(patch.totalPrompts) && patch.totalPrompts !== next.totalPrompts) {
    corrections.push(`totalPrompts:${patch.totalPrompts}->${next.totalPrompts}`);
  }
  if (typeof patch.needsAction === 'boolean' && patch.needsAction !== next.needsAction) {
    corrections.push(`needsAction:${patch.needsAction}->${next.needsAction}`);
  }
  if (Number.isInteger(patch.stageIndex)) {
    const normalizedStage = Number.isInteger(next.stageIndex) ? next.stageIndex : null;
    if (patch.stageIndex !== normalizedStage) {
      corrections.push(`stageIndex:${patch.stageIndex}->${normalizedStage}`);
    }
  }
  if (typeof patch.status === 'string') {
    const patchStatus = normalizeProcessStatus(patch.status);
    if (patchStatus !== next.status) {
      corrections.push(`status:${patchStatus}->${next.status}`);
    }
  }
  return corrections;
}

function logProcessTransition(runId, next, patch) {
  const anomalies = collectProcessRecordAnomalies(next);
  const corrections = collectNormalizationCorrections(next, patch);
  if (anomalies.length === 0 && corrections.length === 0) return;

  console.warn('[monitor] Skorygowano niespojne dane procesu', {
    runId,
    corrections,
    anomalies,
    status: next.status,
    currentPrompt: next.currentPrompt,
    totalPrompts: next.totalPrompts,
    stageIndex: Number.isInteger(next.stageIndex) ? next.stageIndex : null
  });
}

function normalizeProcessRecord(record) {
  if (!record || typeof record !== 'object') return null;
  const id = typeof record.id === 'string' ? record.id : String(record.id || '');
  if (!id) return null;

  const lifecycleStatus = normalizeProcessLifecycleStatus(
    record.lifecycleStatus || record.status,
    'running'
  );
  const phase = normalizeProcessPhase(
    record.phase,
    typeof ProcessContractUtils.defaultPhaseForLifecycle === 'function'
      ? ProcessContractUtils.defaultPhaseForLifecycle(lifecycleStatus)
      : ''
  );
  const actionRequired = normalizeProcessActionRequired(
    record.actionRequired,
    deriveProcessActionRequired(record)
  );
  const status = lifecycleStatus;
  const effectiveActionRequired = isClosedProcessStatus(status) ? 'none' : actionRequired;
  const normalizedCounters = normalizePromptCounters(
    status,
    record.currentPrompt,
    record.totalPrompts,
    record.stageIndex
  );
  const timestamp = Number.isInteger(record.timestamp) ? record.timestamp : Date.now();
  const lastActivityAt = Number.isInteger(record.lastActivityAt) && record.lastActivityAt > 0
    ? record.lastActivityAt
    : timestamp;
  const nextStatusCode = deriveProcessStatusCode({
    ...record,
    lifecycleStatus,
    phase,
    actionRequired: effectiveActionRequired,
    status
  });
  const nextStatusText = buildOperatorStatusText({
    ...record,
    lifecycleStatus,
    phase,
    actionRequired: effectiveActionRequired,
    statusCode: nextStatusCode,
    status
  });
  const attempt = Number.isInteger(record.attempt) && record.attempt >= 0
    ? record.attempt
    : (
      Number.isInteger(record?.autoRecovery?.attempt) && record.autoRecovery.attempt >= 0
        ? record.autoRecovery.attempt
        : 0
    );
  const retryCount = Number.isInteger(record.retryCount) && record.retryCount >= 0
    ? record.retryCount
    : attempt;

  const normalized = {
    ...record,
    id,
    title: typeof record.title === 'string' && record.title.trim()
      ? record.title
      : 'Bez tytulu',
    analysisType: typeof record.analysisType === 'string' && record.analysisType.trim()
      ? record.analysisType
      : 'company',
    lifecycleStatus,
    phase,
    actionRequired: effectiveActionRequired,
    statusCode: nextStatusCode,
    status,
    currentPrompt: normalizedCounters.currentPrompt,
    totalPrompts: normalizedCounters.totalPrompts,
    timestamp,
    lastActivityAt,
    lastProgressAt: Number.isInteger(record.lastProgressAt) && record.lastProgressAt > 0
      ? record.lastProgressAt
      : (
        timestamp > 0 ? timestamp : Date.now()
      ),
    startedAt: Number.isInteger(record.startedAt)
      ? record.startedAt
      : (timestamp > 0 ? timestamp : Date.now()),
    phaseStartedAt: Number.isInteger(record.phaseStartedAt) && record.phaseStartedAt > 0
      ? record.phaseStartedAt
      : lastActivityAt,
    needsAction: effectiveActionRequired !== 'none',
    version: Number.isInteger(record.version) && record.version > 0 ? record.version : 1,
    attempt,
    retryCount,
    statusText: nextStatusText,
    messages: Array.isArray(record.messages) ? record.messages : []
  };

  if (!Number.isInteger(normalized.windowId)) delete normalized.windowId;
  if (!Number.isInteger(normalized.tabId)) delete normalized.tabId;
  if (!Number.isInteger(normalized.queuePosition) || normalized.queuePosition <= 0) delete normalized.queuePosition;
  if (!Number.isInteger(normalized.lastProgressAt)) delete normalized.lastProgressAt;
  if (!Number.isInteger(normalized.lastActivityAt)) delete normalized.lastActivityAt;
  if (!Number.isInteger(normalized.phaseStartedAt)) delete normalized.phaseStartedAt;
  if (typeof normalized.reason !== 'string') delete normalized.reason;
  if (typeof normalized.statusText !== 'string' || !normalized.statusText.trim()) delete normalized.statusText;
  if (typeof normalized.statusCode !== 'string' || !normalized.statusCode.trim()) delete normalized.statusCode;
  if (typeof normalized.stageName !== 'string') delete normalized.stageName;
  if (!Number.isInteger(normalized.stageIndex)) delete normalized.stageIndex;
  const normalizedChatUrl = normalizeChatConversationUrl(
    typeof normalized.chatUrl === 'string' ? normalized.chatUrl : ''
  );
  if (normalizedChatUrl) {
    normalized.chatUrl = normalizedChatUrl;
  } else {
    delete normalized.chatUrl;
  }
  const normalizedConversationUrls = normalizeConversationUrlList([
    ...(Array.isArray(normalized.conversationUrls) ? normalized.conversationUrls : []),
    normalized.chatUrl || ''
  ]);
  if (normalizedConversationUrls.length > 0) {
    normalized.conversationUrls = normalizedConversationUrls;
    if (!normalized.chatUrl) {
      normalized.chatUrl = normalizedConversationUrls[normalizedConversationUrls.length - 1];
    }
  } else {
    delete normalized.conversationUrls;
  }
  if (typeof normalized.sourceUrl !== 'string') delete normalized.sourceUrl;
  if (typeof normalized.error !== 'string') delete normalized.error;
  if (!Number.isInteger(normalized.finishedAt)) delete normalized.finishedAt;
  if (Number.isInteger(normalized.stageIndex) && normalized.totalPrompts > 0) {
    if (normalized.stageIndex < 0) {
      delete normalized.stageIndex;
    } else if (normalized.stageIndex >= normalized.totalPrompts) {
      normalized.stageIndex = normalized.totalPrompts - 1;
    }
  }
  if (Number.isInteger(normalized.stageIndex) && normalized.stageIndex >= 0) {
    const promptFromStage = normalized.stageIndex + 1;
    if (!Number.isInteger(normalized.currentPrompt) || normalized.currentPrompt < promptFromStage) {
      normalized.currentPrompt = promptFromStage;
    }
  }
  if (normalized.totalPrompts > 0 && normalized.currentPrompt === 0 && Number.isInteger(normalized.stageIndex)) {
    normalized.currentPrompt = Math.min(normalized.stageIndex + 1, normalized.totalPrompts);
  }
  if (normalized.totalPrompts > 0 && normalized.currentPrompt > normalized.totalPrompts) {
    normalized.currentPrompt = normalized.totalPrompts;
  }
  if (normalized.currentPrompt < 0) {
    normalized.currentPrompt = 0;
  }
  if (Number.isInteger(normalized.currentPrompt) && normalized.currentPrompt > 0) {
    const derivedStageIndex = normalized.currentPrompt - 1;
    if (!Number.isInteger(normalized.stageIndex) || normalized.stageIndex < derivedStageIndex) {
      normalized.stageIndex = derivedStageIndex;
    }
    if (normalized.totalPrompts > 0 && normalized.stageIndex >= normalized.totalPrompts) {
      normalized.stageIndex = normalized.totalPrompts - 1;
    }
  }
  if (normalized.startedAt > normalized.timestamp) {
    normalized.startedAt = normalized.timestamp;
  }
  if (Number.isInteger(normalized.finishedAt) && normalized.finishedAt < normalized.startedAt) {
    normalized.finishedAt = normalized.timestamp;
  }
  if (isClosedProcessStatus(status)) {
    delete normalized.autoRecovery;
  } else {
    const normalizedAutoRecovery = normalizeAutoRecoveryState(normalized.autoRecovery);
    if (normalizedAutoRecovery) {
      normalized.autoRecovery = normalizedAutoRecovery;
    } else {
      delete normalized.autoRecovery;
    }
  }
  if (normalized.actionRequired === 'none') {
    normalized.needsAction = false;
  }
  if (isClosedProcessStatus(normalized.lifecycleStatus)) {
    normalized.actionRequired = 'none';
    normalized.needsAction = false;
  }

  return normalized;
}

function normalizeConversationUrlList(rawValues, limit = PROCESS_CONVERSATION_URL_HISTORY_LIMIT) {
  const values = Array.isArray(rawValues) ? rawValues : [];
  const dedup = [];
  const seen = new Set();
  for (const value of values) {
    const normalized = normalizeChatConversationUrl(typeof value === 'string' ? value : '');
    if (!normalized || seen.has(normalized)) continue;
    seen.add(normalized);
    dedup.push(normalized);
  }
  if (!Number.isInteger(limit) || limit <= 0 || dedup.length <= limit) return dedup;
  return dedup.slice(dedup.length - limit);
}

function mergeProcessConversationUrls(existingRecord, nextRecord) {
  if (!nextRecord || typeof nextRecord !== 'object') return;
  const merged = normalizeConversationUrlList([
    ...(Array.isArray(existingRecord?.conversationUrls) ? existingRecord.conversationUrls : []),
    typeof existingRecord?.chatUrl === 'string' ? existingRecord.chatUrl : '',
    ...(Array.isArray(nextRecord?.conversationUrls) ? nextRecord.conversationUrls : []),
    typeof nextRecord?.chatUrl === 'string' ? nextRecord.chatUrl : ''
  ]);
  if (merged.length === 0) {
    delete nextRecord.conversationUrls;
    return;
  }
  nextRecord.conversationUrls = merged;
  const latest = merged[merged.length - 1];
  if (!normalizeChatConversationUrl(nextRecord.chatUrl || '')) {
    nextRecord.chatUrl = latest;
  }
}

function pruneProcessRecords(records) {
  const normalized = (Array.isArray(records) ? records : [])
    .map(normalizeProcessRecord)
    .filter(Boolean);

  const byId = new Map();
  normalized.forEach((record) => {
    const existing = byId.get(record.id);
    if (!existing) {
      byId.set(record.id, record);
      return;
    }
    const existingTs = Number.isInteger(existing.timestamp) ? existing.timestamp : 0;
    const nextTs = Number.isInteger(record.timestamp) ? record.timestamp : 0;
    if (nextTs >= existingTs) {
      byId.set(record.id, record);
    }
  });

  const deduped = Array.from(byId.values());
  const active = [];
  const closed = [];
  for (const process of deduped) {
    if (isClosedProcessStatus(process.status)) {
      closed.push(process);
    } else {
      active.push(process);
    }
  }

  active.sort((a, b) => (b.startedAt || b.timestamp || 0) - (a.startedAt || a.timestamp || 0));
  closed.sort((a, b) => (b.timestamp || 0) - (a.timestamp || 0));

  return active.concat(closed.slice(0, PROCESS_HISTORY_LIMIT));
}

function rehydrateProcessProblemLogState(records = []) {
  problemLogLastSignatureByRunId.clear();
  processLogLastEmitTsByRunId.clear();
  processStaleWarnLastEmitTsByRunId.clear();

  const sourceRecords = Array.isArray(records) ? records : [];
  const nowTs = Date.now();
  for (const record of sourceRecords) {
    if (!record || typeof record !== 'object') continue;
    const runId = typeof record.id === 'string' ? record.id.trim() : '';
    if (!runId) continue;
    if (isClosedProcessStatus(record.status)) continue;

    const entry = buildProcessProblemLogEntry(runId, record);
    const signature = typeof entry?.signature === 'string' ? entry.signature.trim() : '';
    if (!signature) continue;

    problemLogLastSignatureByRunId.set(runId, signature);
    const ts = Number.isInteger(record.timestamp) && record.timestamp > 0
      ? record.timestamp
      : nowTs;
    processLogLastEmitTsByRunId.set(runId, ts);
  }
}

async function ensureProcessRegistryReady() {
  if (!processRegistryReady) {
    processRegistryReady = (async () => {
      try {
        const stored = await chrome.storage.local.get([PROCESS_MONITOR_STORAGE_KEY]);
        const records = pruneProcessRecords(stored?.[PROCESS_MONITOR_STORAGE_KEY]);
        processRegistry.clear();
        records.forEach((record) => {
          processRegistry.set(record.id, record);
        });
        processRegistryVersion = records.reduce((maxValue, record) => {
          const version = Number.isInteger(record?.version) ? record.version : 0;
          return Math.max(maxValue, version);
        }, 0);
        processSnapshotVersion = processRegistryVersion;
        rehydrateProcessProblemLogState(records);
        scheduleCompletedProcessPersistenceRetriesForSnapshot(records, 'process_registry_ready');
      } catch (error) {
        console.warn('[monitor] Failed to read process monitor state:', error);
        processRegistry.clear();
        problemLogLastSignatureByRunId.clear();
        processLogLastEmitTsByRunId.clear();
        processStaleWarnLastEmitTsByRunId.clear();
        completedProcessPersistenceRetryTimersByRunId.forEach((timerId) => clearTimeout(timerId));
        completedProcessPersistenceRetryTimersByRunId.clear();
        completedProcessPersistenceRetryAttemptCountByRunId.clear();
        completedProcessPersistenceRetryInFlight.clear();
      }
    })();
  }
  return processRegistryReady;
}

async function persistProcessRegistry() {
  const records = pruneProcessRecords(Array.from(processRegistry.values()));
  processRegistry.clear();
  records.forEach((record) => {
    processRegistry.set(record.id, record);
  });
  await chrome.storage.local.set({ [PROCESS_MONITOR_STORAGE_KEY]: records });
  return records;
}

function shouldFlushProcessUpdateImmediately(existingProcess = null, nextProcess = null, patch = {}) {
  const existing = existingProcess && typeof existingProcess === 'object' ? existingProcess : null;
  const next = nextProcess && typeof nextProcess === 'object' ? nextProcess : null;
  const candidatePatch = patch && typeof patch === 'object' ? patch : {};
  if (!next) return true;
  if (isClosedProcessStatus(next.lifecycleStatus || next.status)) return true;
  if (normalizeProcessActionRequired(next.actionRequired || '', deriveProcessActionRequired(next)) !== 'none') return true;

  const existingPrompt = Number.isInteger(existing?.currentPrompt) ? existing.currentPrompt : 0;
  const nextPrompt = Number.isInteger(next?.currentPrompt) ? next.currentPrompt : 0;
  if (nextPrompt > existingPrompt) return true;

  const existingQueueState = typeof existing?.queueState === 'string' ? existing.queueState.trim() : '';
  const nextQueueState = typeof next?.queueState === 'string' ? next.queueState.trim() : '';
  if (existingQueueState !== nextQueueState) return true;

  if ('slotReserved' in candidatePatch || 'slotReleasedAt' in candidatePatch || 'queuePosition' in candidatePatch) {
    return true;
  }

  return false;
}

function clearScheduledProcessRegistryFlush() {
  if (processRegistryFlushTimer !== null) {
    clearTimeout(processRegistryFlushTimer);
    processRegistryFlushTimer = null;
  }
}

async function flushScheduledProcessRegistry(reason = 'scheduled') {
  clearScheduledProcessRegistryFlush();
  if (!processRegistryDirty) {
    return pruneProcessRecords(Array.from(processRegistry.values()));
  }
  processRegistryDirty = false;
  processRegistryFlushReason = '';
  processSnapshotVersion = processRegistryVersion;
  const records = await persistProcessRegistry();
  await broadcastProcessUpdate({
    processes: records,
    reason,
    version: processSnapshotVersion
  });
  return records;
}

function scheduleProcessRegistryFlush(reason = 'scheduled', options = {}) {
  const normalizedReason = typeof reason === 'string' && reason.trim() ? reason.trim() : 'scheduled';
  processRegistryDirty = true;
  processRegistryFlushReason = normalizedReason;
  const immediate = options?.immediate === true;

  if (immediate) {
    processRegistryFlushPromise = processRegistryFlushPromise.then(
      () => flushScheduledProcessRegistry(normalizedReason),
      () => flushScheduledProcessRegistry(normalizedReason)
    );
    return processRegistryFlushPromise;
  }

  if (processRegistryFlushTimer !== null) {
    return processRegistryFlushPromise;
  }

  processRegistryFlushTimer = setTimeout(() => {
    processRegistryFlushTimer = null;
    processRegistryFlushPromise = processRegistryFlushPromise.then(
      () => flushScheduledProcessRegistry(processRegistryFlushReason || normalizedReason),
      () => flushScheduledProcessRegistry(processRegistryFlushReason || normalizedReason)
    );
  }, PROCESS_UPDATE_DEBOUNCE_MS);
  return processRegistryFlushPromise;
}

function applyQueuePositionsToProcesses(records = [], queueState = null) {
  const sourceRecords = Array.isArray(records) ? records : [];
  const state = queueState && typeof queueState === 'object' ? queueState : analysisQueueState;
  const waitingJobs = Array.isArray(state?.waitingJobs) ? state.waitingJobs : [];
  const queuePositionByRunId = new Map();
  waitingJobs.forEach((job, index) => {
    const runId = typeof job?.runId === 'string' ? job.runId.trim() : '';
    if (!runId || queuePositionByRunId.has(runId)) return;
    queuePositionByRunId.set(runId, index + 1);
  });
  return sourceRecords.map((record) => {
    const runId = typeof record?.id === 'string' ? record.id.trim() : '';
    const queuePosition = queuePositionByRunId.get(runId) || null;
    if (!queuePosition) {
      if (!record || typeof record !== 'object') return record;
      if (!('queuePosition' in record)) return record;
      const { queuePosition: _queuePosition, ...rest } = record;
      return rest;
    }
    return {
      ...record,
      queuePosition
    };
  });
}

async function getProcessSnapshot() {
  await ensureProcessRegistryReady();
  await ensureAnalysisQueueReady().catch(() => null);
  const records = pruneProcessRecords(Array.from(processRegistry.values()));
  return applyQueuePositionsToProcesses(records);
}

function sanitizeManualPdfAttachmentContext(rawAttachment) {
  if (!rawAttachment || typeof rawAttachment !== 'object') return null;
  const providerId = typeof rawAttachment.providerId === 'string' ? rawAttachment.providerId.trim() : '';
  const token = typeof rawAttachment.token === 'string' ? rawAttachment.token.trim() : '';
  if (!providerId || !token) return null;
  return {
    enabled: rawAttachment.enabled !== false,
    providerId,
    token,
    name: typeof rawAttachment.name === 'string' ? rawAttachment.name : 'source.pdf',
    mimeType: typeof rawAttachment.mimeType === 'string' ? rawAttachment.mimeType : 'application/pdf',
    size: Number.isFinite(rawAttachment.size) ? Math.max(0, Math.floor(rawAttachment.size)) : 0,
    instanceIndex: Number.isInteger(rawAttachment.instanceIndex) ? rawAttachment.instanceIndex : null,
    instanceTotal: Number.isInteger(rawAttachment.instanceTotal) ? rawAttachment.instanceTotal : null
  };
}

function sanitizeAnalysisQueueTabSnapshot(rawTab) {
  if (!rawTab || typeof rawTab !== 'object') return null;
  const title = typeof rawTab.title === 'string' && rawTab.title.trim()
    ? rawTab.title.trim()
    : 'Bez tytulu';
  const url = typeof rawTab.url === 'string' ? rawTab.url : '';
  const snapshot = {
    id: rawTab.id,
    title,
    url
  };
  if (Number.isInteger(rawTab.windowId)) snapshot.windowId = rawTab.windowId;
  if (Number.isInteger(rawTab.index)) snapshot.index = rawTab.index;
  if (typeof rawTab.manualText === 'string') snapshot.manualText = rawTab.manualText;
  const manualPdfAttachment = sanitizeManualPdfAttachmentContext(rawTab.manualPdfAttachment);
  if (manualPdfAttachment) {
    snapshot.manualPdfAttachment = manualPdfAttachment;
  }
  return snapshot;
}

function sanitizePromptChainSnapshot(rawPromptChain) {
  if (!Array.isArray(rawPromptChain)) return [];
  return rawPromptChain
    .map((item) => (typeof item === 'string' ? item.trim() : ''))
    .filter((item) => item.length > 0);
}

function sanitizeRemoteAnalysisQueueJobMetadata(rawRemote) {
  if (!rawRemote || typeof rawRemote !== 'object') return null;
  const remoteJobId = typeof rawRemote.remoteJobId === 'string'
    ? rawRemote.remoteJobId.trim()
    : (typeof rawRemote.jobId === 'string' ? rawRemote.jobId.trim() : '');
  if (!remoteJobId) return null;
  const remoteAttemptId = typeof rawRemote.remoteAttemptId === 'string'
    ? rawRemote.remoteAttemptId.trim()
    : (typeof rawRemote.attemptId === 'string' ? rawRemote.attemptId.trim() : '');
  return {
    remoteJobId,
    remoteAttemptId,
    remoteRunnerId: typeof rawRemote.remoteRunnerId === 'string'
      ? rawRemote.remoteRunnerId.trim()
      : (typeof rawRemote.runnerId === 'string' ? rawRemote.runnerId.trim() : ''),
    controllerId: typeof rawRemote.controllerId === 'string' ? rawRemote.controllerId.trim() : '',
    batchId: typeof rawRemote.batchId === 'string' ? rawRemote.batchId.trim() : '',
    submissionId: typeof rawRemote.submissionId === 'string' ? rawRemote.submissionId.trim() : ''
  };
}

function sanitizeAnalysisQueueJob(rawJob) {
  if (!rawJob || typeof rawJob !== 'object') return null;
  const kind = rawJob.kind === ANALYSIS_QUEUE_KIND_RESUME_STAGE
    ? ANALYSIS_QUEUE_KIND_RESUME_STAGE
    : ANALYSIS_QUEUE_KIND_ARTICLE;
  const jobId = typeof rawJob.jobId === 'string' ? rawJob.jobId.trim() : '';
  const runId = typeof rawJob.runId === 'string' ? rawJob.runId.trim() : '';
  if (!jobId || !runId) return null;

  const sanitized = {
    jobId,
    runId,
    kind,
    createdAt: Number.isInteger(rawJob.createdAt) ? rawJob.createdAt : Date.now(),
    sequence: Number.isInteger(rawJob.sequence) ? rawJob.sequence : 0,
    analysisType: typeof rawJob.analysisType === 'string' && rawJob.analysisType.trim()
      ? rawJob.analysisType.trim()
      : 'company',
    title: typeof rawJob.title === 'string' && rawJob.title.trim()
      ? rawJob.title.trim()
      : 'Bez tytulu',
    sourceKind: typeof rawJob.sourceKind === 'string' ? rawJob.sourceKind.trim() : '',
    queueBatchId: typeof rawJob.queueBatchId === 'string' ? rawJob.queueBatchId.trim() : '',
    manualPdfBatchId: typeof rawJob.manualPdfBatchId === 'string' ? rawJob.manualPdfBatchId.trim() : '',
    manualPdfProviderId: typeof rawJob.manualPdfProviderId === 'string' ? rawJob.manualPdfProviderId.trim() : '',
    sourceUrl: typeof rawJob.sourceUrl === 'string' ? rawJob.sourceUrl.trim() : '',
    chatUrl: typeof rawJob.chatUrl === 'string' ? rawJob.chatUrl.trim() : '',
    startedAt: Number.isInteger(rawJob.startedAt) ? rawJob.startedAt : null,
    slotReservedAt: Number.isInteger(rawJob.slotReservedAt) ? rawJob.slotReservedAt : null,
    dispatchDeadlineAt: Number.isInteger(rawJob.dispatchDeadlineAt) ? rawJob.dispatchDeadlineAt : null
  };

  if (Number.isInteger(rawJob.invocationWindowId)) sanitized.invocationWindowId = rawJob.invocationWindowId;
  if (Number.isInteger(rawJob.sourceWindowId)) sanitized.sourceWindowId = rawJob.sourceWindowId;
  const promptChainSnapshot = sanitizePromptChainSnapshot(rawJob.promptChainSnapshot);
  if (promptChainSnapshot.length > 0) {
    sanitized.promptChainSnapshot = promptChainSnapshot;
  }
  if (typeof rawJob.promptHash === 'string' && rawJob.promptHash.trim()) {
    sanitized.promptHash = rawJob.promptHash.trim();
  }
  const remote = sanitizeRemoteAnalysisQueueJobMetadata(rawJob.remote);
  if (remote) {
    sanitized.remote = remote;
  }

  if (kind === ANALYSIS_QUEUE_KIND_ARTICLE) {
    const tabSnapshot = sanitizeAnalysisQueueTabSnapshot(rawJob.tabSnapshot || rawJob.tab);
    if (!tabSnapshot) return null;
    sanitized.tabSnapshot = tabSnapshot;
  } else {
    const resumeTargetTabId = Number.isInteger(rawJob.resumeTargetTabId)
      ? rawJob.resumeTargetTabId
      : (Number.isInteger(rawJob.targetTabId) ? rawJob.targetTabId : null);
    if (!Number.isInteger(resumeTargetTabId)) return null;
    sanitized.resumeTargetTabId = resumeTargetTabId;
    if (Number.isInteger(rawJob.resumeTargetWindowId)) {
      sanitized.resumeTargetWindowId = rawJob.resumeTargetWindowId;
    } else if (Number.isInteger(rawJob.targetWindowId)) {
      sanitized.resumeTargetWindowId = rawJob.targetWindowId;
    }
    sanitized.resumeStartIndex = Number.isInteger(rawJob.resumeStartIndex)
      ? rawJob.resumeStartIndex
      : (Number.isInteger(rawJob.startIndex) ? rawJob.startIndex : 0);
    if (Number.isInteger(rawJob.minStartIndex)) {
      sanitized.minStartIndex = rawJob.minStartIndex;
    }
    if (Number.isInteger(rawJob.stagePlanMaxWaitMs)) {
      sanitized.stagePlanMaxWaitMs = rawJob.stagePlanMaxWaitMs;
    }
    sanitized.reloadBeforeResume = rawJob.reloadBeforeResume !== false;
    sanitized.forceRepeatLastPrompt = rawJob.forceRepeatLastPrompt === true;
    sanitized.skipStagePreflight = rawJob.skipStagePreflight === true;
    if (typeof rawJob.composerThinkingEffort === 'string' && rawJob.composerThinkingEffort.trim()) {
      sanitized.composerThinkingEffort = rawJob.composerThinkingEffort.trim();
    }
    if (rawJob.precomputedStagePlan && typeof rawJob.precomputedStagePlan === 'object') {
      sanitized.precomputedStagePlan = rawJob.precomputedStagePlan;
    }
  }

  return sanitized;
}

function getAnalysisQueueJobPriority(job) {
  return job?.kind === ANALYSIS_QUEUE_KIND_RESUME_STAGE ? 0 : 1;
}

function compareAnalysisQueueJobs(left, right) {
  const priorityDiff = getAnalysisQueueJobPriority(left) - getAnalysisQueueJobPriority(right);
  if (priorityDiff !== 0) return priorityDiff;

  const leftSequence = Number.isInteger(left?.sequence) && left.sequence > 0 ? left.sequence : null;
  const rightSequence = Number.isInteger(right?.sequence) && right.sequence > 0 ? right.sequence : null;
  if (leftSequence !== null && rightSequence !== null && leftSequence !== rightSequence) {
    return leftSequence - rightSequence;
  }

  const leftCreatedAt = Number.isInteger(left?.createdAt) ? left.createdAt : 0;
  const rightCreatedAt = Number.isInteger(right?.createdAt) ? right.createdAt : 0;
  if (leftCreatedAt !== rightCreatedAt) return leftCreatedAt - rightCreatedAt;

  return String(left?.jobId || '').localeCompare(String(right?.jobId || ''));
}

function sortAnalysisQueueWaitingJobs(waitingJobs) {
  if (!Array.isArray(waitingJobs) || waitingJobs.length < 2) return waitingJobs;
  waitingJobs.sort(compareAnalysisQueueJobs);
  return waitingJobs;
}

function createEmptyAnalysisQueueState() {
  return {
    waitingJobs: [],
    activeJobs: [],
    maxConcurrent: ANALYSIS_QUEUE_MAX_CONCURRENT,
    lastSequence: 0
  };
}

function sanitizeAnalysisQueueState(rawState) {
  const source = rawState && typeof rawState === 'object'
    ? rawState
    : {};
  const waitingJobs = [];
  const activeJobs = [];
  const seenJobIds = new Set();

  const appendJob = (target, rawJob) => {
    const job = sanitizeAnalysisQueueJob(rawJob);
    if (!job || seenJobIds.has(job.jobId)) return;
    seenJobIds.add(job.jobId);
    target.push(job);
  };

  const waitingSource = Array.isArray(source.waitingJobs) ? source.waitingJobs : [];
  const activeSource = Array.isArray(source.activeJobs) ? source.activeJobs : [];
  waitingSource.forEach((job) => appendJob(waitingJobs, job));
  activeSource.forEach((job) => appendJob(activeJobs, job));
  sortAnalysisQueueWaitingJobs(waitingJobs);

  const maxSeenSequence = waitingJobs.concat(activeJobs).reduce((maxValue, job) => {
    const sequence = Number.isInteger(job?.sequence) && job.sequence > 0 ? job.sequence : 0;
    return Math.max(maxValue, sequence);
  }, 0);
  const storedLastSequence = Number.isInteger(source.lastSequence) ? Math.max(0, source.lastSequence) : 0;

  return {
    waitingJobs,
    activeJobs,
    maxConcurrent: ANALYSIS_QUEUE_MAX_CONCURRENT,
    lastSequence: Math.max(storedLastSequence, maxSeenSequence)
  };
}

function cloneAnalysisQueueState(state = null) {
  return sanitizeAnalysisQueueState(state || analysisQueueState || createEmptyAnalysisQueueState());
}

async function ensureAnalysisQueueReady() {
  if (!analysisQueueReady) {
    analysisQueueReady = (async () => {
      try {
        const stored = await chrome.storage.local.get([ANALYSIS_QUEUE_STORAGE_KEY]);
        analysisQueueState = sanitizeAnalysisQueueState(stored?.[ANALYSIS_QUEUE_STORAGE_KEY]);
      } catch (error) {
        console.warn('[analysis-queue] Failed to read queue state:', error?.message || String(error));
        analysisQueueState = createEmptyAnalysisQueueState();
      }
      if (!analysisQueueState) {
        analysisQueueState = createEmptyAnalysisQueueState();
      }
      return analysisQueueState;
    })();
  }
  return analysisQueueReady;
}

function clearAnalysisQueueDeadlineTimer() {
  if (analysisQueueDeadlineTimer !== null) {
    clearTimeout(analysisQueueDeadlineTimer);
    analysisQueueDeadlineTimer = null;
  }
}

function scheduleAnalysisQueueDeadlineTimerFromState(state = null) {
  clearAnalysisQueueDeadlineTimer();
  const snapshot = sanitizeAnalysisQueueState(state || analysisQueueState || createEmptyAnalysisQueueState());
  const deadlines = snapshot.activeJobs
    .map((job) => Number.isInteger(job.dispatchDeadlineAt) ? job.dispatchDeadlineAt : null)
    .filter((value) => Number.isInteger(value) && value > Date.now())
    .sort((left, right) => left - right);
  if (deadlines.length === 0) return;
  const nextDelayMs = Math.max(500, deadlines[0] - Date.now());
  analysisQueueDeadlineTimer = setTimeout(() => {
    analysisQueueDeadlineTimer = null;
    requestAnalysisQueueReconcile('dispatch_deadline_timer');
  }, nextDelayMs);
}

async function persistAnalysisQueueState(nextState = null) {
  const normalized = sanitizeAnalysisQueueState(nextState || analysisQueueState || createEmptyAnalysisQueueState());
  analysisQueueState = normalized;
  analysisQueueVersion += 1;
  await chrome.storage.local.set({ [ANALYSIS_QUEUE_STORAGE_KEY]: normalized });
  scheduleAnalysisQueueDeadlineTimerFromState(normalized);
  return normalized;
}

function withAnalysisQueueMutationLock(task) {
  const taskFn = typeof task === 'function' ? task : null;
  if (!taskFn) {
    return Promise.reject(new Error('analysis_queue_mutation_task_required'));
  }
  const next = analysisQueueMutationQueue.then(
    () => taskFn(),
    () => taskFn()
  );
  analysisQueueMutationQueue = next.catch(() => {});
  return next;
}

async function getAnalysisQueueSnapshot() {
  await ensureAnalysisQueueReady();
  return cloneAnalysisQueueState();
}

function getProcessLastActivityTimestamp(process) {
  if (!process || typeof process !== 'object') return 0;
  if (Number.isInteger(process.lastActivityAt) && process.lastActivityAt > 0) return process.lastActivityAt;
  if (Number.isInteger(process.timestamp) && process.timestamp > 0) return process.timestamp;
  if (Number.isInteger(process.startedAt) && process.startedAt > 0) return process.startedAt;
  return 0;
}

function getProcessLastProgressTimestamp(process) {
  if (!process || typeof process !== 'object') return 0;
  if (Number.isInteger(process.lastProgressAt) && process.lastProgressAt > 0) {
    return process.lastProgressAt;
  }
  return getProcessLastActivityTimestamp(process);
}

function getAnalysisQueueCompletionTimestamp(process) {
  if (!process || typeof process !== 'object') return 0;
  const candidates = [
    process.finishedAt,
    process.completedResponseCapturedAt
  ].filter((value) => Number.isInteger(value) && value > 0);
  return candidates.length > 0 ? Math.max(...candidates) : 0;
}

function resolveAnalysisQueueDispatchDeadlineAt(job, process, nowTs = Date.now()) {
  const explicitDeadlineAt = Number.isInteger(job?.dispatchDeadlineAt) && job.dispatchDeadlineAt > 0
    ? job.dispatchDeadlineAt
    : null;
  const completedAt = getAnalysisQueueCompletionTimestamp(process);
  const completionFallbackDeadlineAt = completedAt > 0
    ? completedAt + ANALYSIS_QUEUE_DISPATCH_CONFIRM_TIMEOUT_MS
    : null;
  if (Number.isInteger(explicitDeadlineAt) && Number.isInteger(completionFallbackDeadlineAt)) {
    return Math.min(explicitDeadlineAt, completionFallbackDeadlineAt);
  }
  if (Number.isInteger(completionFallbackDeadlineAt)) return completionFallbackDeadlineAt;
  if (Number.isInteger(explicitDeadlineAt)) return explicitDeadlineAt;
  return nowTs + ANALYSIS_QUEUE_DISPATCH_CONFIRM_TIMEOUT_MS;
}

function getAnalysisQueueProcessContextKey(process) {
  if (!process || typeof process !== 'object') return '';
  if (Number.isInteger(process.tabId)) return `tab:${process.tabId}`;
  if (Number.isInteger(process.windowId)) return `window:${process.windowId}`;
  const runId = typeof process.id === 'string' ? process.id.trim() : '';
  return runId ? `run:${runId}` : '';
}

function shouldProcessOccupyAnalysisQueueSlot(process) {
  if (!process || typeof process !== 'object') return false;
  const status = normalizeProcessLifecycleStatus(process.lifecycleStatus || process.status, 'running');
  if (process.queueManaged === true && process.slotReserved === false && status !== 'queued') {
    return false;
  }
  if (status === 'finalizing' || status === 'completed') return false;
  if (isClosedProcessStatus(status)) return false;
  if (status === 'queued') {
    return process.queueManaged === true && process.slotReserved === true;
  }
  return true;
}

function isProcessWithinAnalysisQueueContextGrace(process, nowTs = Date.now()) {
  if (!process || typeof process !== 'object') return false;
  if (Number.isInteger(process.tabId) || Number.isInteger(process.windowId)) return false;
  const lastSeenAt = getProcessLastActivityTimestamp(process);
  if (lastSeenAt <= 0) return false;
  return Math.max(0, nowTs - lastSeenAt) <= ANALYSIS_QUEUE_LOCAL_CONTEXT_GRACE_MS;
}

async function getAnalysisQueueProcessActivityState(process, nowTs = Date.now()) {
  const contextKey = getAnalysisQueueProcessContextKey(process);
  if (!shouldProcessOccupyAnalysisQueueSlot(process)) {
    return {
      active: false,
      live: false,
      recent: false,
      contextKey,
      reason: 'not_counted'
    };
  }

  const status = normalizeProcessStatus(process?.status);
  if (status === 'completed') {
    const runId = typeof process?.id === 'string' ? process.id.trim() : '';
    return {
      active: true,
      live: false,
      recent: false,
      contextKey: runId ? `run:${runId}` : contextKey,
      reason: hasProcessReachedFinalStage(process)
        ? 'completed_dispatch_pending'
        : 'completed_final_stage_pending'
    };
  }

  const tabId = Number.isInteger(process.tabId) ? process.tabId : null;
  if (tabId !== null) {
    const tab = await getTabByIdSafe(tabId);
    if (tab) {
      return {
        active: true,
        live: true,
        recent: false,
        contextKey: `tab:${tabId}`,
        reason: 'tab_exists'
      };
    }
  }

  const windowId = Number.isInteger(process.windowId) ? process.windowId : null;
  if (windowId !== null) {
    const queryResult = await queryTabsInWindowSafe(windowId);
    if (queryResult?.ok === true) {
      const hasTabs = Array.isArray(queryResult.tabs) && queryResult.tabs.length > 0;
      if (hasTabs) {
        return {
          active: true,
          live: true,
          recent: false,
          contextKey: `window:${windowId}`,
          reason: 'window_exists'
        };
      }
    }
  }

  if (isProcessWithinAnalysisQueueContextGrace(process, nowTs)) {
    return {
      active: true,
      live: false,
      recent: true,
      contextKey,
      reason: 'recent_grace'
    };
  }

  return {
    active: false,
    live: false,
    recent: false,
    contextKey,
    reason: 'local_context_missing'
  };
}

async function isLocalProcessActiveForQueue(process, nowTs = Date.now()) {
  const activity = await getAnalysisQueueProcessActivityState(process, nowTs);
  return activity.active === true;
}

function shouldReplaceAnalysisQueueActiveProcess(existingEntry, nextEntry) {
  const existingScore = existingEntry?.activity?.live ? 2 : (existingEntry?.activity?.recent ? 1 : 0);
  const nextScore = nextEntry?.activity?.live ? 2 : (nextEntry?.activity?.recent ? 1 : 0);
  if (existingScore !== nextScore) return nextScore > existingScore;

  const existingTs = getProcessLastActivityTimestamp(existingEntry?.process);
  const nextTs = getProcessLastActivityTimestamp(nextEntry?.process);
  if (existingTs !== nextTs) return nextTs > existingTs;

  return String(nextEntry?.process?.id || '').localeCompare(String(existingEntry?.process?.id || '')) > 0;
}

function getAnalysisQueueJobContextKey(job, process = null) {
  const processContextKey = getAnalysisQueueProcessContextKey(process);
  if (processContextKey) return processContextKey;
  if (!job || typeof job !== 'object') return '';

  if (Number.isInteger(job.resumeTargetTabId)) return `tab:${job.resumeTargetTabId}`;
  if (Number.isInteger(job?.tabSnapshot?.id)) return `tab:${job.tabSnapshot.id}`;
  if (Number.isInteger(job.resumeTargetWindowId)) return `window:${job.resumeTargetWindowId}`;
  if (Number.isInteger(job.invocationWindowId)) return `window:${job.invocationWindowId}`;
  if (Number.isInteger(job.sourceWindowId)) return `window:${job.sourceWindowId}`;

  const chatUrl = typeof job.chatUrl === 'string' ? job.chatUrl.trim() : '';
  if (chatUrl) return `chat:${chatUrl}`;
  const sourceUrl = typeof job.sourceUrl === 'string' ? job.sourceUrl.trim() : '';
  if (sourceUrl) return `source:${sourceUrl}`;

  const runId = typeof job.runId === 'string' ? job.runId.trim() : '';
  return runId ? `run:${runId}` : '';
}

function shouldReplaceAnalysisQueueActiveJob(existingEntry, nextEntry) {
  const existingHasProcess = !!(existingEntry?.process && typeof existingEntry.process === 'object');
  const nextHasProcess = !!(nextEntry?.process && typeof nextEntry.process === 'object');
  if (existingHasProcess && nextHasProcess) {
    return shouldReplaceAnalysisQueueActiveProcess(existingEntry, nextEntry);
  }
  if (nextHasProcess !== existingHasProcess) return nextHasProcess;

  const existingStartedAt = Number.isInteger(existingEntry?.job?.startedAt) ? existingEntry.job.startedAt : 0;
  const nextStartedAt = Number.isInteger(nextEntry?.job?.startedAt) ? nextEntry.job.startedAt : 0;
  if (existingStartedAt !== nextStartedAt) return nextStartedAt > existingStartedAt;

  const existingSequence = Number.isInteger(existingEntry?.job?.sequence) ? existingEntry.job.sequence : 0;
  const nextSequence = Number.isInteger(nextEntry?.job?.sequence) ? nextEntry.job.sequence : 0;
  if (existingSequence !== nextSequence) return nextSequence > existingSequence;

  return String(nextEntry?.job?.runId || '').localeCompare(String(existingEntry?.job?.runId || '')) > 0;
}

async function collectAnalysisQueueActiveProcesses(options = {}) {
  const nowTs = Number.isInteger(options?.nowTs) ? options.nowTs : Date.now();
  const sourceProcesses = Array.isArray(options?.processes)
    ? pruneProcessRecords(options.processes)
    : pruneProcessRecords(Array.from(processRegistry.values()));
  const excludedRunIds = options?.excludedRunIds instanceof Set
    ? options.excludedRunIds
    : new Set(Array.isArray(options?.excludedRunIds) ? options.excludedRunIds : []);
  const candidates = await Promise.all(sourceProcesses.map(async (process) => {
    const runId = typeof process?.id === 'string' ? process.id.trim() : '';
    if (!runId || excludedRunIds.has(runId)) return null;
    const activity = await getAnalysisQueueProcessActivityState(process, nowTs);
    if (!activity.active) return null;
    return { process, activity };
  }));

  const deduped = new Map();
  for (const entry of candidates) {
    if (!entry) continue;
    const key = entry.activity.contextKey || `run:${entry.process.id}`;
    const existingEntry = deduped.get(key);
    if (!existingEntry || shouldReplaceAnalysisQueueActiveProcess(existingEntry, entry)) {
      deduped.set(key, entry);
    }
  }

  return Array.from(deduped.values());
}

async function getAnalysisQueueStatusSnapshot() {
  const [snapshot] = await Promise.all([
    getAnalysisQueueSnapshot(),
    ensureProcessRegistryReady()
  ]);
  const activeProcesses = await collectAnalysisQueueActiveProcesses();
  const activeSlots = activeProcesses.length;
  const reservedSlots = snapshot.activeJobs.length;
  const liveSlots = activeProcesses.filter((entry) => entry?.activity?.live === true).length;
  const startingSlots = Math.max(0, reservedSlots - liveSlots);
  return {
    success: true,
    version: analysisQueueVersion,
    maxConcurrent: snapshot.maxConcurrent,
    activeSlots,
    reservedSlots,
    liveSlots,
    startingSlots,
    queueSize: snapshot.waitingJobs.length,
    waitingJobs: snapshot.waitingJobs.length,
    activeJobs: reservedSlots,
    liveActiveJobs: liveSlots,
    totalJobs: snapshot.waitingJobs.length + reservedSlots
  };
}

async function broadcastProcessUpdate(options = {}) {
  const providedProcesses = Array.isArray(options?.processes) ? options.processes : null;
  const processes = applyQueuePositionsToProcesses(
    providedProcesses || await getProcessSnapshot()
  );
  let queue = null;
  try {
    queue = await getAnalysisQueueStatusSnapshot();
  } catch {
    queue = null;
  }
  try {
    await chrome.runtime.sendMessage({
      type: 'PROCESSES_UPDATE',
      processes,
      queue,
      version: Number.isInteger(options?.version) ? options.version : processSnapshotVersion,
      queueVersion: Number.isInteger(queue?.version) ? queue.version : analysisQueueVersion,
      reason: typeof options?.reason === 'string' ? options.reason : ''
    });
  } catch (error) {
    // Ignore: no listeners currently connected.
  }
  return processes;
}

function requestAnalysisQueueReconcile(reason = 'manual') {
  const normalizedReason = typeof reason === 'string' && reason.trim()
    ? reason.trim()
    : 'manual';
  if (analysisQueueReconcileInProgress) {
    analysisQueueReconcileRequested = true;
    return;
  }
  analysisQueueReconcileRequested = true;
  Promise.resolve().then(() => reconcileAnalysisQueueState(normalizedReason)).catch((error) => {
    console.warn('[analysis-queue] reconcile request failed:', error?.message || String(error));
  });
}

function normalizeRemoteExecutionMode(value) {
  const normalized = typeof value === 'string' ? value.trim().toLowerCase() : '';
  return normalized === 'remote' ? 'remote' : 'local';
}

async function getStoredRemoteExecutionMode() {
  try {
    const stored = await chrome.storage.local.get([ISKRA_REMOTE_EXECUTION_MODE_STORAGE_KEY]);
    return normalizeRemoteExecutionMode(stored?.[ISKRA_REMOTE_EXECUTION_MODE_STORAGE_KEY]);
  } catch (error) {
    return 'local';
  }
}

async function getStoredSelectedRemoteRunnerId() {
  try {
    const stored = await chrome.storage.local.get([ISKRA_REMOTE_SELECTED_RUNNER_ID_STORAGE_KEY]);
    return typeof stored?.[ISKRA_REMOTE_SELECTED_RUNNER_ID_STORAGE_KEY] === 'string'
      ? stored[ISKRA_REMOTE_SELECTED_RUNNER_ID_STORAGE_KEY].trim()
      : '';
  } catch (error) {
    return '';
  }
}

async function getStoredRemoteRunnerEnabled() {
  try {
    const stored = await chrome.storage.local.get([ISKRA_REMOTE_RUNNER_ENABLED_STORAGE_KEY]);
    return stored?.[ISKRA_REMOTE_RUNNER_ENABLED_STORAGE_KEY] === true;
  } catch (error) {
    return false;
  }
}

async function getStoredRemoteRunnerName() {
  try {
    const stored = await chrome.storage.local.get([ISKRA_REMOTE_RUNNER_NAME_STORAGE_KEY]);
    return typeof stored?.[ISKRA_REMOTE_RUNNER_NAME_STORAGE_KEY] === 'string'
      ? stored[ISKRA_REMOTE_RUNNER_NAME_STORAGE_KEY].trim()
      : '';
  } catch (error) {
    return '';
  }
}

function normalizeRemoteRunnerName(value) {
  return typeof value === 'string' ? value.trim().slice(0, 80) : '';
}

function normalizeSelectedRemoteRunnerId(value) {
  return typeof value === 'string' ? value.trim() : '';
}

async function getRemoteExecutionConfigSnapshot(options = {}) {
  const identityPromise = getConfiguredRemoteRunnerIdentity();
  const localStatePromise = getRemoteRunnerLocalState();
  const promptsReadyPromise = ensureCompanyPromptsReady().catch(() => false);
  const [
    executionMode,
    selectedRunnerId,
    runnerEnabled,
    runnerName,
    identity,
    localState,
    promptsReady
  ] = await Promise.all([
    getStoredRemoteExecutionMode(),
    getStoredSelectedRemoteRunnerId(),
    getStoredRemoteRunnerEnabled(),
    getStoredRemoteRunnerName(),
    identityPromise,
    localStatePromise,
    promptsReadyPromise
  ]);
  const promptHash = promptsReady ? await getCompanyPromptHash().catch(() => '') : '';
  const alarmState = options?.alarmState && typeof options.alarmState === 'object'
    ? options.alarmState
    : await getAlarmSafe(ISKRA_REMOTE_RUNNER.alarmName).then((alarm) => ({
      alarmActive: !!alarm,
      nextRunAt: Number.isInteger(alarm?.scheduledTime) ? alarm.scheduledTime : null
    })).catch(() => ({
      alarmActive: false,
      nextRunAt: null
    }));
  const activeRemoteJobId = typeof localState?.activeRemoteJob?.remote?.remoteJobId === 'string'
    ? localState.activeRemoteJob.remote.remoteJobId
    : '';
  const queuedRemoteJobId = typeof localState?.queuedRemoteJob?.remote?.remoteJobId === 'string'
    ? localState.queuedRemoteJob.remote.remoteJobId
    : '';
  return {
    success: true,
    executionMode,
    selectedRunnerId,
    runnerEnabled,
    runnerName: runnerName || identity?.runnerName || '',
    runnerId: typeof identity?.runnerId === 'string' ? identity.runnerId : '',
    controllerId: typeof identity?.controllerId === 'string' ? identity.controllerId : '',
    promptsLoaded: promptsReady === true,
    promptHash,
    localBusy: localState?.localBusy === true,
    localQueueSize: Number.isInteger(localState?.localQueueSize) ? localState.localQueueSize : 0,
    activeRemoteJobId,
    queuedRemoteJobId,
    alarmActive: alarmState?.alarmActive === true,
    nextRunAt: Number.isInteger(alarmState?.nextRunAt) ? alarmState.nextRunAt : null
  };
}

async function updateRemoteExecutionConfig(patch = {}) {
  const nextStoragePatch = {};
  if (Object.prototype.hasOwnProperty.call(patch, 'executionMode') || Object.prototype.hasOwnProperty.call(patch, 'remote')) {
    const requestedMode = patch?.remote === true
      ? 'remote'
      : (patch?.remote === false ? 'local' : patch?.executionMode);
    nextStoragePatch[ISKRA_REMOTE_EXECUTION_MODE_STORAGE_KEY] = normalizeRemoteExecutionMode(requestedMode);
  }
  if (Object.prototype.hasOwnProperty.call(patch, 'selectedRunnerId') || Object.prototype.hasOwnProperty.call(patch, 'runnerId')) {
    nextStoragePatch[ISKRA_REMOTE_SELECTED_RUNNER_ID_STORAGE_KEY] = normalizeSelectedRemoteRunnerId(
      Object.prototype.hasOwnProperty.call(patch, 'selectedRunnerId')
        ? patch?.selectedRunnerId
        : patch?.runnerId
    );
  }
  if (Object.prototype.hasOwnProperty.call(patch, 'runnerEnabled') || Object.prototype.hasOwnProperty.call(patch, 'enabled')) {
    nextStoragePatch[ISKRA_REMOTE_RUNNER_ENABLED_STORAGE_KEY] = patch?.runnerEnabled === true || patch?.enabled === true;
  }
  if (Object.prototype.hasOwnProperty.call(patch, 'runnerName') || Object.prototype.hasOwnProperty.call(patch, 'name')) {
    nextStoragePatch[ISKRA_REMOTE_RUNNER_NAME_STORAGE_KEY] = normalizeRemoteRunnerName(
      Object.prototype.hasOwnProperty.call(patch, 'runnerName')
        ? patch?.runnerName
        : patch?.name
    );
  }

  if (Object.keys(nextStoragePatch).length > 0) {
    await chrome.storage.local.set(nextStoragePatch);
  }

  const alarmState = await syncRemoteRunnerAlarm().catch((error) => {
    console.warn('[remote-runner] sync alarm after config update failed:', error?.message || String(error));
    return { alarmActive: false, nextRunAt: null };
  });

  if (
    Object.prototype.hasOwnProperty.call(nextStoragePatch, ISKRA_REMOTE_RUNNER_ENABLED_STORAGE_KEY)
    || Object.prototype.hasOwnProperty.call(nextStoragePatch, ISKRA_REMOTE_RUNNER_NAME_STORAGE_KEY)
  ) {
    requestRemoteRunnerCycle('remote_config_updated');
  }

  return getRemoteExecutionConfigSnapshot({ alarmState });
}

function createRemoteExecutionId(prefix = 'remote') {
  return `${prefix}-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 10)}`;
}

function buildPromptChainHashKey(promptChain) {
  return JSON.stringify(sanitizePromptChainSnapshot(promptChain));
}

async function computePromptChainHash(promptChain) {
  const normalizedPromptChain = sanitizePromptChainSnapshot(promptChain);
  if (normalizedPromptChain.length === 0 || typeof WatchlistApiUtils?.sha256Hex !== 'function') {
    return '';
  }
  const digest = await WatchlistApiUtils.sha256Hex(JSON.stringify(normalizedPromptChain));
  return digest ? `sha256:${digest}` : '';
}

async function getCompanyPromptHash(forceReload = false) {
  const cacheKey = buildPromptChainHashKey(PROMPTS_COMPANY);
  if (!forceReload && cacheKey === promptsCompanyHashCacheKey && promptsCompanyHashCache) {
    return promptsCompanyHashCache;
  }
  const nextHash = await computePromptChainHash(PROMPTS_COMPANY);
  promptsCompanyHashCacheKey = cacheKey;
  promptsCompanyHashCache = nextHash;
  return nextHash;
}

function getIskraApiPath(kind = 'jobs') {
  if (kind === 'runners') {
    return typeof WatchlistApiUtils?.ISKRA_RUNNERS_PATH === 'string' && WatchlistApiUtils.ISKRA_RUNNERS_PATH.trim()
      ? WatchlistApiUtils.ISKRA_RUNNERS_PATH.trim()
      : '/api/v1/iskra/runners';
  }
  if (kind === 'runnerHeartbeat') {
    return typeof WatchlistApiUtils?.ISKRA_RUNNERS_HEARTBEAT_PATH === 'string' && WatchlistApiUtils.ISKRA_RUNNERS_HEARTBEAT_PATH.trim()
      ? WatchlistApiUtils.ISKRA_RUNNERS_HEARTBEAT_PATH.trim()
      : '/api/v1/iskra/runners/heartbeat';
  }
  if (kind === 'claim') {
    return typeof WatchlistApiUtils?.ISKRA_JOBS_CLAIM_PATH === 'string' && WatchlistApiUtils.ISKRA_JOBS_CLAIM_PATH.trim()
      ? WatchlistApiUtils.ISKRA_JOBS_CLAIM_PATH.trim()
      : '/api/v1/iskra/jobs/claim';
  }
  return typeof WatchlistApiUtils?.ISKRA_JOBS_PATH === 'string' && WatchlistApiUtils.ISKRA_JOBS_PATH.trim()
    ? WatchlistApiUtils.ISKRA_JOBS_PATH.trim()
    : '/api/v1/iskra/jobs';
}

function buildRemoteRunnerStatusApiPath(runnerId) {
  const safeRunnerId = typeof runnerId === 'string' ? runnerId.trim() : '';
  return `${getIskraApiPath('runners')}/${encodeURIComponent(safeRunnerId)}/status`;
}

function buildRemoteJobApiPath(jobId, suffix = '') {
  const safeJobId = typeof jobId === 'string' ? jobId.trim() : '';
  const safeSuffix = typeof suffix === 'string' ? suffix.trim() : '';
  return `${getIskraApiPath('jobs')}/${encodeURIComponent(safeJobId)}${safeSuffix ? `/${safeSuffix}` : ''}`;
}

function normalizeRemoteApiErrorText(error, fallback = 'remote_api_failed') {
  const text = typeof error?.message === 'string'
    ? error.message
    : String(error || '');
  const normalized = text.trim();
  return normalized || fallback;
}

async function performSignedIskraApiRequest(options = {}) {
  const config = await resolveWatchlistDispatchConfiguration(options?.forceConfigReload === true);
  if (!config?.ok) {
    return {
      success: false,
      status: null,
      error: config?.reason || 'watchlist_dispatch_config_unavailable',
      payload: null,
      intakeUrl: config?.intakeUrl || ''
    };
  }
  if (typeof WatchlistApiUtils?.buildSignedJsonRequest !== 'function') {
    return {
      success: false,
      status: null,
      error: 'watchlist_request_signing_unavailable',
      payload: null,
      intakeUrl: config.intakeUrl
    };
  }

  const method = typeof options?.method === 'string' && options.method.trim()
    ? options.method.trim().toUpperCase()
    : 'GET';
  const retryCount = Number.isInteger(options?.retryCount)
    ? Math.max(0, Math.min(4, options.retryCount))
    : ISKRA_REMOTE_RUNNER.retryCount;
  const timeoutMs = Number.isInteger(options?.timeoutMs)
    ? Math.max(1000, options.timeoutMs)
    : ISKRA_REMOTE_RUNNER.requestTimeoutMs;
  const backoffMs = Number.isInteger(options?.backoffMs)
    ? Math.max(0, options.backoffMs)
    : ISKRA_REMOTE_RUNNER.backoffMs;

  let lastStatus = null;
  let lastError = 'remote_api_failed';
  let lastPayload = null;
  let lastUrl = '';

  for (let attempt = 0; attempt <= retryCount; attempt += 1) {
    try {
      const signedRequest = await WatchlistApiUtils.buildSignedJsonRequest({
        intakeUrl: config.intakeUrl,
        keyId: config.keyId,
        secret: config.secret,
        method,
        path: options?.path || '/',
        payload: options?.payload && typeof options.payload === 'object' ? options.payload : {},
        query: options?.query && typeof options.query === 'object' ? options.query : null
      });
      lastUrl = signedRequest.url || '';
      const controller = new AbortController();
      let timeoutId = null;
      try {
        const response = await Promise.race([
          fetch(signedRequest.url, {
            method: signedRequest.method,
            headers: signedRequest.headers,
            ...(signedRequest.method === 'GET' ? {} : { body: signedRequest.body }),
            signal: controller.signal
          }),
          new Promise((_, reject) => {
            timeoutId = setTimeout(() => {
              try {
                controller.abort();
              } catch {
                // Ignore abort exceptions in timeout branch.
              }
              reject(new Error(`remote_api_timeout_${timeoutMs}`));
            }, timeoutMs);
          })
        ]);

        if (timeoutId) {
          clearTimeout(timeoutId);
          timeoutId = null;
        }

        const responseText = await response.text().catch(() => '');
        let responsePayload = {};
        try {
          responsePayload = responseText ? JSON.parse(responseText) : {};
        } catch {
          responsePayload = {};
        }
        lastPayload = responsePayload;

        if (!response.ok) {
          lastStatus = response.status;
          lastError = (
            (typeof responsePayload?.detail === 'string' && responsePayload.detail.trim())
            || (typeof responsePayload?.reason === 'string' && responsePayload.reason.trim())
            || (typeof responseText === 'string' && responseText.trim())
            || `http_${response.status}`
          );
          if (response.status === 401 || response.status === 403 || response.status === 404 || response.status === 409 || response.status === 422) {
            break;
          }
        } else {
          return {
            success: true,
            status: response.status,
            error: '',
            payload: responsePayload && typeof responsePayload === 'object' ? responsePayload : {},
            intakeUrl: lastUrl
          };
        }
      } finally {
        if (timeoutId) clearTimeout(timeoutId);
      }
    } catch (error) {
      lastError = normalizeRemoteApiErrorText(error, 'remote_api_failed');
    }

    if (attempt < retryCount && backoffMs > 0) {
      await sleep(backoffMs * (attempt + 1));
    }
  }

  return {
    success: false,
    status: lastStatus,
    error: lastError,
    payload: lastPayload,
    intakeUrl: lastUrl
  };
}

