async function upsertProcess(runId, patch = {}) {
  if (!runId) return null;
  await ensureProcessRegistryReady();
  const patchData = (patch && typeof patch === 'object')
    ? { ...patch }
    : {};

  const existing = processRegistry.get(runId) || {
    id: runId,
    title: 'Bez tytulu',
    analysisType: 'company',
    lifecycleStatus: 'starting',
    status: 'starting',
    phase: 'slot_reserved',
    actionRequired: 'none',
    currentPrompt: 0,
    totalPrompts: 0,
    startedAt: Date.now(),
    timestamp: Date.now(),
    needsAction: false,
    version: 0,
    messages: []
  };

  const existingStatus = normalizeProcessLifecycleStatus(existing.lifecycleStatus || existing.status, 'starting');
  if (existingStatus === 'stopped' && !patchData.forceStatusOverride) {
    const requestedStatus = normalizeProcessLifecycleStatus(
      patchData.lifecycleStatus || patchData.status,
      ''
    );
    if (!requestedStatus || requestedStatus !== 'stopped') {
      patchData.lifecycleStatus = 'stopped';
      patchData.status = 'stopped';
    }
    patchData.actionRequired = 'none';
    patchData.needsAction = false;
    if (!patchData.reason && typeof existing.reason === 'string') {
      patchData.reason = existing.reason;
    }
    if (!patchData.statusCode && typeof existing.statusCode === 'string') {
      patchData.statusCode = existing.statusCode;
    }
  }
  delete patchData.forceStatusOverride;

  if (!Number.isInteger(patchData.attempt) && Number.isInteger(patchData?.autoRecovery?.attempt)) {
    patchData.attempt = patchData.autoRecovery.attempt;
  }
  if (!Number.isInteger(patchData.retryCount) && Number.isInteger(patchData.attempt)) {
    patchData.retryCount = patchData.attempt;
  }

  const nowTs = Number.isInteger(patchData.timestamp) ? patchData.timestamp : Date.now();
  const nextLifecycleStatus = normalizeProcessLifecycleStatus(
    patchData.lifecycleStatus || patchData.status || existing.lifecycleStatus || existing.status,
    'running'
  );
  const previousPhase = normalizeProcessPhase(
    existing.phase,
    typeof ProcessContractUtils.defaultPhaseForLifecycle === 'function'
      ? ProcessContractUtils.defaultPhaseForLifecycle(existingStatus)
      : ''
  );
  const nextPhase = normalizeProcessPhase(
    patchData.phase,
    previousPhase || (
      typeof ProcessContractUtils.defaultPhaseForLifecycle === 'function'
        ? ProcessContractUtils.defaultPhaseForLifecycle(nextLifecycleStatus)
        : ''
    )
  );
  const nextActionRequired = normalizeProcessActionRequired(
    patchData.actionRequired,
    deriveProcessActionRequired({
      ...existing,
      ...patchData,
      lifecycleStatus: nextLifecycleStatus,
      phase: nextPhase
    })
  );

  const next = normalizeProcessRecord({
    ...existing,
    ...patchData,
    id: runId,
    lifecycleStatus: nextLifecycleStatus,
    status: nextLifecycleStatus,
    phase: nextPhase,
    actionRequired: nextActionRequired,
    startedAt: existing.startedAt || Date.now(),
    phaseStartedAt: nextPhase && nextPhase !== previousPhase
      ? nowTs
      : (
        Number.isInteger(patchData.phaseStartedAt) && patchData.phaseStartedAt > 0
          ? patchData.phaseStartedAt
          : (
            Number.isInteger(existing.phaseStartedAt) && existing.phaseStartedAt > 0
              ? existing.phaseStartedAt
              : nowTs
          )
      ),
    lastActivityAt: Number.isInteger(patchData.lastActivityAt) && patchData.lastActivityAt > 0
      ? patchData.lastActivityAt
      : nowTs,
    timestamp: nowTs,
    version: Math.max(
      Number.isInteger(existing.version) ? existing.version : 0,
      Number.isInteger(patchData.version) ? patchData.version : 0
    ) + 1
  });

  if (!next) return null;
  mergeProcessConversationUrls(existing, next);
  processRegistryVersion = Math.max(processRegistryVersion, Number.isInteger(next.version) ? next.version : 0);
  const problemEntry = buildProcessProblemLogEntry(runId, next);
  const knownSignature = problemLogLastSignatureByRunId.get(runId) || '';
  const signatureChanged = !!(problemEntry?.signature && problemEntry.signature !== knownSignature);
  const heartbeatDue = !!(problemEntry?.signature && !signatureChanged && shouldEmitProcessProblemHeartbeat(runId, next));
  if (problemEntry && heartbeatDue && !signatureChanged) {
    problemEntry.heartbeat = true;
  }
  if (problemEntry?.signature && (signatureChanged || heartbeatDue)) {
    const emittedEntry = await appendProblemLog(problemEntry);
    if (emittedEntry) {
      processLogLastEmitTsByRunId.set(runId, Date.now());
    }
    problemLogLastSignatureByRunId.set(runId, problemEntry.signature);
  } else if (!problemEntry) {
    problemLogLastSignatureByRunId.delete(runId);
    processLogLastEmitTsByRunId.delete(runId);
    processStaleWarnLastEmitTsByRunId.delete(runId);
  } else if (isClosedProcessStatus(next.status)) {
    processLogLastEmitTsByRunId.delete(runId);
    processStaleWarnLastEmitTsByRunId.delete(runId);
  }
  processRegistry.set(runId, next);
  logger.event({
    level: isClosedProcessStatus(next.lifecycleStatus || next.status)
      ? (normalizeProcessLifecycleStatus(next.lifecycleStatus || next.status) === 'failed' ? 'warn' : 'info')
      : 'info',
    area: 'process',
    event: 'upsert',
    runId,
    phase: next.phase || '',
    statusCode: next.statusCode || '',
    meta: {
      lifecycleStatus: next.lifecycleStatus || next.status,
      actionRequired: next.actionRequired || 'none',
      version: next.version,
      currentPrompt: next.currentPrompt,
      totalPrompts: next.totalPrompts
    }
  });
  scheduleCompletedProcessPersistenceRetry(next, {
    origin: 'process_upsert'
  });
  if (next.queueManaged === true || existing?.queueManaged === true || analysisQueueState?.waitingJobs?.length || analysisQueueState?.activeJobs?.length) {
    requestAnalysisQueueReconcile('process_upsert');
  }
  void handleManualPdfBatchProcessUpdate(existing, next).catch((error) => {
    console.warn('[manual-pdf] batch progress update failed:', error?.message || String(error));
  });
  logProcessTransition(runId, next, patchData);
  const flushImmediately = shouldFlushProcessUpdateImmediately(existing, next, patchData);
  await scheduleProcessRegistryFlush('process_upsert', {
    immediate: flushImmediately
  });
  return next;
}

function resolveProcessConversationUrlFromMessage(message, sender) {
  const candidates = [
    typeof message?.chatUrl === 'string' ? message.chatUrl : '',
    typeof message?.conversationUrl === 'string' ? message.conversationUrl : '',
    getTabEffectiveUrl(sender?.tab)
  ];
  for (const candidate of candidates) {
    const normalized = normalizeChatConversationUrl(candidate);
    if (normalized) return normalized;
  }
  return '';
}

async function findProcessIdByTabId(tabId) {
  if (!Number.isInteger(tabId)) return null;
  await ensureProcessRegistryReady();

  for (const process of processRegistry.values()) {
    if (process.tabId === tabId && !isClosedProcessStatus(process.status)) {
      return process.id;
    }
  }
  for (const process of processRegistry.values()) {
    if (process.tabId === tabId) {
      return process.id;
    }
  }
  return null;
}

async function resolveProcessId(message, sender) {
  if (typeof message?.runId === 'string' && message.runId.trim()) {
    return message.runId;
  }
  const messageTabId = Number.isInteger(message?.tabId) ? message.tabId : null;
  const senderTabId = Number.isInteger(sender?.tab?.id) ? sender.tab.id : null;
  const tabId = messageTabId ?? senderTabId;
  return findProcessIdByTabId(tabId);
}

async function hasActiveProcessForTab(tabId) {
  if (!Number.isInteger(tabId)) return false;
  const process = await getActiveProcessForTab(tabId);
  return !!process;
}

async function getActiveProcessForTab(tabId) {
  if (!Number.isInteger(tabId)) return null;
  await ensureProcessRegistryReady();
  let latest = null;
  let latestTs = -1;
  for (const process of processRegistry.values()) {
    if (!process || process.tabId !== tabId) continue;
    if (isClosedProcessStatus(process.status)) continue;
    const ts = Number.isInteger(process.timestamp)
      ? process.timestamp
      : (Number.isInteger(process.startedAt) ? process.startedAt : 0);
    if (ts >= latestTs) {
      latestTs = ts;
      latest = process;
    }
  }
  return latest;
}

function removeWindowSafe(windowId) {
  return new Promise((resolve) => {
    if (!Number.isInteger(windowId)) {
      resolve(false);
      return;
    }
    try {
      chrome.windows.remove(windowId, () => {
        if (chrome.runtime.lastError) {
          resolve(false);
          return;
        }
        resolve(true);
      });
    } catch (error) {
      resolve(false);
    }
  });
}

function removeTabSafe(tabId) {
  return new Promise((resolve) => {
    if (!Number.isInteger(tabId)) {
      resolve(false);
      return;
    }
    try {
      chrome.tabs.remove(tabId, () => {
        if (chrome.runtime.lastError) {
          resolve(false);
          return;
        }
        resolve(true);
      });
    } catch (error) {
      resolve(false);
    }
  });
}

function getTabGroupIdNone() {
  return Number.isInteger(chrome?.tabGroups?.TAB_GROUP_ID_NONE)
    ? chrome.tabGroups.TAB_GROUP_ID_NONE
    : -1;
}

async function ungroupTabsById(tabIds, options = {}) {
  const requestedTabIds = Array.from(
    new Set(
      (Array.isArray(tabIds) ? tabIds : [tabIds])
        .map((value) => (Number.isInteger(value) ? value : null))
        .filter((value) => value !== null)
    )
  );

  const baseResult = {
    ok: false,
    reason: 'unknown',
    requested: requestedTabIds.length,
    groupedCount: 0,
    ungroupedCount: 0,
    skippedCount: 0,
    error: '',
    requestedTabIds,
    groupedTabIds: [],
    origin: typeof options?.origin === 'string' ? options.origin : ''
  };

  if (requestedTabIds.length === 0) {
    return {
      ...baseResult,
      reason: 'no_tab_ids',
      ok: true,
      skippedCount: 0
    };
  }

  if (!chrome?.tabs?.ungroup) {
    return {
      ...baseResult,
      reason: 'ungroup_api_unavailable',
      error: 'chrome.tabs.ungroup is not available'
    };
  }

  const noneGroupId = getTabGroupIdNone();
  const tabLookups = await Promise.all(requestedTabIds.map((tabId) => getTabByIdSafe(tabId)));
  const groupedTabIds = tabLookups
    .map((tab) => (Number.isInteger(tab?.id) && Number.isInteger(tab?.groupId) && tab.groupId !== noneGroupId ? tab.id : null))
    .filter((tabId) => Number.isInteger(tabId));
  const uniqueGroupedTabIds = Array.from(new Set(groupedTabIds));

  if (uniqueGroupedTabIds.length === 0) {
    return {
      ...baseResult,
      reason: 'already_ungrouped',
      ok: true,
      groupedCount: 0,
      ungroupedCount: 0,
      skippedCount: requestedTabIds.length,
      groupedTabIds: []
    };
  }

  const ungroupResult = await new Promise((resolve) => {
    try {
      chrome.tabs.ungroup(uniqueGroupedTabIds, () => {
        if (chrome.runtime.lastError) {
          resolve({
            ok: false,
            reason: 'ungroup_runtime_error',
            error: chrome.runtime.lastError.message || 'ungroup_runtime_error'
          });
          return;
        }
        resolve({
          ok: true,
          reason: 'ungrouped',
          error: ''
        });
      });
    } catch (error) {
      resolve({
        ok: false,
        reason: 'ungroup_exception',
        error: error?.message || String(error)
      });
    }
  });

  return {
    ...baseResult,
    ...ungroupResult,
    groupedCount: uniqueGroupedTabIds.length,
    ungroupedCount: ungroupResult.ok ? uniqueGroupedTabIds.length : 0,
    skippedCount: requestedTabIds.length - uniqueGroupedTabIds.length,
    groupedTabIds: uniqueGroupedTabIds
  };
}

async function ungroupChatGptTabsInWindow(windowId, options = {}) {
  const origin = typeof options?.origin === 'string' ? options.origin : '';
  if (!Number.isInteger(windowId)) {
    return {
      ok: false,
      reason: 'invalid_window_id',
      windowId: null,
      requested: 0,
      groupedCount: 0,
      ungroupedCount: 0,
      skippedCount: 0,
      error: '',
      origin
    };
  }

  const queryResult = await queryTabsInWindowSafe(windowId);
  if (!queryResult.ok) {
    return {
      ok: false,
      reason: queryResult.reason || 'query_tabs_failed',
      windowId,
      requested: 0,
      groupedCount: 0,
      ungroupedCount: 0,
      skippedCount: 0,
      error: queryResult.reason || '',
      origin
    };
  }

  const tabs = Array.isArray(queryResult.tabs) ? queryResult.tabs : [];
  const chatTabIds = tabs
    .filter((tab) => isChatGptUrl(getTabEffectiveUrl(tab)))
    .map((tab) => (Number.isInteger(tab?.id) ? tab.id : null))
    .filter((tabId) => Number.isInteger(tabId));

  if (chatTabIds.length === 0) {
    return {
      ok: true,
      reason: 'no_chat_tabs',
      windowId,
      requested: 0,
      groupedCount: 0,
      ungroupedCount: 0,
      skippedCount: 0,
      error: '',
      origin
    };
  }

  const ungroupResult = await ungroupTabsById(chatTabIds, { origin });
  return {
    ...ungroupResult,
    windowId,
    requested: chatTabIds.length,
    reason: ungroupResult.reason || 'ungroup_result_missing_reason',
    origin
  };
}

function matchesWindowScope(process, windowId) {
  if (!Number.isInteger(windowId)) return true;
  if (!process || typeof process !== 'object') return false;
  return (
    process.windowId === windowId ||
    process.invocationWindowId === windowId ||
    process.sourceWindowId === windowId
  );
}

function requestProcessForceStopOnTab(tabId, payload = {}, timeoutMs = 1200) {
  return new Promise((resolve) => {
    if (!Number.isInteger(tabId)) {
      resolve({
        sent: false,
        acknowledged: false,
        reason: 'invalid_tab_id'
      });
      return;
    }

    let settled = false;
    const finish = (result) => {
      if (settled) return;
      settled = true;
      resolve(result);
    };

    const timer = setTimeout(() => {
      finish({
        sent: false,
        acknowledged: false,
        reason: 'timeout'
      });
    }, Math.max(200, timeoutMs));

    try {
      const forceStopMessage = {
        type: 'PROCESS_FORCE_STOP',
        reason: typeof payload.reason === 'string' ? payload.reason : 'manual_stop',
        origin: typeof payload.origin === 'string' ? payload.origin : 'background'
      };
      if (typeof payload.runId === 'string' && payload.runId.trim()) {
        forceStopMessage.runId = payload.runId.trim();
      }

      chrome.tabs.sendMessage(
        tabId,
        forceStopMessage,
        (response) => {
          clearTimeout(timer);
          if (chrome.runtime.lastError) {
            finish({
              sent: false,
              acknowledged: false,
              reason: chrome.runtime.lastError.message || 'runtime_error'
            });
            return;
          }

          const acknowledged = !!(
            response?.acknowledged ||
            response?.success ||
            response?.stopped
          );

          finish({
            sent: true,
            acknowledged,
            reason: acknowledged ? 'ack' : 'no_ack'
          });
        }
      );
    } catch (error) {
      clearTimeout(timer);
      finish({
        sent: false,
        acknowledged: false,
        reason: error?.message || String(error)
      });
    }
  });
}

function extractResponseIdFromCopyTrace(copyTrace, expectedRunId = '') {
  if (typeof copyTrace !== 'string' || !copyTrace.trim()) return '';
  const trimmed = copyTrace.trim();
  const separator = trimmed.lastIndexOf('/');
  if (separator < 0 || separator >= trimmed.length - 1) return '';
  const runPart = trimmed.slice(0, separator).trim();
  const responsePart = trimmed.slice(separator + 1).trim();
  if (!responsePart || responsePart === 'no-response') return '';
  if (typeof expectedRunId === 'string' && expectedRunId.trim() && runPart && runPart !== expectedRunId.trim()) {
    return '';
  }
  return responsePart;
}

function collectKnownProcessResponseIds(process, expectedRunId = '') {
  const ids = new Set();
  if (!process || typeof process !== 'object') return ids;

  const runId = typeof expectedRunId === 'string' ? expectedRunId.trim() : '';
  const traces = [];

  if (typeof process?.completedResponseSaveTrace === 'string' && process.completedResponseSaveTrace.trim()) {
    traces.push(process.completedResponseSaveTrace.trim());
  }
  if (typeof process?.persistenceStatus?.copyTrace === 'string' && process.persistenceStatus.copyTrace.trim()) {
    traces.push(process.persistenceStatus.copyTrace.trim());
  }
  if (typeof process?.restartReplay?.copyTrace === 'string' && process.restartReplay.copyTrace.trim()) {
    traces.push(process.restartReplay.copyTrace.trim());
  }

  for (const trace of traces) {
    const responseId = extractResponseIdFromCopyTrace(trace, runId);
    if (responseId) ids.add(responseId);
  }

  const directIds = [
    process?.finalStagePersistence?.responseId,
    process?.restartReplay?.responseId
  ];
  for (const candidate of directIds) {
    if (typeof candidate !== 'string') continue;
    const normalized = candidate.trim();
    if (normalized) ids.add(normalized);
  }

  return ids;
}

function buildProcessCopyTrace(process, fallbackRunId = '') {
  if (typeof process?.completedResponseSaveTrace === 'string' && process.completedResponseSaveTrace.trim()) {
    return process.completedResponseSaveTrace.trim();
  }
  if (typeof process?.persistenceStatus?.copyTrace === 'string' && process.persistenceStatus.copyTrace.trim()) {
    return process.persistenceStatus.copyTrace.trim();
  }
  const runId = typeof process?.id === 'string' && process.id.trim()
    ? process.id.trim()
    : (typeof fallbackRunId === 'string' && fallbackRunId.trim() ? fallbackRunId.trim() : '');
  const knownResponseIds = Array.from(collectKnownProcessResponseIds(process, runId));
  return buildCopyTrace(runId, knownResponseIds[0] || '');
}

function createDeliveredDispatchSnapshot(previousDispatch = {}, responseId = '', details = {}) {
  const prev = previousDispatch && typeof previousDispatch === 'object'
    ? previousDispatch
    : {};
  const sent = Number.isInteger(prev.sent) ? Math.max(prev.sent, 1) : 1;
  const accepted = Number.isInteger(prev.accepted)
    ? Math.max(prev.accepted, sent, 1)
    : Math.max(sent, 1);
  const failed = Number.isInteger(prev.failed) ? Math.max(0, prev.failed) : 0;
  const normalizedResponseId = typeof responseId === 'string' ? responseId.trim() : '';
  return {
    ...prev,
    queued: true,
    queueSize: 0,
    queueSkipped: false,
    queueSkipReason: '',
    flushSkipped: false,
    flushSkipReason: '',
    flushFollowUpScheduled: false,
    accepted,
    sent,
    failed,
    deferred: 0,
    remaining: 0,
    verifyEventId: normalizeWatchlistEventId(details?.eventId) || (typeof prev.verifyEventId === 'string' ? prev.verifyEventId : ''),
    verifyState: 'verified',
    verifyReason: 'verified',
    firstFailure: '',
    failureStage: '',
    failureReason: '',
    failureStatus: null,
    failureRequestId: typeof details?.requestId === 'string' ? details.requestId.trim() : '',
    failureIntakeUrl: typeof details?.intakeUrl === 'string' ? details.intakeUrl.trim() : '',
    state: 'dispatch_confirmed',
    responseId: normalizedResponseId || (typeof prev.responseId === 'string' ? prev.responseId : '')
  };
}

async function updateProcessDispatchAfterSendSuccess(runId = '', responseId = '', details = {}) {
  const normalizedRunId = typeof runId === 'string' ? runId.trim() : '';
  if (!normalizedRunId) return false;

  const normalizedResponseId = typeof responseId === 'string' ? responseId.trim() : '';
  const process = processRegistry.get(normalizedRunId) || null;
  if (!process || typeof process !== 'object') return false;

  if (normalizedResponseId) {
    const knownResponseIds = collectKnownProcessResponseIds(process, normalizedRunId);
    if (knownResponseIds.size > 0 && !knownResponseIds.has(normalizedResponseId)) {
      return false;
    }
  }

  const now = Date.now();
  const previousPersistenceStatus = process?.persistenceStatus && typeof process.persistenceStatus === 'object'
    ? process.persistenceStatus
    : {};
  const previousDispatch = previousPersistenceStatus?.dispatch && typeof previousPersistenceStatus.dispatch === 'object'
    ? previousPersistenceStatus.dispatch
    : (process?.completedResponseDispatch && typeof process.completedResponseDispatch === 'object'
      ? process.completedResponseDispatch
      : {});

  const nextDispatch = createDeliveredDispatchSnapshot(previousDispatch, normalizedResponseId, details);
  const dispatchSummary = formatDispatchUiSummary(nextDispatch);
  const previousLog = Array.isArray(previousPersistenceStatus?.dispatchProcessLog)
    ? previousPersistenceStatus.dispatchProcessLog
    : [];
  const deliveryLogEntry = [
    'dispatch_delivery',
    'ok',
    `responseId=${normalizedResponseId || 'n/a'}`,
    `status=${Number.isInteger(details?.status) ? details.status : 'n/a'}`,
    `eventId=${typeof details?.eventId === 'string' && details.eventId.trim() ? details.eventId.trim() : 'n/a'}`,
    `requestId=${typeof details?.requestId === 'string' && details.requestId.trim() ? details.requestId.trim() : 'n/a'}`
  ].join('|');
  const nextLog = [...previousLog.slice(-15), deliveryLogEntry];

  const patch = {
    lifecycleStatus: 'completed',
    status: 'completed',
    phase: 'verify_remote',
    actionRequired: 'none',
    statusCode: 'dispatch.confirmed',
    completedResponseDispatch: nextDispatch,
    completedResponseDispatchSummary: dispatchSummary,
    completedResponseDispatchProcessLog: nextLog.slice(-16),
    persistenceStatus: {
      ...previousPersistenceStatus,
      hasResponse: true,
      saveOk: true,
      saveError: '',
      dispatch: nextDispatch,
      dispatchSummary,
      dispatchProcessLog: nextLog.slice(-16),
      updatedAt: now
    },
    timestamp: now
  };

  const previousFinalStagePersistence = process?.finalStagePersistence && typeof process.finalStagePersistence === 'object'
    ? process.finalStagePersistence
    : null;
  if (previousFinalStagePersistence && previousFinalStagePersistence.success === true) {
    const previousFinalSent = Number.isInteger(previousFinalStagePersistence.sent)
      ? previousFinalStagePersistence.sent
      : 0;
    const previousFinalFailed = Number.isInteger(previousFinalStagePersistence.failed)
      ? previousFinalStagePersistence.failed
      : 0;
    patch.finalStagePersistence = {
      ...previousFinalStagePersistence,
      sent: Math.max(previousFinalSent, nextDispatch.sent || 0),
      failed: Math.max(previousFinalFailed, nextDispatch.failed || 0),
      deferred: 0,
      remaining: 0,
      pending: 0,
      queueSkipped: false,
      queueSkipReason: '',
      flushSkipped: false,
      flushSkipReason: '',
      failureStage: '',
      failureReason: '',
      failureStatus: null,
      failureRequestId: '',
      failureIntakeUrl: '',
      state: 'dispatch_confirmed',
      dispatchSummary,
      updatedAt: now
    };
  }

  await upsertProcess(normalizedRunId, patch);
  clearCompletedProcessPersistenceRetry(normalizedRunId);
  await closeCompletedProcessAfterDispatchConfirmed(normalizedRunId, {
    origin: 'verify_dispatch_success'
  }).catch(() => false);
  return true;
}

function getProcessPersistenceDispatchSnapshot(process) {
  const persistenceStatus = process?.persistenceStatus && typeof process.persistenceStatus === 'object'
    ? process.persistenceStatus
    : null;
  const finalStagePersistence = process?.finalStagePersistence && typeof process.finalStagePersistence === 'object'
    ? process.finalStagePersistence
    : null;
  return persistenceStatus?.dispatch && typeof persistenceStatus.dispatch === 'object'
    ? persistenceStatus.dispatch
    : (process?.completedResponseDispatch && typeof process.completedResponseDispatch === 'object'
      ? process.completedResponseDispatch
      : (finalStagePersistence && typeof finalStagePersistence === 'object' ? finalStagePersistence : null));
}

function getProcessQueueDeliveryState(process) {
  const persistenceStatus = process?.persistenceStatus && typeof process.persistenceStatus === 'object'
    ? process.persistenceStatus
    : null;
  const finalStagePersistence = process?.finalStagePersistence && typeof process.finalStagePersistence === 'object'
    ? process.finalStagePersistence
    : null;
  const dispatch = getProcessPersistenceDispatchSnapshot(process);

  const saveOk = typeof persistenceStatus?.saveOk === 'boolean'
    ? persistenceStatus.saveOk
    : (typeof process?.completedResponseSaved === 'boolean'
      ? process.completedResponseSaved
      : (typeof finalStagePersistence?.success === 'boolean' ? finalStagePersistence.success : null));
  const sent = Number.isInteger(dispatch?.sent) ? dispatch.sent : 0;
  const failed = Number.isInteger(dispatch?.failed) ? dispatch.failed : 0;
  const deferred = Number.isInteger(dispatch?.deferred) ? dispatch.deferred : 0;
  const remaining = Number.isInteger(dispatch?.remaining) ? dispatch.remaining : 0;
  const pending = Number.isInteger(dispatch?.pending) ? dispatch.pending : (deferred + remaining);
  const state = typeof dispatch?.state === 'string' && dispatch.state.trim()
    ? dispatch.state.trim()
    : '';
  const queueSkipped = dispatch?.queueSkipped === true;
  const flushSkipped = dispatch?.flushSkipped === true;
  const confirmed = state === 'dispatch_confirmed'
    || (
      saveOk === true
      && sent > 0
      && failed === 0
      && pending === 0
      && !queueSkipped
      && !flushSkipped
    );

  return {
    saveOk,
    sent,
    failed,
    deferred,
    remaining,
    pending,
    state,
    queueSkipped,
    flushSkipped,
    confirmed
  };
}

function resolveAnalysisQueueReleaseDecision(job, process, nowTs = Date.now()) {
  if (!job || typeof job !== 'object') {
    return { action: 'release', closeWindow: false, reason: 'invalid_job' };
  }
  if (!process || typeof process !== 'object') {
    return { action: 'release', closeWindow: false, reason: 'missing_process' };
  }

  const status = normalizeProcessLifecycleStatus(process.lifecycleStatus || process.status, 'running');
  if (status === 'finalizing' || status === 'completed') {
    if (!hasProcessReachedFinalStage(process)) {
      return {
        action: 'keep',
        queueState: 'awaiting_final_stage'
      };
    }
    const delivery = getProcessQueueDeliveryState(process);
    if (delivery.confirmed === true) {
      return {
        action: 'release',
        closeWindow: true,
        reason: 'dispatch_confirmed'
      };
    }
    if (delivery.saveOk !== true) {
      return {
        action: 'release',
        closeWindow: true,
        reason: 'local_save_failed'
      };
    }
    if (delivery.queueSkipped === true || delivery.flushSkipped === true) {
      return {
        action: 'release',
        closeWindow: true,
        reason: 'dispatch_skipped'
      };
    }
    return {
      action: 'release',
      closeWindow: true,
      reason: delivery.confirmed === true ? 'dispatch_confirmed' : 'dispatch_pending'
    };
  }

  if (isClosedProcessStatus(status)) {
    return { action: 'release', closeWindow: false, reason: status || 'closed' };
  }

  return {
    action: 'keep',
    queueState: status === 'queued' ? 'active' : 'running'
  };
}

async function markTrackedProcessStoppedForClosedTab(tabId, removeInfo = null) {
  if (!Number.isInteger(tabId)) return false;
  const process = await getActiveProcessForTab(tabId);
  if (!process || isClosedProcessStatus(process.status)) return false;

  const now = Date.now();
  const status = normalizeProcessStatus(process.status);
  const completedResponseText = extractAssistantTextFromProcess(process);
  const currentPrompt = Number.isInteger(process?.currentPrompt) ? process.currentPrompt : 0;
  const totalPrompts = Number.isInteger(process?.totalPrompts) ? process.totalPrompts : 0;
  const statusTextLower = typeof process?.statusText === 'string' ? process.statusText.toLowerCase() : '';
  const likelyFinalStage = completedResponseText.length > 0 && (
    (totalPrompts > 0 && currentPrompt >= totalPrompts)
    || statusTextLower.includes('trwa zapis do bazy')
    || statusTextLower.includes('zakonczono')
    || Number.isInteger(process?.completedResponseCapturedAt)
    || process?.completedResponseSaved === true
  );

  if (likelyFinalStage) {
    const persistResult = await ensureCompletedProcessResponsePersisted(process, {
      force: true,
      origin: 'tab_closed_completed_response'
    }).catch((error) => ({
      attempted: false,
      success: false,
      reason: error?.message || String(error)
    }));
    const persistenceSummary = summarizeFinalStagePersistence(persistResult);
    const refreshedProcess = processRegistry.get(process.id) || process;
    const delivery = getProcessQueueDeliveryState(refreshedProcess);
    await upsertProcess(process.id, {
      lifecycleStatus: delivery.confirmed === true ? 'completed' : 'finalizing',
      status: delivery.confirmed === true ? 'completed' : 'finalizing',
      phase: delivery.confirmed === true ? 'verify_remote' : 'dispatch_remote',
      actionRequired: 'none',
      statusCode: delivery.confirmed === true ? 'dispatch.confirmed' : 'dispatch.verify_pending',
      reason: delivery.confirmed === true
        ? 'tab_closed_after_completion'
        : 'tab_closed_after_completion_pending_dispatch',
      needsAction: false,
      autoRecovery: null,
      finishedAt: now,
      timestamp: now,
      ...(persistenceSummary
        ? {
            finalStagePersistence: {
              ...persistenceSummary,
              origin: 'tab_closed_completed_response',
              updatedAt: now
            }
          }
        : {})
    });
    if (delivery.confirmed === true) {
      clearCompletedProcessPersistenceRetry(process.id);
      await closeCompletedProcessAfterDispatchConfirmed(process.id, {
        origin: 'tab_closed_completed_response'
      }).catch(() => false);
    } else {
      scheduleCompletedProcessPersistenceRetry(process.id, {
        origin: 'tab_closed_completed_response',
        force: true,
        delayMs: 0
      });
    }
    return true;
  }

  const statusText = status === 'queued'
    ? 'Karta zamknieta przed startem procesu'
    : 'Karta zamknieta podczas wykonywania procesu';
  const reason = status === 'queued' ? 'tab_closed_before_start' : 'tab_closed_during_execution';

  await upsertProcess(process.id, {
    status: 'stopped',
    statusText,
    reason,
    needsAction: false,
    autoRecovery: null,
    finishedAt: now,
    timestamp: now
  });
  return true;
}

async function buildStaleQueueReleasePatch(process, now = Date.now()) {
  if (!process || typeof process !== 'object') return null;
  return {
    status: 'stopped',
    statusText: 'Brak aktywnej lokalnej karty procesu - slot zwolniony',
    reason: 'local_context_missing',
    needsAction: false,
    autoRecovery: null,
    finishedAt: now,
    timestamp: now
  };
}

async function closeProcessWindowAfterQueueSuccess(process) {
  if (!process || typeof process !== 'object') return false;
  const processWindowId = Number.isInteger(process.windowId) ? process.windowId : null;
  const processTabId = Number.isInteger(process.tabId) ? process.tabId : null;
  let tabClosed = false;

  if (processTabId !== null) {
    tabClosed = await removeTabSafe(processTabId);
  }

  if (!tabClosed && processWindowId !== null) {
    const tabsInWindow = await queryTabsInWindowSafe(processWindowId);
    const validTabs = Array.isArray(tabsInWindow?.tabs)
      ? tabsInWindow.tabs.filter((tab) => Number.isInteger(tab?.id))
      : [];
    const hasOnlyProcessTab = validTabs.length === 1
      && processTabId !== null
      && validTabs[0].id === processTabId;
    if (hasOnlyProcessTab) {
      await removeWindowSafe(processWindowId);
      return true;
    }
  }

  return tabClosed;
}

function getCompletedProcessPersistenceRetryDelayMs(attemptCount = 0) {
  const attempts = Number.isInteger(attemptCount) && attemptCount > 0 ? attemptCount : 0;
  if (attempts <= 0) {
    return COMPLETED_PROCESS_PERSISTENCE_RETRY.initialDelayMs;
  }
  const scaledDelay = COMPLETED_PROCESS_PERSISTENCE_RETRY.initialDelayMs * Math.pow(2, Math.min(attempts, 8));
  return Math.min(COMPLETED_PROCESS_PERSISTENCE_RETRY.maxDelayMs, scaledDelay);
}

function clearCompletedProcessPersistenceRetry(runId = '', options = {}) {
  const normalizedRunId = typeof runId === 'string' ? runId.trim() : '';
  if (!normalizedRunId) return false;
  const timerId = completedProcessPersistenceRetryTimersByRunId.get(normalizedRunId);
  if (timerId) {
    clearTimeout(timerId);
  }
  completedProcessPersistenceRetryTimersByRunId.delete(normalizedRunId);
  if (options.keepAttempts !== true) {
    completedProcessPersistenceRetryAttemptCountByRunId.delete(normalizedRunId);
  }
  if (options.keepInFlight !== true) {
    completedProcessPersistenceRetryInFlight.delete(normalizedRunId);
  }
  return true;
}

function resolveCompletedProcessPersistenceRetryPlan(process) {
  if (!process || typeof process !== 'object') {
    return { needed: false, mode: '', reason: 'invalid_process', delivery: null };
  }

  const status = normalizeProcessStatus(process.status || '');
  if (status !== 'completed') {
    return { needed: false, mode: '', reason: 'status_not_completed', delivery: getProcessQueueDeliveryState(process) };
  }

  const delivery = getProcessQueueDeliveryState(process);
  if (delivery.confirmed === true) {
    return { needed: false, mode: '', reason: 'already_confirmed', delivery };
  }

  const dispatch = getProcessPersistenceDispatchSnapshot(process);
  const hasResponsePayload = extractAssistantTextFromProcess(process).length > 0;

  if (delivery.saveOk === true) {
    const queueSkipReason = typeof dispatch?.queueSkipReason === 'string' ? dispatch.queueSkipReason.trim() : '';
    if (delivery.queueSkipped === true) {
      if (queueSkipReason === 'dispatch_disabled' || queueSkipReason === 'invalid_payload') {
        return { needed: false, mode: '', reason: queueSkipReason || 'queue_skipped_not_retriable', delivery };
      }
      if (!hasResponsePayload) {
        return { needed: false, mode: '', reason: 'missing_response_text', delivery };
      }
      return { needed: true, mode: 'replay', reason: 'queue_skipped', delivery };
    }
    if (dispatch && typeof dispatch === 'object') {
      return {
        needed: true,
        mode: 'flush',
        reason: delivery.state || 'dispatch_unconfirmed',
        delivery
      };
    }
    if (!hasResponsePayload) {
      return { needed: false, mode: '', reason: 'missing_response_text', delivery };
    }
    return { needed: true, mode: 'replay', reason: 'missing_dispatch_state', delivery };
  }

  if (!hasResponsePayload) {
    return { needed: false, mode: '', reason: 'missing_response_text', delivery };
  }

  return {
    needed: true,
    mode: 'replay',
    reason: delivery.saveOk === false ? 'save_failed' : 'save_not_attempted',
    delivery
  };
}

function scheduleCompletedProcessPersistenceRetriesForSnapshot(records = [], origin = 'registry_ready') {
  const snapshot = Array.isArray(records) ? records : [];
  snapshot.forEach((process, index) => {
    scheduleCompletedProcessPersistenceRetry(process, {
      origin,
      force: true,
      delayMs: Math.min(15000, Math.max(0, index) * 350)
    });
  });
}

function scheduleCompletedProcessPersistenceRetry(processOrRunId, options = {}) {
  const process = processOrRunId && typeof processOrRunId === 'object'
    ? processOrRunId
    : null;
  const normalizedRunId = typeof processOrRunId === 'string' && processOrRunId.trim()
    ? processOrRunId.trim()
    : (typeof process?.id === 'string' ? process.id.trim() : '');
  if (!normalizedRunId) return false;

  const currentProcess = process || processRegistry.get(normalizedRunId) || null;
  const plan = resolveCompletedProcessPersistenceRetryPlan(currentProcess);
  if (!plan.needed) {
    clearCompletedProcessPersistenceRetry(normalizedRunId);
    return false;
  }

  if (completedProcessPersistenceRetryInFlight.has(normalizedRunId) && options.allowWhileInFlight !== true) {
    return true;
  }

  const hasTimer = completedProcessPersistenceRetryTimersByRunId.has(normalizedRunId);
  if (hasTimer && options.force !== true) {
    return true;
  }

  clearCompletedProcessPersistenceRetry(normalizedRunId, { keepAttempts: true });
  const attemptCount = completedProcessPersistenceRetryAttemptCountByRunId.get(normalizedRunId) || 0;
  const delayMs = Number.isInteger(options?.delayMs)
    ? Math.max(0, options.delayMs)
    : getCompletedProcessPersistenceRetryDelayMs(attemptCount);
  const trace = buildProcessCopyTrace(currentProcess, normalizedRunId);
  const origin = typeof options?.origin === 'string' && options.origin.trim()
    ? options.origin.trim()
    : 'schedule_completed_persist_retry';
  emitWatchlistDispatchProcessLog('info', 'completed_persist_retry_scheduled', 'Scheduled completed process persistence retry', {
    trace,
    runId: normalizedRunId,
    origin,
    mode: plan.mode,
    reason: plan.reason,
    delayMs,
    attemptCount,
    queueState: typeof currentProcess?.queueState === 'string' ? currentProcess.queueState : '',
    status: typeof currentProcess?.status === 'string' ? currentProcess.status : '',
    confirmed: plan.delivery?.confirmed === true
  });
  const timerId = setTimeout(() => {
    completedProcessPersistenceRetryTimersByRunId.delete(normalizedRunId);
    void runCompletedProcessPersistenceRetry(normalizedRunId, {
      origin,
      scheduledMode: plan.mode,
      scheduledReason: plan.reason
    });
  }, delayMs);
  completedProcessPersistenceRetryTimersByRunId.set(normalizedRunId, timerId);
  return true;
}

async function closeCompletedProcessAfterDispatchConfirmed(runId = '', options = {}) {
  const normalizedRunId = typeof runId === 'string' ? runId.trim() : '';
  if (!normalizedRunId) return false;
  await ensureProcessRegistryReady();

  let process = processRegistry.get(normalizedRunId) || null;
  if (!process || typeof process !== 'object') return false;
  const lifecycleStatus = normalizeProcessLifecycleStatus(process.lifecycleStatus || process.status, 'running');
  if (lifecycleStatus !== 'completed' && lifecycleStatus !== 'finalizing') return false;
  if (process.queueManaged !== true) return false;
  const slotAlreadyReleased = process.slotReserved === false
    || process.queueState === 'slot_released'
    || process.queueState === 'dispatch_confirmed';
  if (!slotAlreadyReleased) return false;

  const delivery = getProcessQueueDeliveryState(process);
  if (delivery.confirmed !== true) return false;
  if (lifecycleStatus !== 'completed') {
    await upsertProcess(normalizedRunId, {
      lifecycleStatus: 'completed',
      status: 'completed',
      phase: 'verify_remote',
      actionRequired: 'none',
      statusCode: 'dispatch.confirmed',
      timestamp: Date.now()
    });
    process = processRegistry.get(normalizedRunId) || process;
  }

  const trace = buildProcessCopyTrace(process, normalizedRunId);
  const now = Date.now();
  if (process.queueState !== 'dispatch_confirmed') {
    await upsertProcess(normalizedRunId, {
      queueManaged: true,
      queueJobId: typeof process.queueJobId === 'string' ? process.queueJobId : '',
      queueState: 'dispatch_confirmed',
      slotReserved: false,
      slotReleasedAt: Number.isInteger(process.slotReleasedAt) ? process.slotReleasedAt : now,
      slotReleaseReason: typeof process.slotReleaseReason === 'string' && process.slotReleaseReason.trim()
        ? process.slotReleaseReason.trim()
        : 'dispatch_confirmed_late',
      timestamp: now
    });
    process = processRegistry.get(normalizedRunId) || process;
  }

  const closed = await closeProcessWindowAfterQueueSuccess(process);
  emitWatchlistDispatchProcessLog(closed ? 'info' : 'warn', 'completed_process_window_close', closed
    ? 'Closed queued process window after dispatch confirmation'
    : 'Completed queued process confirmed, but no process tab/window was closed', {
    trace,
    runId: normalizedRunId,
    origin: typeof options?.origin === 'string' ? options.origin : 'dispatch_confirmed',
    tabId: Number.isInteger(process?.tabId) ? process.tabId : null,
    windowId: Number.isInteger(process?.windowId) ? process.windowId : null,
    queueState: typeof process?.queueState === 'string' ? process.queueState : '',
    closed
  });
  await reportAnalysisQueueEvent('job_window_close_after_confirm', {
    process,
    runId: normalizedRunId,
    jobId: typeof process?.queueJobId === 'string' ? process.queueJobId : '',
    status: closed ? 'closed' : 'close_skipped',
    reason: typeof options?.origin === 'string' ? options.origin : 'dispatch_confirmed',
    queueState: typeof process?.queueState === 'string' ? process.queueState : 'dispatch_confirmed',
    closeWindowRequested: true,
    closed,
    dispatchState: delivery?.state || 'dispatch_confirmed',
    dispatchConfirmed: true,
    title: 'Analysis queue: close after dispatch confirm'
  }).catch((error) => {
    console.warn('[analysis-queue] late close log failed:', {
      runId: normalizedRunId,
      error: error?.message || String(error)
    });
  });
  return closed;
}

async function runCompletedProcessPersistenceRetry(runId = '', options = {}) {
  const normalizedRunId = typeof runId === 'string' ? runId.trim() : '';
  if (!normalizedRunId) {
    return { success: false, reason: 'missing_run_id' };
  }
  if (completedProcessPersistenceRetryInFlight.has(normalizedRunId)) {
    return { success: false, skipped: true, reason: 'retry_in_flight' };
  }

  completedProcessPersistenceRetryInFlight.add(normalizedRunId);
  try {
    await ensureProcessRegistryReady();
    let process = processRegistry.get(normalizedRunId) || null;
    if (!process || typeof process !== 'object') {
      clearCompletedProcessPersistenceRetry(normalizedRunId);
      return { success: false, reason: 'missing_process' };
    }

    let plan = resolveCompletedProcessPersistenceRetryPlan(process);
    if (!plan.needed) {
      clearCompletedProcessPersistenceRetry(normalizedRunId);
      if (plan.delivery?.confirmed === true) {
        await closeCompletedProcessAfterDispatchConfirmed(normalizedRunId, {
          origin: options?.origin || 'completed_process_retry'
        }).catch(() => false);
      }
      return {
        success: true,
        skipped: true,
        reason: plan.reason,
        delivery: plan.delivery
      };
    }

    const attemptCount = (completedProcessPersistenceRetryAttemptCountByRunId.get(normalizedRunId) || 0) + 1;
    completedProcessPersistenceRetryAttemptCountByRunId.set(normalizedRunId, attemptCount);
    const trace = buildProcessCopyTrace(process, normalizedRunId);
    const origin = typeof options?.origin === 'string' && options.origin.trim()
      ? options.origin.trim()
      : 'completed_process_retry';
    const attemptMode = plan.mode;
    const attemptReason = plan.reason;
    emitWatchlistDispatchProcessLog('info', 'completed_persist_retry_start', 'Started completed process persistence retry', {
      trace,
      runId: normalizedRunId,
      origin,
      attemptCount,
      mode: attemptMode,
      reason: attemptReason,
      queueState: typeof process?.queueState === 'string' ? process.queueState : '',
      status: typeof process?.status === 'string' ? process.status : ''
    });

    let actionResult = null;
    if (attemptMode === 'flush') {
      actionResult = await flushWatchlistDispatchOutbox(`completed_process_retry:${origin}`);
    } else {
      actionResult = await ensureCompletedProcessResponsePersisted(process, {
        force: true,
        tabId: Number.isInteger(process?.tabId) ? process.tabId : null,
        tabReadTimeoutMs: 2200,
        origin: `completed_process_retry:${origin}`
      });
    }

    process = processRegistry.get(normalizedRunId) || process;
    plan = resolveCompletedProcessPersistenceRetryPlan(process);
    const delivery = plan.delivery || getProcessQueueDeliveryState(process);
    const confirmed = delivery?.confirmed === true;
    const shouldRetry = plan.needed === true;
    const resultLogLevel = confirmed ? 'info' : (shouldRetry ? 'warn' : 'info');
    const resultSummary = attemptMode === 'flush'
      ? {
          skipped: actionResult?.skipped === true,
          accepted: Number.isInteger(actionResult?.accepted) ? actionResult.accepted : 0,
          sent: Number.isInteger(actionResult?.sent) ? actionResult.sent : 0,
          failed: Number.isInteger(actionResult?.failed) ? actionResult.failed : 0,
          deferred: Number.isInteger(actionResult?.deferred) ? actionResult.deferred : 0,
          remaining: Number.isInteger(actionResult?.remaining) ? actionResult.remaining : 0,
          verifyState: typeof actionResult?.verifyState === 'string' ? actionResult.verifyState : '',
          verifyReason: typeof actionResult?.verifyReason === 'string' ? actionResult.verifyReason : ''
        }
      : {
          attempted: actionResult?.attempted === true,
          success: actionResult?.success === true,
          reason: typeof actionResult?.reason === 'string' ? actionResult.reason : '',
          dispatchSummary: typeof actionResult?.dispatchSummary === 'string' ? actionResult.dispatchSummary : ''
        };
    emitWatchlistDispatchProcessLog(resultLogLevel, 'completed_persist_retry_result', confirmed
      ? 'Completed process persistence retry confirmed dispatch'
      : (shouldRetry ? 'Completed process persistence retry still pending' : 'Completed process persistence retry settled'), {
      trace,
      runId: normalizedRunId,
      origin,
      attemptCount,
      mode: attemptMode,
      reason: attemptReason,
      confirmed,
      nextReason: plan.reason,
      deliveryState: delivery?.state || '',
      saveOk: delivery?.saveOk === true,
      pending: Number.isInteger(delivery?.pending) ? delivery.pending : null,
      failed: Number.isInteger(delivery?.failed) ? delivery.failed : null,
      queueState: typeof process?.queueState === 'string' ? process.queueState : '',
      result: resultSummary
    });

    if (confirmed) {
      clearCompletedProcessPersistenceRetry(normalizedRunId);
      await closeCompletedProcessAfterDispatchConfirmed(normalizedRunId, {
        origin
      }).catch(() => false);
      requestAnalysisQueueReconcile('completed_process_persist_retry_confirmed');
      return {
        success: true,
        confirmed: true,
        attemptCount,
        delivery
      };
    }

    if (!shouldRetry) {
      clearCompletedProcessPersistenceRetry(normalizedRunId);
      return {
        success: true,
        confirmed: false,
        settled: true,
        attemptCount,
        delivery
      };
    }

    if (attemptCount >= COMPLETED_PROCESS_PERSISTENCE_RETRY.maxAttempts) {
      clearCompletedProcessPersistenceRetry(normalizedRunId, { keepAttempts: true });
      emitWatchlistDispatchProcessLog('warn', 'completed_persist_retry_exhausted', 'Completed process persistence retry reached max attempts', {
        trace,
        runId: normalizedRunId,
        origin,
        attemptCount,
        mode: plan.mode,
        reason: plan.reason,
        deliveryState: delivery?.state || ''
      });
      return {
        success: false,
        confirmed: false,
        reason: 'max_attempts_reached',
        attemptCount,
        delivery
      };
    }

    scheduleCompletedProcessPersistenceRetry(process, {
      origin,
      force: true,
      allowWhileInFlight: true
    });
    return {
      success: true,
      confirmed: false,
      pending: true,
      attemptCount,
      delivery
    };
  } catch (error) {
    const process = processRegistry.get(normalizedRunId) || null;
    const trace = buildProcessCopyTrace(process, normalizedRunId);
    emitWatchlistDispatchProcessLog('error', 'completed_persist_retry_error', 'Completed process persistence retry failed with exception', {
      trace,
      runId: normalizedRunId,
      origin: typeof options?.origin === 'string' ? options.origin : 'completed_process_retry',
      error: error?.message || String(error)
    });
    scheduleCompletedProcessPersistenceRetry(normalizedRunId, {
      origin: typeof options?.origin === 'string' ? options.origin : 'completed_process_retry',
      force: true,
      allowWhileInFlight: true
    });
    return {
      success: false,
      reason: error?.message || String(error)
    };
  } finally {
    completedProcessPersistenceRetryInFlight.delete(normalizedRunId);
  }
}

function generateAnalysisQueueRunId(prefix = 'analysis') {
  const safePrefix = typeof prefix === 'string' && prefix.trim()
    ? prefix.trim().replace(/[^a-zA-Z0-9._-]/g, '_')
    : 'analysis';
  return `queue-${safePrefix}-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;
}

function generateAnalysisQueueJobId(sequence = 0) {
  const safeSequence = Number.isInteger(sequence) ? Math.max(0, sequence) : 0;
  return `aq-${Date.now()}-${safeSequence}-${Math.random().toString(36).slice(2, 8)}`;
}

function buildQueuedProcessPatchForJob(job) {
  const safeJob = sanitizeAnalysisQueueJob(job);
  if (!safeJob) return null;
  const totalPrompts = Array.isArray(PROMPTS_COMPANY) ? PROMPTS_COMPANY.length : 0;
  const patch = {
    title: safeJob.title,
    analysisType: safeJob.analysisType || 'company',
    status: 'queued',
    statusText: 'Oczekuje w kolejce',
    currentPrompt: safeJob.kind === ANALYSIS_QUEUE_KIND_RESUME_STAGE
      ? Math.max(0, safeJob.resumeStartIndex || 0)
      : 0,
    totalPrompts,
    needsAction: false,
    startedAt: safeJob.createdAt,
    timestamp: safeJob.createdAt,
    queueManaged: true,
    queueJobId: safeJob.jobId,
    queueState: 'waiting',
    slotReserved: false,
    slotReleasedAt: null,
    slotReleaseReason: '',
    queueBatchId: safeJob.queueBatchId || '',
    manualPdfBatchId: safeJob.manualPdfBatchId || '',
    manualPdfProviderId: safeJob.manualPdfProviderId || '',
    invocationWindowId: Number.isInteger(safeJob.invocationWindowId) ? safeJob.invocationWindowId : null,
    sourceWindowId: Number.isInteger(safeJob.sourceWindowId) ? safeJob.sourceWindowId : null,
    messages: []
  };

  if (safeJob.kind === ANALYSIS_QUEUE_KIND_ARTICLE) {
    const sourceUrl = typeof safeJob?.tabSnapshot?.url === 'string' ? safeJob.tabSnapshot.url : '';
    patch.sourceUrl = sourceUrl;
  } else {
    const startIndex = Number.isInteger(safeJob.resumeStartIndex) ? safeJob.resumeStartIndex : 0;
    patch.currentPrompt = Math.max(0, startIndex);
    patch.stageIndex = startIndex > 0 ? (startIndex - 1) : null;
    patch.stageName = startIndex > 0 ? `Prompt ${startIndex}` : 'Start';
    patch.tabId = safeJob.resumeTargetTabId;
    if (Number.isInteger(safeJob.resumeTargetWindowId)) {
      patch.windowId = safeJob.resumeTargetWindowId;
    }
    if (typeof safeJob.chatUrl === 'string' && safeJob.chatUrl.trim()) {
      patch.chatUrl = safeJob.chatUrl.trim();
      patch.sourceUrl = safeJob.chatUrl.trim();
    }
  }

  return patch;
}

async function enqueueAnalysisJobs(rawJobs, options = {}) {
  const sourceJobs = Array.isArray(rawJobs) ? rawJobs : [];
  if (sourceJobs.length === 0) {
    const emptySnapshot = await getAnalysisQueueStatusSnapshot();
    return {
      success: true,
      jobs: [],
      queuedCount: 0,
      maxConcurrent: emptySnapshot.maxConcurrent,
      queueSize: emptySnapshot.queueSize,
      activeSlots: emptySnapshot.activeSlots,
      reservedSlots: emptySnapshot.reservedSlots,
      liveSlots: emptySnapshot.liveSlots,
      startingSlots: emptySnapshot.startingSlots
    };
  }

  await ensureAnalysisQueueReady();
  let queuedJobs = [];
  let persistedSnapshot = null;
  persistedSnapshot = await withAnalysisQueueMutationLock(async () => {
    let state = cloneAnalysisQueueState();
    const nextJobs = [];

    for (const rawJob of sourceJobs) {
      const sequence = (state.lastSequence || 0) + 1;
      state.lastSequence = sequence;
      const prepared = sanitizeAnalysisQueueJob({
        ...rawJob,
        jobId: typeof rawJob?.jobId === 'string' && rawJob.jobId.trim()
          ? rawJob.jobId.trim()
          : generateAnalysisQueueJobId(sequence),
        runId: typeof rawJob?.runId === 'string' && rawJob.runId.trim()
          ? rawJob.runId.trim()
          : generateAnalysisQueueRunId(rawJob?.kind === ANALYSIS_QUEUE_KIND_RESUME_STAGE ? 'resume' : 'article'),
        sequence,
        createdAt: Number.isInteger(rawJob?.createdAt) ? rawJob.createdAt : Date.now()
      });
      if (!prepared) continue;
      state.waitingJobs.push(prepared);
      nextJobs.push(prepared);
    }

    sortAnalysisQueueWaitingJobs(state.waitingJobs);

    queuedJobs = nextJobs;
    return persistAnalysisQueueState(state);
  });

  for (const job of queuedJobs) {
    const patch = buildQueuedProcessPatchForJob(job);
    if (!patch) continue;
    await upsertProcess(job.runId, patch);
  }

  await reconcileAnalysisQueueState(typeof options?.reason === 'string' ? options.reason : 'enqueue');
  const queueSnapshot = await getAnalysisQueueStatusSnapshot();
  const enqueueReason = typeof options?.reason === 'string' && options.reason.trim()
    ? options.reason.trim()
    : 'enqueue';
  await Promise.all(
    queuedJobs.map((job, index) => reportAnalysisQueueEvent('job_enqueued', {
      job,
      process: processRegistry.get(job.runId) || null,
      status: 'queued',
      reason: enqueueReason,
      queueState: typeof processRegistry.get(job.runId)?.queueState === 'string'
        ? processRegistry.get(job.runId).queueState
        : 'waiting',
      queueSize: queueSnapshot.queueSize,
      waitingJobs: queueSnapshot.waitingJobs,
      activeSlots: queueSnapshot.activeSlots,
      maxConcurrent: queueSnapshot.maxConcurrent,
      batchIndex: index + 1,
      batchTotal: queuedJobs.length,
      sequence: Number.isInteger(job?.sequence) ? job.sequence : null,
      triggerReason: enqueueReason,
      title: `Analysis queue: enqueued ${job?.kind === ANALYSIS_QUEUE_KIND_RESUME_STAGE ? 'resume' : 'analysis'}`
    }).catch((error) => {
      console.warn('[analysis-queue] enqueue log failed:', {
        jobId: job?.jobId || '',
        runId: job?.runId || '',
        error: error?.message || String(error)
      });
    }))
  );

  return {
    success: true,
    jobs: queuedJobs,
    queuedCount: queuedJobs.length,
    maxConcurrent: queueSnapshot.maxConcurrent,
    queueSize: queueSnapshot.queueSize,
    activeSlots: queueSnapshot.activeSlots,
    reservedSlots: queueSnapshot.reservedSlots,
    liveSlots: queueSnapshot.liveSlots,
    startingSlots: queueSnapshot.startingSlots
  };
}

async function cancelQueuedAnalysisJobs(matchFn, options = {}) {
  const matcher = typeof matchFn === 'function' ? matchFn : null;
  if (!matcher) {
    return { success: false, cancelledCount: 0, jobs: [] };
  }

  await ensureAnalysisQueueReady();
  let cancelledJobs = [];
  let persistedSnapshot = null;
  persistedSnapshot = await withAnalysisQueueMutationLock(async () => {
    let state = cloneAnalysisQueueState();
    const keptJobs = [];
    const removedJobs = [];

    for (const job of state.waitingJobs) {
      if (matcher(job)) {
        removedJobs.push(job);
      } else {
        keptJobs.push(job);
      }
    }

    state.waitingJobs = keptJobs;
    cancelledJobs = removedJobs;
    return persistAnalysisQueueState(state);
  });

  if (cancelledJobs.length === 0) {
    return {
      success: true,
      cancelledCount: 0,
      jobs: [],
      queueSize: Number.isInteger(persistedSnapshot?.waitingJobs?.length) ? persistedSnapshot.waitingJobs.length : 0
    };
  }

  const now = Date.now();
  const statusText = typeof options?.statusText === 'string' && options.statusText.trim()
    ? options.statusText.trim()
    : 'Anulowano w kolejce';
  const reason = typeof options?.reason === 'string' && options.reason.trim()
    ? options.reason.trim()
    : 'queue_cancelled';
  for (const job of cancelledJobs) {
    await upsertProcess(job.runId, {
      status: 'cancelled',
      statusText,
      reason,
      needsAction: false,
      queueManaged: true,
      queueJobId: job.jobId,
      queueState: 'cancelled',
      slotReserved: false,
      slotReleasedAt: now,
      slotReleaseReason: reason,
      finishedAt: now,
      timestamp: now
    });
    if (job?.remote?.remoteJobId && job?.remote?.remoteAttemptId) {
      const failure = buildRemoteJobFailureDetails(
        job,
        processRegistry.get(job.runId) || null,
        null,
        statusText,
        reason
      );
      await reportRemoteJobEvent(
        job.remote.remoteJobId,
        'failed',
        job.remote.remoteAttemptId,
        failure.payload,
        failure.error
      ).catch((error) => {
        console.warn('[remote-runner] failed to report queued cancellation:', {
          jobId: job.remote.remoteJobId,
          attemptId: job.remote.remoteAttemptId,
          error: error?.message || String(error)
        });
      });
    }
  }

  await reconcileAnalysisQueueState('cancel_waiting_jobs');
  const queueSnapshot = await getAnalysisQueueStatusSnapshot();
  return {
    success: true,
    cancelledCount: cancelledJobs.length,
    jobs: cancelledJobs,
    queueSize: queueSnapshot.queueSize,
    activeSlots: queueSnapshot.activeSlots
  };
}

async function promoteQueuedAnalysisJob(matchFn, options = {}) {
  const matcher = typeof matchFn === 'function' ? matchFn : null;
  if (!matcher) {
    return { success: false, promoted: false, job: null };
  }

  await ensureAnalysisQueueReady();
  let promotedJob = null;
  let changed = false;
  await withAnalysisQueueMutationLock(async () => {
    const state = cloneAnalysisQueueState();
    const targetIndex = state.waitingJobs.findIndex((job) => matcher(job));
    if (targetIndex < 0) {
      return state;
    }

    const [targetJob] = state.waitingJobs.splice(targetIndex, 1);
    if (!targetJob) {
      return state;
    }

    state.waitingJobs.unshift(targetJob);
    state.waitingJobs = state.waitingJobs.map((job, index) => ({
      ...job,
      sequence: index + 1
    }));
    sortAnalysisQueueWaitingJobs(state.waitingJobs);

    promotedJob = state.waitingJobs.find((job) => matcher(job)) || targetJob;
    changed = true;
    return persistAnalysisQueueState(state);
  });

  if (!changed || !promotedJob) {
    const queueSnapshot = await getAnalysisQueueStatusSnapshot();
    return {
      success: true,
      promoted: false,
      job: null,
      queueSize: queueSnapshot.queueSize,
      activeSlots: queueSnapshot.activeSlots
    };
  }

  await reconcileAnalysisQueueState(typeof options?.reason === 'string' ? options.reason : 'promote_waiting_job');
  const queueSnapshot = await getAnalysisQueueStatusSnapshot();
  return {
    success: true,
    promoted: true,
    job: promotedJob,
    queueSize: queueSnapshot.queueSize,
    activeSlots: queueSnapshot.activeSlots
  };
}

function matchesAnalysisQueueJobForProcessIdentifiers(job, runId = '', queueJobId = '') {
  const normalizedRunId = typeof runId === 'string' ? runId.trim() : '';
  const normalizedQueueJobId = typeof queueJobId === 'string' ? queueJobId.trim() : '';
  const jobRunId = typeof job?.runId === 'string' ? job.runId.trim() : '';
  const jobId = typeof job?.jobId === 'string' ? job.jobId.trim() : '';
  if (normalizedQueueJobId && jobId === normalizedQueueJobId) return true;
  if (normalizedRunId && jobRunId === normalizedRunId) return true;
  return false;
}

async function handleProcessQueueActionMessage(message = {}) {
  const runId = typeof message?.runId === 'string' ? message.runId.trim() : '';
  if (!runId) {
    return { success: false, error: 'missing_process_id' };
  }

  const action = typeof message?.action === 'string' ? message.action.trim().toLowerCase() : '';
  if (action !== 'remove' && action !== 'promote') {
    return { success: false, error: 'invalid_queue_action' };
  }

  const queueJobId = typeof message?.queueJobId === 'string' ? message.queueJobId.trim() : '';
  const process = processRegistry.get(runId) || null;
  if (process && normalizeProcessStatus(process?.status) !== 'queued') {
    return { success: false, error: 'process_not_queued' };
  }

  const matcher = (job) => matchesAnalysisQueueJobForProcessIdentifiers(job, runId, queueJobId);
  if (action === 'remove') {
    const result = await cancelQueuedAnalysisJobs(matcher, {
      reason: 'queue_removed_from_panel',
      statusText: 'Usunieto z kolejki'
    });
    const removedJob = Array.isArray(result?.jobs) && result.jobs.length > 0 ? result.jobs[0] : null;
    if ((result?.cancelledCount || 0) <= 0 || !removedJob) {
      return {
        success: false,
        error: 'queued_job_not_found',
        queueSize: Number.isInteger(result?.queueSize) ? result.queueSize : 0,
        activeSlots: Number.isInteger(result?.activeSlots) ? result.activeSlots : 0
      };
    }
    return {
      success: true,
      action,
      removed: true,
      runId,
      queueJobId: typeof removedJob?.jobId === 'string' ? removedJob.jobId : queueJobId,
      queueSize: Number.isInteger(result?.queueSize) ? result.queueSize : 0,
      activeSlots: Number.isInteger(result?.activeSlots) ? result.activeSlots : 0
    };
  }

  const result = await promoteQueuedAnalysisJob(matcher, {
    reason: 'promote_waiting_job_from_panel'
  });
  const promotedJob = result?.job && typeof result.job === 'object' ? result.job : null;
  if (result?.promoted !== true || !promotedJob) {
    return {
      success: false,
      error: 'queued_job_not_found',
      queueSize: Number.isInteger(result?.queueSize) ? result.queueSize : 0,
      activeSlots: Number.isInteger(result?.activeSlots) ? result.activeSlots : 0
    };
  }

  const queueSnapshot = await getAnalysisQueueSnapshot();
  const queuePosition = Array.isArray(queueSnapshot?.waitingJobs)
    ? (queueSnapshot.waitingJobs.findIndex((job) => matchesAnalysisQueueJobForProcessIdentifiers(job, runId, queueJobId)) + 1)
    : 0;
  return {
    success: true,
    action,
    promoted: true,
    runId,
    queueJobId: typeof promotedJob?.jobId === 'string' ? promotedJob.jobId : queueJobId,
    queuePosition: queuePosition > 0 ? queuePosition : null,
    queueSize: Number.isInteger(result?.queueSize) ? result.queueSize : 0,
    activeSlots: Number.isInteger(result?.activeSlots) ? result.activeSlots : 0
  };
}

function registerManualPdfQueueBatch(batchId, providerId, queuedJobs = []) {
  const safeBatchId = typeof batchId === 'string' ? batchId.trim() : '';
  const safeProviderId = typeof providerId === 'string' ? providerId.trim() : '';
  if (!safeBatchId || !safeProviderId) return;
  const batchJobs = Array.isArray(queuedJobs) ? queuedJobs : [];
  manualPdfQueueBatches.set(safeBatchId, {
    batchId: safeBatchId,
    providerId: safeProviderId,
    totalJobs: batchJobs.length,
    completedJobs: 0,
    failedJobs: 0,
    finishedRunIds: new Set(),
    createdAt: Date.now()
  });
}

async function handleManualPdfBatchProcessUpdate(previousProcess, nextProcess) {
  const next = nextProcess && typeof nextProcess === 'object' ? nextProcess : null;
  if (!next) return;
  const batchId = typeof next.manualPdfBatchId === 'string' ? next.manualPdfBatchId.trim() : '';
  if (!batchId || !manualPdfQueueBatches.has(batchId)) return;
  const batch = manualPdfQueueBatches.get(batchId);
  if (!batch) return;
  const runId = typeof next.id === 'string' ? next.id.trim() : '';
  if (!runId || batch.finishedRunIds.has(runId)) return;

  const nextStatus = normalizeProcessStatus(next.status);
  if (!isClosedProcessStatus(nextStatus)) return;

  batch.finishedRunIds.add(runId);
  if (nextStatus === 'completed') {
    batch.completedJobs += 1;
  } else {
    batch.failedJobs += 1;
  }

  const doneCount = batch.completedJobs + batch.failedJobs;
  const finalMessage = `Kolejka PDF zakonczona. Sukces: ${batch.completedJobs}, bledy: ${batch.failedJobs}, razem: ${batch.totalJobs}.`;
  if (doneCount >= batch.totalJobs) {
    await notifyManualPdfProviderStatus(
      batch.providerId,
      batch.failedJobs > 0 ? 'failed' : 'completed',
      finalMessage,
      {
        totalJobs: batch.totalJobs,
        completedJobs: batch.completedJobs,
        failedJobs: batch.failedJobs,
        success: batch.failedJobs === 0
      }
    );
    await releaseManualPdfProvider(batch.providerId, finalMessage, {
      totalJobs: batch.totalJobs,
      completedJobs: batch.completedJobs,
      failedJobs: batch.failedJobs,
      success: batch.failedJobs === 0
    });
    manualPdfQueueBatches.delete(batchId);
    return;
  }

  const progressMessage = nextStatus === 'completed'
    ? `Gotowe ${doneCount}/${batch.totalJobs}: ${next.title || runId}.`
    : `Blad ${doneCount}/${batch.totalJobs}: ${next.title || runId}.`;
  await notifyManualPdfProviderStatus(
    batch.providerId,
    nextStatus === 'completed' ? 'running' : 'failed',
    progressMessage,
    {
      currentJob: doneCount,
      totalJobs: batch.totalJobs,
      completedJobs: batch.completedJobs,
      failedJobs: batch.failedJobs,
      success: nextStatus === 'completed',
      reason: typeof next.reason === 'string' ? next.reason : ''
    }
  );
}

function runQueuedAnalysisJob(job, reason = 'scheduler') {
  const scheduledJob = sanitizeAnalysisQueueJob(job);
  if (!scheduledJob) return;

  void Promise.resolve()
    .then(async () => {
      if (scheduledJob.kind === ANALYSIS_QUEUE_KIND_RESUME_STAGE) {
        const resumeResult = await resumeFromStageOnTab(
          scheduledJob.resumeTargetTabId,
          Number.isInteger(scheduledJob.resumeTargetWindowId) ? scheduledJob.resumeTargetWindowId : null,
          scheduledJob.resumeStartIndex,
          {
            reloadBeforeResume: scheduledJob.reloadBeforeResume !== false,
            forceRepeatLastPrompt: scheduledJob.forceRepeatLastPrompt === true,
            skipStagePreflight: scheduledJob.skipStagePreflight === true,
            minStartIndex: Number.isInteger(scheduledJob.minStartIndex) ? scheduledJob.minStartIndex : undefined,
            stagePlanMaxWaitMs: Number.isInteger(scheduledJob.stagePlanMaxWaitMs) ? scheduledJob.stagePlanMaxWaitMs : undefined,
            precomputedStagePlan: scheduledJob.precomputedStagePlan && typeof scheduledJob.precomputedStagePlan === 'object'
              ? scheduledJob.precomputedStagePlan
              : undefined,
            composerThinkingEffort: typeof scheduledJob.composerThinkingEffort === 'string'
              ? scheduledJob.composerThinkingEffort
              : '',
            processTitle: scheduledJob.title,
            runId: scheduledJob.runId,
            queueJobId: scheduledJob.jobId
          }
        );

        if (!resumeResult?.success) {
          const now = Date.now();
          await upsertProcess(scheduledJob.runId, {
            title: scheduledJob.title,
            analysisType: scheduledJob.analysisType || 'company',
            status: 'failed',
            statusText: 'Resume z kolejki nieudany',
            reason: resumeResult?.error || 'resume_queue_failed',
            error: resumeResult?.details || resumeResult?.reason || resumeResult?.error || 'resume_queue_failed',
            needsAction: false,
            queueManaged: true,
            queueJobId: scheduledJob.jobId,
            queueState: 'active',
            slotReserved: true,
            autoRecovery: null,
            finishedAt: now,
            timestamp: now
          });
          await reportAnalysisQueueEvent('job_execution_failed', {
            job: scheduledJob,
            process: processRegistry.get(scheduledJob.runId) || null,
            status: 'failed',
            reason: resumeResult?.error || 'resume_queue_failed',
            queueState: 'active',
            triggerReason: reason,
            title: 'Analysis queue: resume job failed'
          }).catch((error) => {
            console.warn('[analysis-queue] resume failure log failed:', {
              jobId: scheduledJob.jobId,
              runId: scheduledJob.runId,
              error: error?.message || String(error)
            });
          });
        }
        requestAnalysisQueueReconcile('resume_job_finished');
        return;
      }

      const promptChain = Array.isArray(scheduledJob.promptChainSnapshot) && scheduledJob.promptChainSnapshot.length > 0
        ? scheduledJob.promptChainSnapshot
        : PROMPTS_COMPANY;
      if (!(Array.isArray(scheduledJob.promptChainSnapshot) && scheduledJob.promptChainSnapshot.length > 0)) {
        await ensureCompanyPromptsReady();
      }
      if (scheduledJob?.remote?.remoteJobId && scheduledJob?.remote?.remoteAttemptId) {
        await reportRemoteJobEvent(
          scheduledJob.remote.remoteJobId,
          'started',
          scheduledJob.remote.remoteAttemptId,
          {
            queueState: 'running',
            promptHash: typeof scheduledJob.promptHash === 'string' ? scheduledJob.promptHash : '',
            runId: scheduledJob.runId,
            jobId: scheduledJob.jobId
          }
        ).catch((error) => {
          console.warn('[remote-runner] failed to report started event:', {
            jobId: scheduledJob.remote.remoteJobId,
            attemptId: scheduledJob.remote.remoteAttemptId,
            error: error?.message || String(error)
          });
        });
      }
      const executionResult = await executeAnalysisProcessJob(
        scheduledJob.tabSnapshot,
        promptChain,
        typeof scheduledJob.chatUrl === 'string' && scheduledJob.chatUrl.trim()
          ? scheduledJob.chatUrl.trim()
          : CHAT_URL,
        scheduledJob.analysisType || 'company',
        {
          invocationWindowId: Number.isInteger(scheduledJob.invocationWindowId) ? scheduledJob.invocationWindowId : null,
          runId: scheduledJob.runId,
          queueJobId: scheduledJob.jobId,
          sourceKind: scheduledJob.sourceKind || '',
          remote: scheduledJob.remote || null,
          promptHash: typeof scheduledJob.promptHash === 'string' ? scheduledJob.promptHash : ''
        }
      );
      if (scheduledJob?.remote?.remoteJobId && scheduledJob?.remote?.remoteAttemptId) {
        const currentProcess = processRegistry.get(scheduledJob.runId) || null;
        const delivery = currentProcess ? getProcessQueueDeliveryState(currentProcess) : null;
        if (delivery?.saveOk === true) {
          await reportRemoteJobEvent(
            scheduledJob.remote.remoteJobId,
            'completed',
            scheduledJob.remote.remoteAttemptId,
            buildRemoteJobCompletedPayload(scheduledJob, currentProcess, executionResult)
          ).catch((error) => {
            console.warn('[remote-runner] failed to report completed event:', {
              jobId: scheduledJob.remote.remoteJobId,
              attemptId: scheduledJob.remote.remoteAttemptId,
              error: error?.message || String(error)
            });
          });
        } else {
          const failure = buildRemoteJobFailureDetails(scheduledJob, currentProcess, executionResult);
          await reportRemoteJobEvent(
            scheduledJob.remote.remoteJobId,
            'failed',
            scheduledJob.remote.remoteAttemptId,
            failure.payload,
            failure.error
          ).catch((error) => {
            console.warn('[remote-runner] failed to report failed event:', {
              jobId: scheduledJob.remote.remoteJobId,
              attemptId: scheduledJob.remote.remoteAttemptId,
              error: error?.message || String(error)
            });
          });
        }
      }
      requestAnalysisQueueReconcile('article_job_finished');
    })
    .catch(async (error) => {
      const now = Date.now();
      await upsertProcess(scheduledJob.runId, {
        title: scheduledJob.title,
        analysisType: scheduledJob.analysisType || 'company',
        status: 'failed',
        statusText: 'Blad wykonania kolejki',
        reason: 'queue_execution_exception',
        error: error?.message || String(error),
        needsAction: false,
        queueManaged: true,
        queueJobId: scheduledJob.jobId,
        queueState: 'active',
        slotReserved: true,
        autoRecovery: null,
        finishedAt: now,
        timestamp: now
      });
      console.warn('[analysis-queue] job execution failed:', {
        reason,
        jobId: scheduledJob.jobId,
        runId: scheduledJob.runId,
        error: error?.message || String(error)
      });
      if (scheduledJob?.remote?.remoteJobId && scheduledJob?.remote?.remoteAttemptId) {
        const failure = buildRemoteJobFailureDetails(
          scheduledJob,
          processRegistry.get(scheduledJob.runId) || null,
          null,
          error?.message || String(error)
        );
        await reportRemoteJobEvent(
          scheduledJob.remote.remoteJobId,
          'failed',
          scheduledJob.remote.remoteAttemptId,
          failure.payload,
          failure.error
        ).catch((eventError) => {
          console.warn('[remote-runner] failed to report execution exception:', {
            jobId: scheduledJob.remote.remoteJobId,
            attemptId: scheduledJob.remote.remoteAttemptId,
            error: eventError?.message || String(eventError)
          });
        });
      }
      await reportAnalysisQueueEvent('job_execution_exception', {
        job: scheduledJob,
        process: processRegistry.get(scheduledJob.runId) || null,
        status: 'failed',
        reason: 'queue_execution_exception',
        queueState: 'active',
        triggerReason: reason,
        title: 'Analysis queue: execution exception'
      }).catch((logError) => {
        console.warn('[analysis-queue] execution exception log failed:', {
          jobId: scheduledJob.jobId,
          runId: scheduledJob.runId,
          error: logError?.message || String(logError)
        });
      });
      requestAnalysisQueueReconcile('queue_job_exception');
    });
}

async function reconcileAnalysisQueueState(reason = 'manual') {
  if (analysisQueueReconcileInProgress) {
    analysisQueueReconcileRequested = true;
    return { success: false, skipped: true, reason: 'queue_reconcile_in_progress' };
  }

  analysisQueueReconcileInProgress = true;
  const normalizedReason = typeof reason === 'string' && reason.trim()
    ? reason.trim()
    : 'manual';

  try {
    await ensureAnalysisQueueReady();
    await ensureProcessRegistryReady();

    while (true) {
      analysisQueueReconcileRequested = false;
      const now = Date.now();
      let startJobs = [];
      let releaseJobs = [];
      let releaseEventRecords = [];
      const followUpProcessPatchesByRunId = new Map();
      const queueFollowUpProcessPatch = (runId, patch) => {
        const normalizedRunId = typeof runId === 'string' ? runId.trim() : '';
        if (!normalizedRunId || !patch || typeof patch !== 'object') return;
        const existing = followUpProcessPatchesByRunId.get(normalizedRunId);
        const previousPatch = existing?.patch && typeof existing.patch === 'object'
          ? existing.patch
          : {};
        followUpProcessPatchesByRunId.set(normalizedRunId, {
          runId: normalizedRunId,
          patch: {
            ...previousPatch,
            ...patch
          }
        });
      };

      await withAnalysisQueueMutationLock(async () => {
        let state = cloneAnalysisQueueState();
        const nextActiveJobsByContext = new Map();

        for (const activeJob of state.activeJobs) {
          const process = processRegistry.get(activeJob.runId) || null;
          const decision = resolveAnalysisQueueReleaseDecision(activeJob, process, now);
          if (decision.action === 'release') {
            releaseJobs.push({
              job: activeJob,
              process,
              reason: decision.reason,
              closeWindow: decision.closeWindow === true
            });
            continue;
          }
          const processActivity = process
            ? await getAnalysisQueueProcessActivityState(process, now)
            : null;
          if (process && processActivity?.active !== true) {
            releaseJobs.push({
              job: activeJob,
              process,
              reason: 'local_context_missing',
              closeWindow: false
            });
            const stalePatch = await buildStaleQueueReleasePatch(process, now);
            if (stalePatch) {
              queueFollowUpProcessPatch(activeJob.runId, {
                queueManaged: true,
                queueJobId: activeJob.jobId,
                queueState: 'slot_released',
                slotReserved: false,
                slotReleasedAt: now,
                slotReleaseReason: 'local_context_missing',
                ...stalePatch
              });
            }
            continue;
          }

          const nextActiveJob = sanitizeAnalysisQueueJob({
            ...activeJob,
            dispatchDeadlineAt: Number.isInteger(decision.dispatchDeadlineAt)
              ? decision.dispatchDeadlineAt
              : activeJob.dispatchDeadlineAt
          });
          if (!nextActiveJob) {
            continue;
          }

          const contextKey = getAnalysisQueueJobContextKey(nextActiveJob, process) || `run:${nextActiveJob.runId}`;
          const candidate = {
            job: nextActiveJob,
            process,
            activity: processActivity && typeof processActivity === 'object'
              ? processActivity
              : {
                active: false,
                live: false,
                recent: false,
                contextKey,
                reason: 'job_context'
              }
          };
          const existingEntry = nextActiveJobsByContext.get(contextKey);
          if (existingEntry) {
            const keepNext = shouldReplaceAnalysisQueueActiveJob(existingEntry, candidate);
            const keptEntry = keepNext ? candidate : existingEntry;
            const releasedEntry = keepNext ? existingEntry : candidate;
            nextActiveJobsByContext.set(contextKey, keptEntry);
            releaseJobs.push({
              job: releasedEntry.job,
              process: releasedEntry.process,
              reason: 'duplicate_context_superseded',
              closeWindow: false
            });
            if (releasedEntry.process) {
              queueFollowUpProcessPatch(releasedEntry.job.runId, {
                queueManaged: true,
                queueJobId: releasedEntry.job.jobId,
                queueState: 'slot_released',
                slotReserved: false,
                slotReleasedAt: now,
                slotReleaseReason: 'duplicate_context_superseded',
                status: 'stopped',
                statusText: 'Zduplikowany aktywny job kolejki - slot zwolniony',
                reason: 'duplicate_context_superseded',
                needsAction: false,
                autoRecovery: null,
                finishedAt: now,
                timestamp: now
              });
            }
            continue;
          }
          nextActiveJobsByContext.set(contextKey, candidate);
          if (process && typeof decision.queueState === 'string' && process.queueState !== decision.queueState) {
            queueFollowUpProcessPatch(activeJob.runId, {
              queueManaged: true,
              queueJobId: activeJob.jobId,
              queueState: decision.queueState,
              slotReserved: true,
              slotReservedAt: Number.isInteger(activeJob.slotReservedAt) ? activeJob.slotReservedAt : now,
              timestamp: now
            });
          }
        }

        state.activeJobs = Array.from(nextActiveJobsByContext.values()).map((entry) => entry.job);
        const releasedRunIds = new Set(
          releaseJobs
            .map((entry) => (typeof entry?.job?.runId === 'string' ? entry.job.runId.trim() : ''))
            .filter(Boolean)
        );
        const occupiedSlots = await collectAnalysisQueueActiveProcesses({
          processes: Array.from(processRegistry.values()),
          nowTs: now,
          excludedRunIds: releasedRunIds
        });
        let reservedSlots = occupiedSlots.length;
        sortAnalysisQueueWaitingJobs(state.waitingJobs);
        while (reservedSlots < state.maxConcurrent && state.waitingJobs.length > 0) {
          const waitingJob = state.waitingJobs.shift();
          const activatedJob = sanitizeAnalysisQueueJob({
            ...waitingJob,
            startedAt: now,
            slotReservedAt: now,
            dispatchDeadlineAt: null
          });
          if (!activatedJob) continue;
          state.activeJobs.push(activatedJob);
          startJobs.push(activatedJob);
          reservedSlots += 1;
        }

        await persistAnalysisQueueState(state);
      });

      const followUpProcessPatches = Array.from(followUpProcessPatchesByRunId.values());

      for (const update of followUpProcessPatches) {
        await upsertProcess(update.runId, update.patch);
      }

      for (const release of releaseJobs) {
        if (release.process) {
          const releaseQueueState = release.reason === 'dispatch_confirmed'
            ? 'dispatch_confirmed'
            : 'slot_released';
          const releasePatch = {
            queueManaged: true,
            queueJobId: release.job.jobId,
            queueState: releaseQueueState,
            slotReserved: false,
            slotReleasedAt: now,
            slotReleaseReason: release.reason,
            timestamp: now
          };
          if (release.reason === 'dispatch_pending') {
            releasePatch.reason = 'dispatch_pending';
            releasePatch.queueState = 'dispatch_pending';
          } else if (release.reason === 'local_save_failed') {
            releasePatch.reason = 'local_save_failed';
          } else if (release.reason === 'dispatch_skipped') {
            releasePatch.reason = 'dispatch_skipped';
          }
          await upsertProcess(release.job.runId, releasePatch);
          let windowClosed = null;
          if (release.closeWindow) {
            windowClosed = await closeProcessWindowAfterQueueSuccess(release.process);
          }
          const releaseProcess = processRegistry.get(release.job.runId) || release.process;
          releaseEventRecords.push({
            job: release.job,
            process: releaseProcess,
            reason: release.reason,
            closeWindowRequested: release.closeWindow === true,
            windowClosed
          });
        }
      }

      for (const startJob of startJobs) {
        await upsertProcess(startJob.runId, {
          queueManaged: true,
          queueJobId: startJob.jobId,
          queueState: 'active',
          slotReserved: true,
          slotReservedAt: Number.isInteger(startJob.slotReservedAt) ? startJob.slotReservedAt : now,
          slotReleasedAt: null,
          slotReleaseReason: '',
          statusText: 'Slot przydzielony, startuje',
          timestamp: now
        });
        runQueuedAnalysisJob(startJob, normalizedReason);
      }

      if (startJobs.length > 0 || releaseEventRecords.length > 0 || followUpProcessPatches.length > 0) {
        const queueLogSnapshot = await getAnalysisQueueStatusSnapshot().catch(() => null);
        await Promise.all(releaseEventRecords.map((releaseEvent) => {
          const currentProcess = releaseEvent.process || processRegistry.get(releaseEvent.job.runId) || null;
          const delivery = currentProcess ? getProcessQueueDeliveryState(currentProcess) : null;
          return reportAnalysisQueueEvent('job_released', {
            job: releaseEvent.job,
            process: currentProcess,
            status: releaseEvent.closeWindowRequested
              ? (releaseEvent.windowClosed === true ? 'released_closed' : 'released_close_pending')
              : 'released',
            reason: releaseEvent.reason,
            queueState: typeof currentProcess?.queueState === 'string'
              ? currentProcess.queueState
              : (releaseEvent.closeWindowRequested ? 'dispatch_confirmed' : 'slot_released'),
            waitingJobs: Number.isInteger(queueLogSnapshot?.waitingJobs) ? queueLogSnapshot.waitingJobs : null,
            activeSlots: Number.isInteger(queueLogSnapshot?.activeSlots) ? queueLogSnapshot.activeSlots : null,
            maxConcurrent: Number.isInteger(queueLogSnapshot?.maxConcurrent) ? queueLogSnapshot.maxConcurrent : null,
            slotReleaseReason: releaseEvent.reason,
            closeWindowRequested: releaseEvent.closeWindowRequested,
            closed: typeof releaseEvent.windowClosed === 'boolean' ? releaseEvent.windowClosed : null,
            dispatchState: delivery?.state || '',
            dispatchConfirmed: delivery?.confirmed === true,
            triggerReason: normalizedReason,
            title: 'Analysis queue: released job'
          }).catch((error) => {
            console.warn('[analysis-queue] release log failed:', {
              jobId: releaseEvent.job?.jobId || '',
              runId: releaseEvent.job?.runId || '',
              error: error?.message || String(error)
            });
          });
        }));

        await Promise.all(startJobs.map((startJob) => {
          const currentProcess = processRegistry.get(startJob.runId) || null;
          return reportAnalysisQueueEvent('job_started', {
            job: startJob,
            process: currentProcess,
            status: 'started',
            reason: normalizedReason,
            queueState: typeof currentProcess?.queueState === 'string' ? currentProcess.queueState : 'active',
            waitingJobs: Number.isInteger(queueLogSnapshot?.waitingJobs) ? queueLogSnapshot.waitingJobs : null,
            activeSlots: Number.isInteger(queueLogSnapshot?.activeSlots) ? queueLogSnapshot.activeSlots : null,
            maxConcurrent: Number.isInteger(queueLogSnapshot?.maxConcurrent) ? queueLogSnapshot.maxConcurrent : null,
            triggerReason: normalizedReason,
            title: 'Analysis queue: started job'
          }).catch((error) => {
            console.warn('[analysis-queue] start log failed:', {
              jobId: startJob?.jobId || '',
              runId: startJob?.runId || '',
              error: error?.message || String(error)
            });
          });
        }));

        await reportAnalysisQueueEvent('reconcile_summary', {
          status: 'reconciled',
          reason: normalizedReason,
          waitingJobs: Number.isInteger(queueLogSnapshot?.waitingJobs) ? queueLogSnapshot.waitingJobs : null,
          activeSlots: Number.isInteger(queueLogSnapshot?.activeSlots) ? queueLogSnapshot.activeSlots : null,
          maxConcurrent: Number.isInteger(queueLogSnapshot?.maxConcurrent) ? queueLogSnapshot.maxConcurrent : null,
          startedCount: startJobs.length,
          releasedCount: releaseEventRecords.length,
          updatedCount: followUpProcessPatches.length,
          triggerReason: normalizedReason,
          title: 'Analysis queue: reconcile summary'
        }).catch((error) => {
          console.warn('[analysis-queue] reconcile summary log failed:', {
            reason: normalizedReason,
            error: error?.message || String(error)
          });
        });
      }

      if (releaseEventRecords.length > 0) {
        requestRemoteRunnerCycle('analysis_queue_release');
      }

      if (!analysisQueueReconcileRequested) {
        break;
      }
    }

    return { success: true };
  } finally {
    analysisQueueReconcileInProgress = false;
    if (analysisQueueReconcileRequested) {
      requestAnalysisQueueReconcile(`follow_up:${normalizedReason}`);
    }
  }
}

function buildRestartReplayResponseId(runId = '', responseText = '', promptNumber = 0) {
  const safeRunId = typeof runId === 'string' && runId.trim()
    ? runId.trim().replace(/[^a-zA-Z0-9._-]/g, '_')
    : 'run';
  const safePromptNumber = Number.isInteger(promptNumber) && promptNumber > 0 ? promptNumber : 0;
  const fp = textFingerprint(responseText || '');
  return `${safeRunId}_restart_p${safePromptNumber}_${fp}`;
}

function extractAssistantTextFromProcess(process) {
  if (!process || typeof process !== 'object') return '';
  if (typeof process.completedResponseText === 'string' && process.completedResponseText.trim()) {
    return process.completedResponseText.trim();
  }
  const messages = Array.isArray(process.messages) ? process.messages : [];
  for (let i = messages.length - 1; i >= 0; i -= 1) {
    const message = messages[i];
    if (!message || message.role !== 'assistant') continue;
    const text = typeof message.text === 'string' ? message.text.trim() : '';
    if (text) return text;
  }
  return '';
}

function getCompletedProcessFinalityState(process) {
  const currentPrompt = Number.isInteger(process?.currentPrompt) ? process.currentPrompt : 0;
  const totalPrompts = Number.isInteger(process?.totalPrompts) ? process.totalPrompts : 0;
  const completedResponseText = typeof process?.completedResponseText === 'string'
    ? process.completedResponseText.trim()
    : '';
  const hasCompletedPayload = completedResponseText.length > 0;
  const promptComplete = totalPrompts > 0 && currentPrompt >= totalPrompts;
  return {
    currentPrompt,
    totalPrompts,
    completedResponseText,
    hasCompletedPayload,
    promptComplete,
    ready: hasCompletedPayload && promptComplete
  };
}

async function resolveCompletedProcessFinalResponseText(process, options = {}) {
  if (!process || typeof process !== 'object') {
    return {
      success: false,
      reason: 'invalid_process',
      finality: getCompletedProcessFinalityState(null)
    };
  }

  const force = options?.force === true;
  const finality = getCompletedProcessFinalityState(process);
  if (!force) {
    if (!finality.hasCompletedPayload) {
      return { success: false, reason: 'completed_response_missing', finality };
    }
    if (!finality.promptComplete) {
      return { success: false, reason: 'not_final_stage', finality };
    }
  }

  let responseText = finality.completedResponseText;
  if (!responseText && force) {
    responseText = extractAssistantTextFromProcess(process);
  }
  if (!responseText && force && options?.allowDomFallback === true && Number.isInteger(options?.tabId)) {
    responseText = await extractLastAssistantResponseFromTab(options.tabId, options?.tabReadTimeoutMs || 1800);
  }
  responseText = typeof responseText === 'string' ? responseText.trim() : '';
  if (!responseText) {
    return { success: false, reason: 'missing_response_text', finality };
  }

  const contract = buildResponseContractValidation(responseText);
  if (!force && contract?.valid !== true) {
    return {
      success: false,
      reason: 'invalid_final_response_contract',
      finality,
      contractKind: contract?.kind || 'invalid'
    };
  }

  return {
    success: true,
    responseText,
    finality,
    contractKind: contract?.kind || 'invalid',
    contract
  };
}

async function extractLastAssistantResponseFromTab(tabId, maxWaitMs = 1800) {
  if (!Number.isInteger(tabId)) return '';
  try {
    const results = await chrome.scripting.executeScript({
      target: { tabId },
      function: async (waitMs) => {
        const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
        const compact = (text) => (text || '').replace(/\s+/g, ' ').trim();

        function extractTextFromNode(node) {
          if (!node) return '';
          const clone = node.cloneNode(true);
          const removableSelectors = [
            '[data-testid="copy-turn-action-button"]',
            '[data-testid="message-actions"]',
            'button',
            'svg',
            'aside',
            'nav',
            'footer'
          ];
          removableSelectors.forEach((selector) => {
            clone.querySelectorAll(selector).forEach((child) => child.remove());
          });
          return compact(clone.innerText || clone.textContent || '');
        }

        function readAssistantText() {
          const byRole = Array.from(document.querySelectorAll('[data-message-author-role="assistant"]'));
          for (let i = byRole.length - 1; i >= 0; i -= 1) {
            const text = extractTextFromNode(byRole[i]);
            if (text) return text;
          }
          const conversationTurns = Array.from(document.querySelectorAll('[data-testid^="conversation-turn-"]'));
          for (let i = conversationTurns.length - 1; i >= 0; i -= 1) {
            const turn = conversationTurns[i];
            const candidate = turn.querySelector('[data-message-author-role="assistant"]') || turn;
            const text = extractTextFromNode(candidate);
            if (text) return text;
          }
          const articles = Array.from(document.querySelectorAll('article'));
          for (let i = articles.length - 1; i >= 0; i -= 1) {
            const text = extractTextFromNode(articles[i]);
            if (text) return text;
          }
          return '';
        }

        const startedAt = Date.now();
        let best = '';
        while ((Date.now() - startedAt) <= waitMs) {
          const candidate = readAssistantText();
          if (candidate.length > best.length) {
            best = candidate;
          }
          await sleep(220);
        }
        return best;
      },
      args: [Math.max(500, Math.min(maxWaitMs, 12000))]
    });
    const text = typeof results?.[0]?.result === 'string' ? results[0].result.trim() : '';
    return text;
  } catch (error) {
    return '';
  }
}

async function replayCompletedResponseForProcess(process, options = {}) {
  if (!process || typeof process !== 'object') {
    return { attempted: false, success: false, reason: 'invalid_process' };
  }

  const resolvedResponse = await resolveCompletedProcessFinalResponseText(process, {
    force: options?.force === true,
    tabId: options?.tabId,
    tabReadTimeoutMs: options?.tabReadTimeoutMs,
    allowDomFallback: options?.allowDomFallback === true
  });
  if (resolvedResponse?.success !== true) {
    return { attempted: false, success: false, reason: resolvedResponse?.reason || 'missing_response_text' };
  }

  const alreadySaved = process?.completedResponseSaved === true || process?.persistenceStatus?.saveOk === true;
  if (alreadySaved && options?.force !== true) {
    return { attempted: false, success: true, reason: 'already_saved' };
  }

  const runId = typeof process.id === 'string' ? process.id : '';
  const analysisType = typeof process.analysisType === 'string' && process.analysisType.trim()
    ? process.analysisType.trim()
    : 'company';
  const source = typeof process.title === 'string' && process.title.trim()
    ? process.title.trim()
    : 'Restart replay';

  const responseText = resolvedResponse.responseText;

  const existingTrace = typeof process.completedResponseSaveTrace === 'string' && process.completedResponseSaveTrace.trim()
    ? process.completedResponseSaveTrace.trim()
    : (typeof process?.persistenceStatus?.copyTrace === 'string' ? process.persistenceStatus.copyTrace.trim() : '');
  const responseIdFromTrace = extractResponseIdFromCopyTrace(existingTrace, runId);
  const promptNumber = Number.isInteger(process.currentPrompt) && process.currentPrompt > 0
    ? process.currentPrompt
    : (Number.isInteger(process.stageIndex) && process.stageIndex >= 0 ? (process.stageIndex + 1) : 0);
  const responseId = responseIdFromTrace || buildRestartReplayResponseId(runId, responseText, promptNumber);

  const stageMeta = {};
  if (promptNumber > 0) {
    stageMeta.selected_response_prompt = promptNumber;
  }
  if (Number.isInteger(process.stageIndex) && process.stageIndex >= 0) {
    stageMeta.selected_response_stage_index = process.stageIndex;
  } else if (promptNumber > 0) {
    stageMeta.selected_response_stage_index = promptNumber - 1;
  }
  stageMeta.selected_response_reason = 'restart_replay';

  const conversationUrl = normalizeChatConversationUrl(process.chatUrl)
    || normalizeChatConversationUrl(process.sourceUrl)
    || null;

  const saveResult = await saveResponse(
    responseText,
    source,
    analysisType,
    runId || null,
    responseId,
    stageMeta,
    conversationUrl,
    {
      sourceTitle: source,
      sourceName: resolveSupportedSourceNameFromUrl(
        typeof process?.sourceUrl === 'string' ? process.sourceUrl : ''
      ),
      sourceUrl: typeof process?.sourceUrl === 'string' ? process.sourceUrl : ''
    }
  );

  if (!saveResult?.success) {
    return {
      attempted: true,
      success: false,
      reason: 'save_response_failed',
      responseId,
      responseLength: responseText.length
    };
  }

  const dispatchSummary = formatDispatchUiSummary(saveResult.dispatch);
  return {
    attempted: true,
    success: true,
    reason: 'saved',
    responseId,
    responseLength: responseText.length,
    verifiedCount: Number.isInteger(saveResult?.verifiedCount) ? saveResult.verifiedCount : null,
    copyTrace: typeof saveResult.copyTrace === 'string' ? saveResult.copyTrace : '',
    dispatch: saveResult.dispatch && typeof saveResult.dispatch === 'object'
      ? saveResult.dispatch
      : null,
    dispatchProcessLog: Array.isArray(saveResult.dispatchProcessLog) ? saveResult.dispatchProcessLog.slice(-16) : [],
    conversationAnalysis: saveResult.conversationAnalysis && typeof saveResult.conversationAnalysis === 'object'
      ? saveResult.conversationAnalysis
      : null,
    dispatchSummary
  };
}

function summarizeFinalStagePersistence(result) {
  if (!result || typeof result !== 'object') return null;
  const dispatch = result?.dispatch && typeof result.dispatch === 'object'
    ? result.dispatch
    : null;
  const sent = Number.isInteger(dispatch?.sent) ? dispatch.sent : null;
  const failed = Number.isInteger(dispatch?.failed) ? dispatch.failed : null;
  const deferred = Number.isInteger(dispatch?.deferred) ? dispatch.deferred : null;
  const remaining = Number.isInteger(dispatch?.remaining) ? dispatch.remaining : null;
  const failureStage = typeof dispatch?.failureStage === 'string' && dispatch.failureStage.trim()
    ? dispatch.failureStage.trim()
    : '';
  const failureReason = typeof dispatch?.failureReason === 'string' && dispatch.failureReason.trim()
    ? dispatch.failureReason.trim()
    : '';
  const failureStatus = Number.isInteger(dispatch?.failureStatus) ? dispatch.failureStatus : null;
  const failureRequestId = typeof dispatch?.failureRequestId === 'string' && dispatch.failureRequestId.trim()
    ? dispatch.failureRequestId.trim()
    : '';
  const failureIntakeUrl = typeof dispatch?.failureIntakeUrl === 'string' && dispatch.failureIntakeUrl.trim()
    ? dispatch.failureIntakeUrl.trim()
    : '';
  const conversationAnalysis = result?.conversationAnalysis && typeof result.conversationAnalysis === 'object'
    ? result.conversationAnalysis
    : null;
  const conversationLogCountRaw = Number.isInteger(dispatch?.conversationLogCount)
    ? dispatch.conversationLogCount
    : (Number.isInteger(conversationAnalysis?.conversationLogCount) ? conversationAnalysis.conversationLogCount : null);
  const conversationLogCount = Number.isInteger(conversationLogCountRaw)
    ? Math.max(0, conversationLogCountRaw)
    : null;
  const hasConversationUrl = dispatch?.hasConversationUrl === true || conversationAnalysis?.hasConversationUrl === true;
  const conversationSnapshotRefreshed = dispatch?.conversationSnapshotRefreshed === true
    || conversationAnalysis?.snapshotRefreshedBeforeSend === true;
  const conversationSnapshotSource = (typeof dispatch?.conversationSnapshotSource === 'string' && dispatch.conversationSnapshotSource.trim())
    ? dispatch.conversationSnapshotSource.trim()
    : (typeof conversationAnalysis?.snapshotSource === 'string' ? conversationAnalysis.snapshotSource.trim() : '');
  const state = typeof dispatch?.state === 'string' && dispatch.state.trim()
    ? dispatch.state.trim()
    : '';
  return {
    attempted: result.attempted === true,
    success: result.success === true,
    reason: typeof result.reason === 'string' ? result.reason : '',
    responseId: typeof result.responseId === 'string' ? result.responseId : '',
    copyTrace: typeof result.copyTrace === 'string' ? result.copyTrace : '',
    dispatchSummary: typeof result.dispatchSummary === 'string' ? result.dispatchSummary : '',
    verifiedCount: Number.isInteger(result?.verifiedCount) ? result.verifiedCount : null,
    sent,
    failed,
    deferred,
    remaining,
    pending: (deferred ?? 0) + (remaining ?? 0),
    queueSkipped: dispatch?.queueSkipped === true,
    queueSkipReason: typeof dispatch?.queueSkipReason === 'string' ? dispatch.queueSkipReason : '',
    flushSkipped: dispatch?.flushSkipped === true,
    flushSkipReason: typeof dispatch?.flushSkipReason === 'string' ? dispatch.flushSkipReason : '',
    flushFollowUpScheduled: dispatch?.flushFollowUpScheduled === true,
    failureStage,
    failureReason,
    failureStatus,
    failureRequestId,
    failureIntakeUrl,
    conversationLogCount,
    hasConversationUrl,
    conversationSnapshotRefreshed,
    conversationSnapshotSource,
    state
  };
}

async function ensureCompletedProcessResponsePersisted(process, options = {}) {
  if (!process || typeof process !== 'object') {
    return { attempted: false, success: false, reason: 'invalid_process' };
  }

  const runId = typeof process?.id === 'string' ? process.id.trim() : '';
  const tabId = Number.isInteger(options?.tabId)
    ? options.tabId
    : (Number.isInteger(process?.tabId) ? process.tabId : null);
  const force = options?.force === true;
  const allowDomFallback = options?.allowDomFallback === true || (force && options?.allowDomFallback !== false);
  const origin = typeof options?.origin === 'string' && options.origin.trim()
    ? options.origin.trim()
    : 'resume_final_stage_persist_check';

  let replayResult = null;
  try {
    replayResult = await replayCompletedResponseForProcess(process, {
      force,
      tabId,
      tabReadTimeoutMs: Number.isInteger(options?.tabReadTimeoutMs) ? options.tabReadTimeoutMs : 2200,
      allowDomFallback
    });
  } catch (error) {
    replayResult = {
      attempted: false,
      success: false,
      reason: error?.message || String(error)
    };
  }

  if (!runId) {
    return replayResult;
  }

  const now = Date.now();
  const patch = {
    finalStagePersistence: {
      ...summarizeFinalStagePersistence(replayResult),
      origin,
      forced: force,
      updatedAt: now
    },
    timestamp: now
  };

  if (replayResult?.attempted && replayResult?.success) {
    patch.completedResponseSaved = true;
    if (typeof replayResult.copyTrace === 'string' && replayResult.copyTrace.trim()) {
      patch.completedResponseSaveTrace = replayResult.copyTrace.trim();
    }
    if (replayResult.dispatch && typeof replayResult.dispatch === 'object') {
      patch.completedResponseDispatch = replayResult.dispatch;
      patch.completedResponseDispatchSummary = replayResult.dispatchSummary || formatDispatchUiSummary(replayResult.dispatch);
      patch.completedResponseDispatchProcessLog = Array.isArray(replayResult.dispatchProcessLog)
        ? replayResult.dispatchProcessLog.slice(-16)
        : [];
    }
    const previousStatus = process?.persistenceStatus && typeof process.persistenceStatus === 'object'
      ? process.persistenceStatus
      : {};
    patch.persistenceStatus = {
      ...previousStatus,
      hasResponse: true,
      saveOk: true,
      dispatchSummary: replayResult.dispatchSummary || formatDispatchUiSummary(replayResult.dispatch),
      copyTrace: replayResult.copyTrace || '',
      saveError: '',
      dispatch: replayResult.dispatch || null,
      dispatchProcessLog: Array.isArray(replayResult.dispatchProcessLog)
        ? replayResult.dispatchProcessLog.slice(-16)
        : [],
      updatedAt: now
    };
  }

  await upsertProcess(runId, patch);
  return replayResult;
}

async function stopSingleProcess(process, options = {}) {
  if (!process || isClosedProcessStatus(process.status)) return false;

  const runId = process.id;
  if (!runId) return false;

  const reason = typeof options.reason === 'string' && options.reason.trim()
    ? options.reason.trim()
    : 'manual_stop';
  const statusText = typeof options.statusText === 'string' && options.statusText.trim()
    ? options.statusText.trim()
    : 'Przerwano przez uzytkownika';
  const now = Date.now();

  const preserveWindowId = Number.isInteger(options.preserveWindowId)
    ? options.preserveWindowId
    : null;
  const processWindowId = Number.isInteger(process.windowId) ? process.windowId : null;
  const processTabId = Number.isInteger(process.tabId) ? process.tabId : null;
  const replayOnRestart = options?.replayLatestResponse === true
    || reason === 'restarted_in_same_window';
  const forceReplayLatestResponse = options?.forceReplayLatestResponse === true;
  let replayResult = null;

  if (reason === 'restarted_in_same_window' && processTabId !== null) {
    const restartUngroup = await ungroupTabsById([processTabId], {
      origin: 'restart-stop-single-process'
    });
    if (!restartUngroup.ok && restartUngroup.reason !== 'already_ungrouped') {
      console.warn('[restart] ungroup process tab failed:', {
        runId,
        tabId: processTabId,
        reason: restartUngroup.reason,
        error: restartUngroup.error || ''
      });
    }
  }

  if (replayOnRestart) {
    replayResult = await replayCompletedResponseForProcess(process, {
      force: forceReplayLatestResponse,
      tabId: processTabId,
      tabReadTimeoutMs: 1800
    });
    console.log('[restart] replay-last-response', {
      runId,
      attempted: replayResult?.attempted === true,
      success: replayResult?.success === true,
      reason: replayResult?.reason || '',
      responseId: replayResult?.responseId || '',
      copyTrace: replayResult?.copyTrace || ''
    });
  }

  if (processTabId !== null) {
    await requestProcessForceStopOnTab(processTabId, {
      runId,
      reason,
      origin: options.origin || 'background'
    });
  }

  let tabClosed = false;
  if (processTabId !== null) {
    tabClosed = await removeTabSafe(processTabId);
  }

  // Fallback: close the whole window only when it is a dedicated process window
  // with no extra tabs (to avoid closing source/info windows).
  if (!tabClosed && processWindowId !== null && processWindowId !== preserveWindowId) {
    const tabsInWindow = await queryTabsInWindowSafe(processWindowId);
    const validTabs = Array.isArray(tabsInWindow?.tabs)
      ? tabsInWindow.tabs.filter((tab) => Number.isInteger(tab?.id))
      : [];
    const hasOnlyProcessTab = validTabs.length === 1
      && processTabId !== null
      && validTabs[0].id === processTabId;
    if (hasOnlyProcessTab) {
      await removeWindowSafe(processWindowId);
    }
  }

  const stopPatch = {
    status: 'stopped',
    statusText,
    reason,
    needsAction: false,
    finishedAt: now,
    timestamp: now
  };

  if (replayResult?.attempted) {
    stopPatch.restartReplay = {
      attempted: true,
      success: replayResult?.success === true,
      reason: replayResult?.reason || '',
      responseId: replayResult?.responseId || '',
      copyTrace: replayResult?.copyTrace || '',
      updatedAt: now
    };
  }

  if (replayResult?.attempted && replayResult?.success) {
    stopPatch.completedResponseSaved = true;
    if (typeof replayResult.copyTrace === 'string' && replayResult.copyTrace.trim()) {
      stopPatch.completedResponseSaveTrace = replayResult.copyTrace.trim();
    }
    if (replayResult.dispatch && typeof replayResult.dispatch === 'object') {
      stopPatch.completedResponseDispatch = replayResult.dispatch;
      stopPatch.completedResponseDispatchSummary = replayResult.dispatchSummary || formatDispatchUiSummary(replayResult.dispatch);
    }
    const previousStatus = process?.persistenceStatus && typeof process.persistenceStatus === 'object'
      ? process.persistenceStatus
      : {};
    stopPatch.persistenceStatus = {
      ...previousStatus,
      hasResponse: true,
      saveOk: true,
      dispatchSummary: replayResult.dispatchSummary || formatDispatchUiSummary(replayResult.dispatch),
      copyTrace: replayResult.copyTrace || '',
      saveError: '',
      dispatch: replayResult.dispatch || null,
      updatedAt: now
    };
  }

  await upsertProcess(runId, stopPatch);

  if (process?.remote?.remoteJobId && process?.remote?.remoteAttemptId) {
    const failure = buildRemoteJobFailureDetails(
      {
        jobId: process.remote.remoteJobId,
        runId,
        title: process?.title || '',
        promptHash: typeof process?.promptHash === 'string' ? process.promptHash : '',
        remote: process.remote
      },
      {
        ...process,
        reason,
        status: 'stopped',
        error: typeof process?.error === 'string' ? process.error : ''
      },
      null,
      statusText,
      reason
    );
    await reportRemoteJobEvent(
      process.remote.remoteJobId,
      'failed',
      process.remote.remoteAttemptId,
      failure.payload,
      failure.error
    ).catch((error) => {
      console.warn('[remote-runner] failed to report manual stop:', {
        jobId: process.remote.remoteJobId,
        attemptId: process.remote.remoteAttemptId,
        error: error?.message || String(error)
      });
    });
  }

  return true;
}

async function stopActiveProcesses(options = {}) {
  await ensureProcessRegistryReady();
  const targetWindowId = Number.isInteger(options.windowId) ? options.windowId : null;
  const preserveWindowId = Number.isInteger(options.preserveWindowId) ? options.preserveWindowId : null;
  let cancelledQueued = 0;

  if (Number.isInteger(targetWindowId)) {
    const cancelled = await cancelQueuedAnalysisJobs((job) => (
      Number.isInteger(job?.invocationWindowId) && job.invocationWindowId === targetWindowId
    ) || (
      Number.isInteger(job?.sourceWindowId) && job.sourceWindowId === targetWindowId
    ) || (
      Number.isInteger(job?.tabSnapshot?.windowId) && job.tabSnapshot.windowId === targetWindowId
    ) || (
      Number.isInteger(job?.resumeTargetWindowId) && job.resumeTargetWindowId === targetWindowId
    ), {
      reason: typeof options?.reason === 'string' && options.reason.trim()
        ? `${options.reason.trim()}_queued_cancelled`
        : 'stop_window_queued_cancelled',
      statusText: typeof options?.statusText === 'string' && options.statusText.trim()
        ? `${options.statusText.trim()} (kolejka)`
        : 'Anulowano oczekujace joby'
    });
    cancelledQueued = Number.isInteger(cancelled?.cancelledCount) ? cancelled.cancelledCount : 0;
  }

  const candidates = Array.from(processRegistry.values()).filter((process) => {
    if (!process || isClosedProcessStatus(process.status)) return false;
    return matchesWindowScope(process, targetWindowId);
  });

  let stopped = 0;
  for (const process of candidates) {
    const didStop = await stopSingleProcess(process, {
      reason: options.reason,
      statusText: options.statusText,
      origin: options.origin,
      preserveWindowId,
      replayLatestResponse: options?.replayLatestResponse === true,
      forceReplayLatestResponse: options?.forceReplayLatestResponse === true
    });
    if (didStop) stopped += 1;
  }

  return {
    matched: candidates.length,
    stopped,
    cancelledQueued,
    windowId: targetWindowId
  };
}

function queryTabsInWindowSafe(windowId) {
  return new Promise((resolve) => {
    if (!Number.isInteger(windowId)) {
      resolve({ ok: false, tabs: [], reason: 'invalid_window_id' });
      return;
    }

    try {
      chrome.tabs.query({ windowId }, (tabs) => {
        if (chrome.runtime.lastError) {
          resolve({
            ok: false,
            tabs: [],
            reason: chrome.runtime.lastError.message || 'runtime_error'
          });
          return;
        }
        resolve({
          ok: true,
          tabs: Array.isArray(tabs) ? tabs : [],
          reason: ''
        });
      });
    } catch (error) {
      resolve({
        ok: false,
        tabs: [],
        reason: error?.message || String(error)
      });
    }
  });
}

async function forceReloadWindowTabs(windowId, options = {}) {
  const timeoutMs = Number.isInteger(options.timeoutMs) && options.timeoutMs > 0
    ? options.timeoutMs
    : 15000;
  const bypassCache = options.bypassCache !== false;
  const skipTabIds = options?.skipTabIds instanceof Set ? options.skipTabIds : new Set();
  const queryResult = await queryTabsInWindowSafe(windowId);

  if (!queryResult.ok) {
    return {
      ok: false,
      windowId,
      totalTabs: 0,
      attemptedTabIds: [],
      reloadedTabs: 0,
      failedTabs: 0,
      reason: queryResult.reason || 'query_tabs_failed'
    };
  }

  const tabs = Array.isArray(queryResult.tabs) ? queryResult.tabs : [];
  const attemptedTabIds = [];
  let reloadedTabs = 0;
  let failedTabs = 0;

  for (const tab of tabs) {
    const tabId = Number.isInteger(tab?.id) ? tab.id : null;
    if (tabId === null || skipTabIds.has(tabId)) continue;

    attemptedTabIds.push(tabId);
    const reloadResult = await forceReloadTab(tabId, { timeoutMs, bypassCache });
    if (reloadResult?.ok) {
      reloadedTabs += 1;
    } else {
      failedTabs += 1;
    }
  }

  return {
    ok: true,
    windowId,
    totalTabs: tabs.length,
    attemptedTabIds,
    reloadedTabs,
    failedTabs,
    reason: ''
  };
}

async function forceStopAndReloadProcessContext(process, options = {}) {
  const timeoutMs = Number.isInteger(options.timeoutMs) && options.timeoutMs > 0
    ? options.timeoutMs
    : 15000;
  const bypassCache = options.bypassCache !== false;
  const reloadedWindowIds = options?.reloadedWindowIds instanceof Set
    ? options.reloadedWindowIds
    : new Set();
  const seenTabIds = new Set();
  const processTabId = Number.isInteger(process?.tabId) ? process.tabId : null;
  const processWindowId = Number.isInteger(process?.windowId) ? process.windowId : null;

  let tabReloads = 0;
  let tabReloadFailures = 0;
  let windowReloads = 0;
  let windowReloadFailures = 0;

  if (processTabId !== null) {
    seenTabIds.add(processTabId);
    const reloadResult = await forceReloadTab(processTabId, { timeoutMs, bypassCache });
    if (reloadResult?.ok) {
      tabReloads += 1;
    } else {
      tabReloadFailures += 1;
    }
  }

  if (processWindowId !== null && !reloadedWindowIds.has(processWindowId)) {
    reloadedWindowIds.add(processWindowId);

    const windowReloadResult = await forceReloadWindowTabs(processWindowId, {
      timeoutMs,
      bypassCache,
      skipTabIds: seenTabIds
    });

    if (windowReloadResult.ok) {
      windowReloads += 1;
      tabReloads += windowReloadResult.reloadedTabs;
      tabReloadFailures += windowReloadResult.failedTabs;
    } else {
      windowReloadFailures += 1;
    }
  }

  return {
    tabReloads,
    tabReloadFailures,
    windowReloads,
    windowReloadFailures
  };
}

async function resetTrackedProcessesForBulkRun(options = {}) {
  await ensureProcessRegistryReady();

  const clearHistory = options?.clearHistory !== false;
  const reason = typeof options?.reason === 'string' && options.reason.trim()
    ? options.reason.trim()
    : 'bulk_reset_before_detect_resume';
  const statusText = typeof options?.statusText === 'string' && options.statusText.trim()
    ? options.statusText.trim()
    : 'Reset przed globalnym uruchomieniem';
  const origin = typeof options?.origin === 'string' && options.origin.trim()
    ? options.origin.trim()
    : 'bulk-reset';
  const now = Date.now();

  const currentRecords = pruneProcessRecords(Array.from(processRegistry.values()));
  const nextRecords = [];

  let activeBefore = 0;
  let resetCount = 0;
  let historyRetained = 0;
  let stopSignalsSent = 0;
  let stopSignalsAcked = 0;
  let tabReloads = 0;
  let tabReloadFailures = 0;
  let windowReloads = 0;
  let windowReloadFailures = 0;
  const reloadedWindowIds = new Set();

  for (const process of currentRecords) {
    if (!process || typeof process !== 'object') continue;
    const isActive = !isClosedProcessStatus(process.status);

    if (isActive) {
      activeBefore += 1;

      // Try graceful stop first; fallback to tab reload to hard-stop injected execution.
      if (Number.isInteger(process.tabId)) {
        const stopResult = await requestProcessForceStopOnTab(process.tabId, {
          runId: process.id,
          reason,
          origin
        });
        if (stopResult.sent) {
          stopSignalsSent += 1;
        }
        if (stopResult.acknowledged) {
          stopSignalsAcked += 1;
        }
      }

      // Always force a reload of process context during reset.
      // This guarantees that in-tab execution is interrupted even when force-stop was acknowledged.
      const reloadSummary = await forceStopAndReloadProcessContext(process, {
        timeoutMs: 15000,
        bypassCache: true,
        reloadedWindowIds
      });
      tabReloads += reloadSummary.tabReloads;
      tabReloadFailures += reloadSummary.tabReloadFailures;
      windowReloads += reloadSummary.windowReloads;
      windowReloadFailures += reloadSummary.windowReloadFailures;

      const resetRecord = normalizeProcessRecord({
        ...process,
        status: 'stopped',
        statusText,
        reason,
        needsAction: false,
        autoRecovery: null,
        finishedAt: Number.isInteger(process.finishedAt) ? process.finishedAt : now,
        timestamp: now
      });
      if (resetRecord) {
        nextRecords.push(resetRecord);
        resetCount += 1;
      }
      continue;
    }

    if (!clearHistory) {
      nextRecords.push(process);
      historyRetained += 1;
    }
  }

  processRegistry.clear();
  nextRecords.forEach((record) => {
    if (record?.id) processRegistry.set(record.id, record);
  });

  await persistProcessRegistry();
  await broadcastProcessUpdate();

  return {
    clearHistory,
    activeBefore,
    resetCount,
    historyRetained,
    stopSignalsSent,
    stopSignalsAcked,
    tabReloads,
    tabReloadFailures,
    windowReloads,
    windowReloadFailures,
    uniqueWindowsReloaded: reloadedWindowIds.size,
    totalAfter: nextRecords.length
  };
}

function applyMonotonicProcessPatch(existing, patch, message = null) {
  if (!patch || typeof patch !== 'object') return patch;
  if (!existing || typeof existing !== 'object') return patch;

  const next = { ...patch };
  const incomingStatus = normalizeProcessStatus(next.status || existing.status);
  const incomingClosed = isClosedProcessStatus(incomingStatus);
  const existingClosed = isClosedProcessStatus(existing.status);
  const allowLowerProgress = !!message?.allowLowerProgress || incomingClosed;

  if (existingClosed && !incomingClosed) {
    next.status = existing.status;
    next.needsAction = false;
  }

  if (Number.isInteger(existing.totalPrompts) && Number.isInteger(next.totalPrompts)) {
    if (next.totalPrompts < existing.totalPrompts && !incomingClosed) {
      next.totalPrompts = existing.totalPrompts;
    }
  }

  if (Number.isInteger(existing.currentPrompt) && Number.isInteger(next.currentPrompt)) {
    if (next.currentPrompt < existing.currentPrompt && !allowLowerProgress) {
      next.currentPrompt = existing.currentPrompt;
    }
  }

  if (Number.isInteger(existing.stageIndex) && Number.isInteger(next.stageIndex)) {
    if (next.stageIndex < existing.stageIndex && !allowLowerProgress) {
      next.stageIndex = existing.stageIndex;
    }
  }

  if (!Number.isInteger(next.currentPrompt) && Number.isInteger(next.stageIndex) && next.stageIndex >= 0) {
    next.currentPrompt = next.stageIndex + 1;
  }
  if (!Number.isInteger(next.stageIndex) && Number.isInteger(next.currentPrompt) && next.currentPrompt > 0) {
    next.stageIndex = next.currentPrompt - 1;
  }
  if (Number.isInteger(next.currentPrompt) && Number.isInteger(next.stageIndex)) {
    const promptFromStage = next.stageIndex + 1;
    if (next.currentPrompt < promptFromStage) {
      next.currentPrompt = promptFromStage;
    }
    const stageFromPrompt = next.currentPrompt - 1;
    if (next.stageIndex < stageFromPrompt) {
      next.stageIndex = stageFromPrompt;
    }
  }
  if (Number.isInteger(next.currentPrompt) && next.currentPrompt > 0) {
    const normalizedPromptStageName = `Prompt ${next.currentPrompt}`;
    if (typeof next.stageName !== 'string' || /^Prompt\s+\d+/i.test(next.stageName.trim())) {
      next.stageName = normalizedPromptStageName;
    }
  }

  return next;
}

function extractPromptProgressFromChatTitle(rawTitle, promptCount = 0) {
  const title = typeof rawTitle === 'string' ? rawTitle.trim() : '';
  if (!title) {
    return { currentPrompt: null, totalPrompts: null };
  }

  const bracketMatch = title.match(/\bP\s*(\d+)\s*\/\s*(\d+)\b/i);
  const promptOnlyMatch = bracketMatch ? null : title.match(/\bPrompt\s+(\d+)\b/i);
  let currentPrompt = bracketMatch
    ? Number.parseInt(bracketMatch[1], 10)
    : (promptOnlyMatch ? Number.parseInt(promptOnlyMatch[1], 10) : null);
  let totalPrompts = bracketMatch ? Number.parseInt(bracketMatch[2], 10) : null;

  if (!Number.isInteger(currentPrompt) || currentPrompt <= 0) currentPrompt = null;
  if (!Number.isInteger(totalPrompts) || totalPrompts <= 0) totalPrompts = null;

  if (Number.isInteger(promptCount) && promptCount > 0) {
    if (Number.isInteger(currentPrompt) && currentPrompt > promptCount) currentPrompt = promptCount;
    if (Number.isInteger(totalPrompts) && totalPrompts > promptCount) totalPrompts = promptCount;
  }

  return { currentPrompt, totalPrompts };
}

function resolveCompanyConversationAuditPromptFrontier(options = {}) {
  const promptCount = Number.isInteger(options?.promptCount) && options.promptCount > 0
    ? options.promptCount
    : 0;
  const candidates = [];
  const recognizedPromptNumbers = Array.isArray(options?.recognizedPromptNumbers)
    ? options.recognizedPromptNumbers
    : [];

  recognizedPromptNumbers.forEach((value) => {
    if (Number.isInteger(value) && value > 0) candidates.push(value);
  });

  const activePrompt = Number.isInteger(options?.activeProcessPromptNumber) && options.activeProcessPromptNumber > 0
    ? options.activeProcessPromptNumber
    : null;
  if (activePrompt !== null) candidates.push(activePrompt);

  const scannedTitleProgress = extractPromptProgressFromChatTitle(options?.scannedTitle || '', promptCount);
  if (Number.isInteger(scannedTitleProgress.currentPrompt)) candidates.push(scannedTitleProgress.currentPrompt);

  const tabTitleProgress = extractPromptProgressFromChatTitle(options?.targetTabTitle || '', promptCount);
  if (Number.isInteger(tabTitleProgress.currentPrompt)) candidates.push(tabTitleProgress.currentPrompt);

  if (candidates.length === 0) return 0;
  const frontier = Math.max(...candidates);
  if (!Number.isInteger(promptCount) || promptCount <= 0) return frontier;
  return Math.max(0, Math.min(frontier, promptCount));
}

function filterCompanyConversationMissingPromptNumbers(promptNumbers, recognizedPromptSet, frontierPromptNumber) {
  const recognized = recognizedPromptSet && typeof recognizedPromptSet.has === 'function'
    ? recognizedPromptSet
    : new Set(Array.isArray(recognizedPromptSet) ? recognizedPromptSet : []);
  const frontier = Number.isInteger(frontierPromptNumber) && frontierPromptNumber > 0
    ? frontierPromptNumber
    : 0;
  if (frontier <= 0) return [];

  return (Array.isArray(promptNumbers) ? promptNumbers : [])
    .filter((promptNumber) => (
      Number.isInteger(promptNumber)
      && promptNumber > 0
      && promptNumber <= frontier
      && !recognized.has(promptNumber)
    ));
}

function isCompanyConversationActiveProcess(process) {
  if (!process || typeof process !== 'object') return false;
  return normalizeProcessStatus(process.status || '') === 'running' && process.needsAction !== true;
}

function isCompanyConversationFrontierPromptPending(promptNumber, activeProcess, frontierPromptNumber) {
  if (!Number.isInteger(promptNumber) || promptNumber <= 0) return false;
  if (!Number.isInteger(frontierPromptNumber) || frontierPromptNumber <= 0) return false;
  if (promptNumber !== frontierPromptNumber) return false;
  if (!isCompanyConversationActiveProcess(activeProcess)) return false;
  return Number.isInteger(activeProcess?.currentPrompt) && activeProcess.currentPrompt === frontierPromptNumber;
}

async function handleProcessProgressMessage(message, sender) {
  const runId = await resolveProcessId(message, sender);
  if (!runId) return false;

  const nowTs = Date.now();
  const explicitLifecycleStatus = normalizeProcessLifecycleStatus(
    message?.lifecycleStatus || message?.status,
    'running'
  );
  const explicitActionRequired = normalizeProcessActionRequired(
    message?.actionRequired,
    deriveProcessActionRequired(message || {})
  );
  const patch = {
    timestamp: nowTs,
    lastProgressAt: nowTs,
    lastActivityAt: nowTs,
    lifecycleStatus: explicitLifecycleStatus,
    status: explicitLifecycleStatus,
    actionRequired: explicitActionRequired,
    needsAction: explicitActionRequired !== 'none'
  };

  if (typeof message?.phase === 'string' && message.phase.trim()) patch.phase = message.phase.trim();
  if (typeof message?.statusCode === 'string' && message.statusCode.trim()) patch.statusCode = message.statusCode.trim();
  if (Number.isInteger(message?.currentPrompt)) patch.currentPrompt = message.currentPrompt;
  if (Number.isInteger(message?.totalPrompts)) patch.totalPrompts = message.totalPrompts;
  if (typeof message?.statusText === 'string') patch.statusText = message.statusText;
  if (typeof message?.reason === 'string') patch.reason = message.reason;
  if (Number.isInteger(message?.stageIndex)) patch.stageIndex = message.stageIndex;
  if (typeof message?.stageName === 'string') patch.stageName = message.stageName;
  const conversationUrl = resolveProcessConversationUrlFromMessage(message, sender);
  if (conversationUrl) patch.chatUrl = conversationUrl;
  if (typeof message?.sourceUrl === 'string') patch.sourceUrl = message.sourceUrl;
  if (typeof message?.analysisType === 'string' && message.analysisType.trim()) patch.analysisType = message.analysisType.trim();
  if (typeof message?.title === 'string' && message.title.trim()) patch.title = message.title.trim();
  if (Number.isInteger(message?.tabId)) patch.tabId = message.tabId;
  if (Number.isInteger(message?.windowId)) patch.windowId = message.windowId;

  await ensureProcessRegistryReady();
  const existing = processRegistry.get(runId) || null;
  const safePatch = applyMonotonicProcessPatch(existing, patch, message);
  await upsertProcess(runId, safePatch);
  return true;
}

async function handleProcessNeedsActionMessage(message, sender) {
  const runId = await resolveProcessId(message, sender);
  if (!runId) return false;
  const nowTs = Date.now();
  const explicitActionRequired = normalizeProcessActionRequired(
    message?.actionRequired,
    deriveProcessActionRequired({
      ...message,
      needsAction: true
    })
  );
  const patch = {
    lifecycleStatus: normalizeProcessLifecycleStatus(message?.lifecycleStatus || 'running', 'running'),
    status: normalizeProcessLifecycleStatus(message?.lifecycleStatus || 'running', 'running'),
    needsAction: true,
    actionRequired: explicitActionRequired === 'none' ? 'manual_resume' : explicitActionRequired,
    timestamp: nowTs,
    lastActivityAt: nowTs,
    lastProgressAt: nowTs
  };
  if (Number.isInteger(message?.currentPrompt)) patch.currentPrompt = message.currentPrompt;
  if (Number.isInteger(message?.totalPrompts)) patch.totalPrompts = message.totalPrompts;
  if (Number.isInteger(message?.stageIndex)) patch.stageIndex = message.stageIndex;
  if (typeof message?.stageName === 'string') patch.stageName = message.stageName;
  if (typeof message?.phase === 'string') patch.phase = message.phase;
  if (typeof message?.statusCode === 'string') patch.statusCode = message.statusCode;
  if (typeof message?.statusText === 'string') patch.statusText = message.statusText;
  if (typeof message?.reason === 'string') patch.reason = message.reason;
  const conversationUrl = resolveProcessConversationUrlFromMessage(message, sender);
  if (conversationUrl) patch.chatUrl = conversationUrl;
  if (typeof message?.analysisType === 'string' && message.analysisType.trim()) patch.analysisType = message.analysisType.trim();
  if (typeof message?.title === 'string' && message.title.trim()) patch.title = message.title.trim();
  if (Number.isInteger(message?.tabId)) patch.tabId = message.tabId;
  if (Number.isInteger(message?.windowId)) patch.windowId = message.windowId;
  await ensureProcessRegistryReady();
  const existing = processRegistry.get(runId) || null;
  const safePatch = applyMonotonicProcessPatch(existing, patch, message);
  await upsertProcess(runId, safePatch);
  return true;
}

function getDecisionResolvedStatusText(decision) {
  return decision === 'skip' ? 'Pominieto czekanie' : 'Wznowiono czekanie';
}

async function handleProcessActionResolvedMessage(message, sender) {
  const runId = await resolveProcessId(message, sender);
  if (!runId) return false;
  const decision = message?.decision === 'skip' ? 'skip' : 'wait';
  const nowTs = Date.now();
  const patch = {
    lifecycleStatus: 'running',
    status: 'running',
    needsAction: false,
    actionRequired: 'none',
    reason: '',
    statusCode: decision === 'skip' ? 'process.manual_resume_resolved' : 'process.wait_resolved',
    statusText: getDecisionResolvedStatusText(decision),
    timestamp: nowTs,
    lastActivityAt: nowTs,
    lastProgressAt: nowTs
  };
  const conversationUrl = resolveProcessConversationUrlFromMessage(message, sender);
  if (conversationUrl) patch.chatUrl = conversationUrl;
  if (typeof message?.analysisType === 'string' && message.analysisType.trim()) patch.analysisType = message.analysisType.trim();
  if (typeof message?.title === 'string' && message.title.trim()) patch.title = message.title.trim();
  if (Number.isInteger(message?.tabId)) patch.tabId = message.tabId;
  if (Number.isInteger(message?.windowId)) patch.windowId = message.windowId;
  await upsertProcess(runId, patch);
  return true;
}

async function handleProcessDecisionMessage(message) {
  const runId = await resolveProcessId(message, { tab: { id: message?.tabId } });
  if (!runId) return false;

  await ensureProcessRegistryReady();
  const process = processRegistry.get(runId) || null;
  const decision = message?.decision === 'skip' ? 'skip' : 'wait';

  const targetTabId = Number.isInteger(message?.tabId)
    ? message.tabId
    : (Number.isInteger(process?.tabId) ? process.tabId : null);

  let forwarded = false;
  if (Number.isInteger(targetTabId)) {
    try {
      await chrome.tabs.sendMessage(targetTabId, {
        type: 'PROCESS_DECISION',
        runId,
        decision,
        origin: message?.origin || 'panel'
      });
      forwarded = true;
    } catch (error) {
      console.warn('[monitor] Unable to forward PROCESS_DECISION to tab:', targetTabId, error?.message || error);
    }
  }

  if (forwarded) {
    const patch = {
      status: isClosedProcessStatus(process?.status) ? process.status : 'running',
      needsAction: false,
      reason: '',
      statusText: getDecisionResolvedStatusText(decision),
      timestamp: Date.now()
    };
    if (typeof message?.analysisType === 'string' && message.analysisType.trim()) patch.analysisType = message.analysisType.trim();
    if (typeof message?.title === 'string' && message.title.trim()) patch.title = message.title.trim();
    if (Number.isInteger(message?.tabId)) patch.tabId = message.tabId;
    if (Number.isInteger(message?.windowId)) patch.windowId = message.windowId;
    await upsertProcess(runId, patch);
    return true;
  }

  await upsertProcess(runId, {
    status: isClosedProcessStatus(process?.status) ? process.status : 'running',
    needsAction: true,
    statusText: 'Panel: decyzja niedostarczona (brak aktywnej karty)',
    timestamp: Date.now()
  });
  return false;
}

async function handleProcessDecisionAllMessage(message) {
  await ensureProcessRegistryReady();
  const decision = message?.decision === 'skip' ? 'skip' : 'wait';
  const candidates = Array.from(processRegistry.values()).filter((process) => (
    process &&
    !isClosedProcessStatus(process.status) &&
    !!process.needsAction
  ));

  let delivered = 0;
  for (const process of candidates) {
    const handled = await handleProcessDecisionMessage({
      runId: process.id,
      decision,
      origin: message?.origin || 'panel-bulk',
      tabId: Number.isInteger(process.tabId) ? process.tabId : null,
      windowId: Number.isInteger(process.windowId) ? process.windowId : null
    });
    if (handled) delivered += 1;
  }

  return {
    matched: candidates.length,
    delivered
  };
}

